# ================================================================
#  FUNCIONES UTILITARIAS BASE
# ================================================================

function Escribir-Centrado {
    param([string]$Texto, [ConsoleColor]$Color = "Gray")
    $W = $Host.UI.RawUI.WindowSize.Width
    if ($Texto.Length -lt $W) {
        $Esp = [Math]::Floor(($W - $Texto.Length) / 2)
        Write-Host (" " * $Esp + $Texto) -ForegroundColor $Color
    } else {
        Write-Host $Texto -ForegroundColor $Color
    }
}

function Obtener-Router {
    $Routes = Get-NetRoute -DestinationPrefix "0.0.0.0/0" -ErrorAction SilentlyContinue |
              Sort-Object RouteMetric
    foreach ($R in $Routes) {
        $A = Get-NetAdapter -InterfaceIndex $R.InterfaceIndex -ErrorAction SilentlyContinue
        if ($A -and $A.InterfaceDescription -notmatch "VPN|TAP|Tunnel|WireGuard|OpenVPN|PPP|Loopback|Virtual") {
            return @{ Gateway = $R.NextHop; InterfaceIndex = $R.InterfaceIndex }
        }
    }
    $F = $Routes | Select-Object -First 1
    if ($F) { return @{ Gateway = $F.NextHop; InterfaceIndex = $F.InterfaceIndex } }
    return $null
}

function Obtener-SubredBase {
    param([string]$Gateway, [int]$InterfaceIndex)
    $C = Get-NetIPAddress -InterfaceIndex $InterfaceIndex -AddressFamily IPv4 `
         -ErrorAction SilentlyContinue | Select-Object -First 1
    if ($C -and $C.PrefixLength -ge 24) {
        $O = $C.IPAddress.Split('.')
        return "$($O[0]).$($O[1]).$($O[2])"
    }
    return $Gateway.Substring(0, $Gateway.LastIndexOf('.'))
}

function Test-Puerto {
    param([string]$Destino, [int]$Puerto, [int]$TimeoutMs = 1000)
    try {
        $tcp   = New-Object System.Net.Sockets.TcpClient
        $async = $tcp.BeginConnect($Destino, $Puerto, $null, $null)
        $ok    = $async.AsyncWaitHandle.WaitOne($TimeoutMs, $false)
        if ($ok -and $tcp.Connected) { $tcp.EndConnect($async) | Out-Null; $tcp.Close(); return $true }
        $tcp.Close()
    } catch { }
    return $false
}

function Get-MACDesdeARP {
    param([string]$IP)
    try {
        foreach ($L in (arp -a $IP 2>$null)) {
            if ($L -match [regex]::Escape($IP) -and
                $L -match '([0-9a-fA-F]{2}[-:][0-9a-fA-F]{2}[-:][0-9a-fA-F]{2}[-:][0-9a-fA-F]{2}[-:][0-9a-fA-F]{2}[-:][0-9a-fA-F]{2})') {
                $M = $Matches[1].ToUpper()
                if ($M -ne "FF-FF-FF-FF-FF-FF" -and $M -ne "00-00-00-00-00-00") { return $M }
            }
        }
    } catch { }
    return "Desconocida"
}

function Get-Fabricante {
    param([string]$MAC)
    if ($MAC -eq "Desconocida") { return "Desconocido" }
    $Prefijo = ($MAC -replace ":", "-").ToUpper().Substring(0, 8)
    if ($script:OUI.ContainsKey($Prefijo)) { return $script:OUI[$Prefijo] }
    return "Desconocido"
}

function Exportar-Informe {
    param([string[]]$Contenido, [string]$NombreModulo)
    $Fecha      = Get-Date -Format "yyyy-MM-dd_HH-mm-ss"
    $Desktop = [Environment]::GetFolderPath("Desktop")
    $Archivo    = "$Desktop\AtlasRed_${NombreModulo}_${Fecha}.txt"
    $Contenido | Out-File -FilePath $Archivo -Encoding UTF8
    Write-Host "  Informe saved: $Archivo" -ForegroundColor Green
    return $Archivo
}

# ================================================================
#  PANTALLA DE INFORMACION DEL MODULO
#  Retorna $true to continue, $false para cancelar
# ================================================================
function Mostrar-InfoModulo {
    param([string]$Letra)

    if (-not $script:MostrarInfo -or $script:ModoAuto) { return $true }

    $D = $script:Info[$Letra]
    if (-not $D) { return $true }

    Clear-Host
    $Sep = "-" * 64

    Write-Host ""
    Write-Host "  $Sep" -ForegroundColor DarkGray
    Write-Host ("  [ $Letra ]  " + $D.Titulo.ToUpper()) -ForegroundColor $D.Color
    Write-Host "  $Sep" -ForegroundColor DarkGray

    Write-Host "`n  QUE HACE" -ForegroundColor Yellow
    foreach ($L in $D.Desc)  { Write-Host "    $L" -ForegroundColor Gray }

    Write-Host "`n  PRECAUCIONES" -ForegroundColor DarkYellow
    foreach ($L in $D.Prec)  { Write-Host "    $L" -ForegroundColor Gray }

    Write-Host "`n  RECOMENDACIONES" -ForegroundColor Cyan
    foreach ($L in $D.Recs)  { Write-Host "    $L" -ForegroundColor Gray }

    Write-Host "`n  EJEMPLOS DE USO" -ForegroundColor Green
    foreach ($L in $D.Ejem)  { Write-Host "    $L" -ForegroundColor Gray }

    Write-Host ""
    Write-Host "  $Sep" -ForegroundColor DarkGray
    Write-Host "  Y = continue    N = cancel    X = do not show info in the future" -ForegroundColor DarkGray
    Write-Host "  $Sep" -ForegroundColor DarkGray
    $R = Read-Host "  Tu eleccion"

    if ($R.ToUpper() -eq "X") { $script:MostrarInfo = $false; return $true }
    if ($R.ToUpper() -eq "N") { return $false }
    return $true
}

function Esperar-Enter {
    param([switch]$Silencioso)
    if (-not $Silencioso -and -not $script:ModoAuto) {
        Read-Host "`n  Press ENTER to go back to menu..."
    }
}

# ================================================================
#  MODULO A - AUDITORIA DE PUERTOS LAN
# ================================================================
function Modulo-Auditoria {
    param([switch]$Silencioso)
    if (-not $Silencioso -and -not (Mostrar-InfoModulo "A")) { return @() }

    Clear-Host
    Write-Host ""
    Write-Host "  [ A ]  AUDITORIA DE PUERTOS LAN" -ForegroundColor Cyan
    Write-Host "  $("-" * 60)" -ForegroundColor DarkGray

    $RI = Obtener-Router
    if (-not $RI) { Write-Host "`n  No se pudo detectar el router." -ForegroundColor Red; Esperar-Enter -Silencioso:$Silencioso; return @() }
    $GW = $RI.Gateway
    Write-Host "`n  Router detectado: $GW" -ForegroundColor White

    $Base = @(21, 22, 23, 80, 443, 8080, 8443, 8888, 9090)
    Write-Host "  Puertos base    : $($Base -join ', ')" -ForegroundColor DarkGray

    $Extra = ""
    if (-not $Silencioso -and -not $script:ModoAuto) {
        $Extra = Read-Host "`n  Additional ports separated by comma (or ENTER to skip)"
    }

    $Puertos = $Base
    if ($Extra.Trim() -ne "") {
        $Add = $Extra -split ',' | ForEach-Object { $_.Trim() } |
               Where-Object { $_ -match '^\d+$' } | ForEach-Object { [int]$_ }
        $Puertos = ($Puertos + $Add) | Sort-Object -Unique
    }

    Write-Host "`n  Scanning $($Puertos.Count) puertos en $GW...`n" -ForegroundColor DarkGray

    $Leyendas = @{
        21 = "FTP         Transferencia de archivos. INSEGURO si expuesto."
        22 = "SSH         Encrypted CLI access. Normal on managed routers."
        23 = "Telnet      Plain text, no encryption. VERY DANGEROUS if open."
        80 = "HTTP        Router panel via local network."
        443= "HTTPS       Secure router panel via local network."
        8080="HTTP-Alt    Secondary panel in many routers."
        8443="HTTPS-Alt   Panel HTTPS secundario."
        8888="Common Alt  Present in some modern routers."
        9090="Admin-Alt   Puerto de administracion alternativo."
        3389="RDP         Desktop remoto Windows. CRITICO si abierto."
    }

    $Log      = @("=== AUDITORIA DE PUERTOS LAN === $(Get-Date)", "Router: $GW", "")
    $Abiertos = @()

    foreach ($P in $Puertos) {
        $Ok = Test-Puerto -Destino $GW -Puerto $P -TimeoutMs 1000
        if ($Ok) {
            Write-Host "  [ABIERTO]  Puerto $P" -ForegroundColor Red
            $Log += "  [ABIERTO]  Puerto $P"
            $Abiertos += $P
        } else {
            Write-Host "  [cerrado]  Puerto $P" -ForegroundColor DarkGreen
            $Log += "  [cerrado]  Puerto $P"
        }
    }

    Write-Host "`n  $("-" * 60)" -ForegroundColor DarkGray
    Write-Host "  LEYENDA DE PUERTOS" -ForegroundColor Cyan
    foreach ($P in $Puertos) {
        if ($Leyendas.ContainsKey($P)) { Write-Host "    [$P]  $($Leyendas[$P])" -ForegroundColor Gray }
    }
    Write-Host "`n  NOTE: Open ports on LAN are normal. The real risk is" -ForegroundColor DarkGray
    Write-Host "        if they appear open from Internet. Use module H." -ForegroundColor DarkGray

    $script:HistorialSesion.Add("[A] Auditoria $GW | Abiertos: $(if ($Abiertos.Count) { $Abiertos -join ',' } else { 'None' })")

    if (-not $Silencioso -and -not $script:ModoAuto) {
        $Exp = Read-Host "`n  Exportar informe a TXT? (Y/N)"
        if ($Exp -match '^[SsYy]$') { Exportar-Informe -Contenido $Log -NombreModulo "Auditoria" | Out-Null }
    }

    Esperar-Enter -Silencioso:$Silencioso
    return $Log
}

# ================================================================
#  MODULO B - ESCANEO DE DISPOSITIVOS + DETECCION IPs DUPLICADAS (K)
# ================================================================
function Modulo-Escaneo {
    param([switch]$Silencioso)
    if (-not $Silencioso -and -not (Mostrar-InfoModulo "B")) { return @() }

    Clear-Host
    Write-Host ""
    Write-Host "  [ B ]  ESCANEO DE DISPOSITIVOS" -ForegroundColor Cyan
    Write-Host "  $("-" * 60)" -ForegroundColor DarkGray

    $RI = Obtener-Router
    if (-not $RI) { Write-Host "`n  No se pudo detectar el router." -ForegroundColor Red; Esperar-Enter -Silencioso:$Silencioso; return @() }
    $GW  = $RI.Gateway
    $Sub = Obtener-SubredBase -Gateway $GW -InterfaceIndex $RI.InterfaceIndex

    Write-Host "`n  Subred: ${Sub}.1 - ${Sub}.254" -ForegroundColor White
    Write-Host "  This may take up to 90 seconds. Please wait.`n" -ForegroundColor DarkGray

    $Ping        = New-Object System.Net.NetworkInformation.Ping
    $Encontrados = [System.Collections.Generic.List[hashtable]]::new()
    $MACVisto    = @{}
    $Log         = @("=== ESCANEO DE DISPOSITIVOS === $(Get-Date)", "Subred: ${Sub}.x", "")

    for ($i = 1; $i -le 254; $i++) {
        $IP = "$Sub.$i"
        try {
            if ($Ping.Send($IP, 150).Status -eq 'Success') {

                $Host_ = "Oculto"
                try { $H = [System.Net.Dns]::GetHostEntry($IP); if ($H.HostName) { $Host_ = $H.HostName } } catch { }

                $null = arp -a 2>$null
                Start-Sleep -Milliseconds 80
                $MAC  = Get-MACDesdeARP -IP $IP
                $Fab  = Get-Fabricante -MAC $MAC

                # Modulo K: deteccion de conflicto de IP
                $Conflicto = ""
                if ($MAC -ne "Desconocida") {
                    if ($MACVisto.ContainsKey($MAC)) {
                        $Conflicto = "  [!!! CONFLICTO: misma MAC que $($MACVisto[$MAC])]"
                    } else {
                        $MACVisto[$MAC] = $IP
                    }
                }

                $Entrada = @{ IP = $IP; MAC = $MAC; Host = $Host_; Fab = $Fab }
                $Encontrados.Add($Entrada)

                if ($IP -eq $GW) {
                    Write-Host "  [ROUTER]   $IP  $MAC  $Fab" -ForegroundColor Green
                    $Log += "  [ROUTER]   $IP | $MAC | $Fab"
                } elseif ($Conflicto) {
                    Write-Host "  [CONFLICTO]$IP  $MAC  $Fab$Conflicto" -ForegroundColor Red
                    $Log += "  [CONFLICTO]$IP | $MAC | $Fab$Conflicto"
                } else {
                    Write-Host "  [disp]     $IP  $MAC  $Fab  |  $Host_" -ForegroundColor Cyan
                    $Log += "  [disp]     $IP | $MAC | $Fab | $Host_"
                }
            }
        } catch { }
    }

    Write-Host "`n  $("-" * 60)" -ForegroundColor DarkGray
    Write-Host "  Total found: $($Encontrados.Count) devices" -ForegroundColor Yellow
    if ($MACVisto.Count -lt ($Encontrados | Where-Object { $_.MAC -ne "Desconocida" } | Measure-Object).Count) {
        Write-Host "  WARNING: IP conflicts detected. See lines marked [CONFLICT]." -ForegroundColor Red
    }

    # Guardar estado para modulo N
    try {
        $Lineas = $Encontrados | ForEach-Object { "$($_.IP)|$($_.MAC)|$($_.Host)" }
        $Lineas | Out-File $script:ArchivoEstado -Encoding UTF8 -Force
        Write-Host "  State saved for comparison (module N)." -ForegroundColor DarkGray
    } catch { }

    $script:HistorialSesion.Add("[B] Escaneo ${Sub}.x | $($Encontrados.Count) devices")

    if (-not $Silencioso -and -not $script:ModoAuto) {
        $Exp = Read-Host "`n  Exportar informe a TXT? (Y/N)"
        if ($Exp -match '^[SsYy]$') { Exportar-Informe -Contenido $Log -NombreModulo "Escaneo" | Out-Null }
    }

    Esperar-Enter -Silencioso:$Silencioso
    return $Log
}

# ================================================================
#  MODULO C - PANEL DEL ROUTER
# ================================================================
function Modulo-Panel {
    param([switch]$Silencioso)
    if (-not $Silencioso -and -not (Mostrar-InfoModulo "C")) { return }

    Clear-Host
    Write-Host ""
    Write-Host "  [ C ]  PANEL DEL ROUTER" -ForegroundColor Cyan
    Write-Host "  $("-" * 60)" -ForegroundColor DarkGray

    $RI = Obtener-Router
    if (-not $RI) { Write-Host "`n  No se pudo detectar el router." -ForegroundColor Red; Esperar-Enter -Silencioso:$Silencioso; return }
    $GW = $RI.Gateway

    Write-Host "`n  Detecting protocolo en $GW..." -ForegroundColor DarkGray
    $URL = $null
    if (Test-Puerto -Destino $GW -Puerto 443 -TimeoutMs 1500) {
        $URL = "https://$GW"
        Write-Host "  Puerto 443 disponible  ->  usando HTTPS" -ForegroundColor Green
    } elseif (Test-Puerto -Destino $GW -Puerto 80 -TimeoutMs 1500) {
        $URL = "http://$GW"
        Write-Host "  Puerto 80 disponible   ->  usando HTTP" -ForegroundColor Yellow
    } else {
        $URL = "http://$GW"
        Write-Host "  Ningun puerto confirmo response. Intentando HTTP..." -ForegroundColor DarkGray
    }

    Write-Host "`n  Abriendo: $URL" -ForegroundColor White
    Write-Host "  If browser shows 'Site not secure', that is normal on LAN." -ForegroundColor DarkGray
    Write-Host "  Credenciales habituales: admin / admin  |  admin / 1234  |  admin / (vacio)" -ForegroundColor DarkGray

    try { Start-Process $URL } catch { Write-Host "  Error al abrir el navegador." -ForegroundColor Red }

    $script:HistorialSesion.Add("[C] Panel abierto: $URL")
    Esperar-Enter -Silencioso:$Silencioso
}

# ================================================================
#  MODULO D - DIAGNOSTICO DE LATENCIA
# ================================================================
function Modulo-Latencia {
    param([switch]$Silencioso)
    if (-not $Silencioso -and -not (Mostrar-InfoModulo "D")) { return @() }

    Clear-Host
    Write-Host ""
    Write-Host "  [ D ]  DIAGNOSTICO DE LATENCIA" -ForegroundColor Yellow
    Write-Host "  $("-" * 60)" -ForegroundColor DarkGray

    $RI = Obtener-Router
    if (-not $RI) { Write-Host "`n  No se pudo detectar el router." -ForegroundColor Red; Esperar-Enter -Silencioso:$Silencioso; return @() }
    $GW = $RI.Gateway

    $Objetivos = @(
        @{ N = "Router   (LAN)    "; IP = $GW       },
        @{ N = "Cloudflare (WAN)  "; IP = "1.1.1.1" },
        @{ N = "Google     (WAN)  "; IP = "8.8.8.8" }
    )

    $Log = @("=== DIAGNOSTICO DE LATENCIA === $(Get-Date)", "Router: $GW", "")
    $PO  = New-Object System.Net.NetworkInformation.Ping
    $N   = 10

    foreach ($Obj in $Objetivos) {
        Write-Host "`n  $($Obj.N.Trim()) ($($Obj.IP))  -  $N pings" -ForegroundColor Cyan
        $T = @(); $F = 0
        for ($p = 1; $p -le $N; $p++) {
            try {
                $R = $PO.Send($Obj.IP, 2000)
                if ($R.Status -eq 'Success') {
                    $T += $R.RoundtripTime
                    Write-Host "    Ping $p : $($R.RoundtripTime) ms" -ForegroundColor DarkGray
                } else { $F++; Write-Host "    Ping $p : TIMEOUT" -ForegroundColor DarkRed }
            } catch { $F++; Write-Host "    Ping $p : ERROR" -ForegroundColor DarkRed }
            Start-Sleep -Milliseconds 200
        }
        if ($T.Count -gt 0) {
            $Min = ($T | Measure-Object -Minimum).Minimum
            $Max = ($T | Measure-Object -Maximum).Maximum
            $Avg = [Math]::Round(($T | Measure-Object -Average).Average, 1)
            $Res = "Min:${Min}ms  Max:${Max}ms  Media:${Avg}ms  Perdidos:$F/$N"
            Write-Host "  RESULTADO  $Res" -ForegroundColor Yellow
            $Log += "  $($Obj.N.Trim()): $Res"
            if ($Obj.IP -eq $GW     -and $Avg -gt 20)  { Write-Host "  WARNING: High router latency. Possible LAN congestion or weak WiFi." -ForegroundColor Red }
            if ($Obj.IP -ne $GW     -and $Avg -gt 100) { Write-Host "  WARNING: High Internet latency. Possible ISP issue." -ForegroundColor Red }
            if ($F -gt ($N / 2))                        { Write-Host "  WARNING: Over half of pings were lost. Severe failure." -ForegroundColor Red }
        } else {
            Write-Host "  Sin responses. Destino inaccesible." -ForegroundColor Red
            $Log += "  $($Obj.N.Trim()): SIN RESPUESTA"
        }
    }

    $script:HistorialSesion.Add("[D] Diagnostico de latencia completed")

    if (-not $Silencioso -and -not $script:ModoAuto) {
        $Exp = Read-Host "`n  Exportar informe a TXT? (Y/N)"
        if ($Exp -match '^[SsYy]$') { Exportar-Informe -Contenido $Log -NombreModulo "Latencia" | Out-Null }
    }

    Esperar-Enter -Silencioso:$Silencioso
    return $Log
}

# ================================================================
#  MODULO E - INFO DEL ADAPTADOR
# ================================================================
function Modulo-InfoAdaptador {
    param([switch]$Silencioso)
    if (-not $Silencioso -and -not (Mostrar-InfoModulo "E")) { return @() }

    Clear-Host
    Write-Host ""
    Write-Host "  [ E ]  INFORMACION DEL ADAPTADOR DE RED" -ForegroundColor White
    Write-Host "  $("-" * 60)" -ForegroundColor DarkGray

    $RI = Obtener-Router
    if (-not $RI) { Write-Host "`n  No se pudo detectar el router." -ForegroundColor Red; Esperar-Enter -Silencioso:$Silencioso; return @() }
    $GW = $RI.Gateway
    $II = $RI.InterfaceIndex

    $A   = Get-NetAdapter -InterfaceIndex $II -ErrorAction SilentlyContinue
    $IP  = Get-NetIPAddress -InterfaceIndex $II -AddressFamily IPv4 -ErrorAction SilentlyContinue | Select-Object -First 1
    $DNS = Get-DnsClientServerAddress -InterfaceIndex $II -AddressFamily IPv4 -ErrorAction SilentlyContinue
    $EC  = if ($A.Status -eq 'Up') { 'Green' } else { 'Red' }

    Write-Host ""
    Write-Host "  ADAPTADOR ACTIVO" -ForegroundColor Cyan
    Write-Host "  Nombre         : $($A.Name)"
    Write-Host "  Descripcion    : $($A.InterfaceDescription)"
    Write-Host "  Estado         : $($A.Status)" -ForegroundColor $EC
    Write-Host "  Velocidad      : $(if ($A.LinkSpeed) { $A.LinkSpeed } else { 'N/A' })"
    Write-Host "  MAC propia     : $($A.MacAddress)" -ForegroundColor Yellow

    Write-Host ""
    Write-Host "  IP CONFIGURATION" -ForegroundColor Cyan
    $IPColor = if ($IP.IPAddress -match "^169\.254") { "Red" } else { "Yellow" }
    Write-Host "  IP Local       : $($IP.IPAddress)" -ForegroundColor $IPColor
    if ($IP.IPAddress -match "^169\.254") {
        Write-Host "  WARNING: APIPA IP (169.254.x.x). DHCP is not responding." -ForegroundColor Red
    }
    Write-Host "  Mascara de red : /$($IP.PrefixLength)"
    Write-Host "  Puerta enlace  : $GW"

    Write-Host ""
    Write-Host "  SERVIDORES DNS" -ForegroundColor Cyan
    if ($DNS -and $DNS.ServerAddresses.Count -gt 0) {
        foreach ($S in $DNS.ServerAddresses) {
            $DNSColor = "White"
            $DNSNota  = ""
            if ($S -eq "127.0.0.1")  { $DNSColor = "Yellow"; $DNSNota = "  (DNS local activo: Pi-hole, VPN o DNSCrypt)" }
            if ($S -eq "1.1.1.1")    { $DNSNota = "  (Cloudflare)" }
            if ($S -eq "8.8.8.8")    { $DNSNota = "  (Google)" }
            if ($S -eq "9.9.9.9")    { $DNSNota = "  (Quad9)" }
            if ($S -eq "208.67.222.222") { $DNSNota = "  (OpenDNS)" }
            Write-Host "  -> $S$DNSNota" -ForegroundColor $DNSColor
        }
    } else { Write-Host "  No se encontraron DNS configurados." -ForegroundColor DarkGray }

    $Log = @(
        "=== INFO ADAPTADOR === $(Get-Date)",
        "Nombre    : $($A.Name)  |  $($A.InterfaceDescription)",
        "Estado    : $($A.Status)  |  Velocidad: $($A.LinkSpeed)",
        "MAC       : $($A.MacAddress)",
        "IP        : $($IP.IPAddress)/$($IP.PrefixLength)",
        "Gateway   : $GW",
        "DNS       : $($DNS.ServerAddresses -join ', ')"
    )

    $script:HistorialSesion.Add("[E] Adaptador: $($A.Name) | IP: $($IP.IPAddress) | GW: $GW")

    if (-not $Silencioso -and -not $script:ModoAuto) {
        $Exp = Read-Host "`n  Exportar informe a TXT? (Y/N)"
        if ($Exp -match '^[SsYy]$') { Exportar-Informe -Contenido $Log -NombreModulo "Adaptador" | Out-Null }
    }

    Esperar-Enter -Silencioso:$Silencioso
    return $Log
}

# ================================================================
#  MODULO F - TEST DNS
# ================================================================
function Modulo-TestDNS {
    param([switch]$Silencioso)
    if (-not $Silencioso -and -not (Mostrar-InfoModulo "F")) { return @() }

    Clear-Host
    Write-Host ""
    Write-Host "  [ F ]  TEST DE RESOLUCION DNS" -ForegroundColor White
    Write-Host "  $("-" * 60)" -ForegroundColor DarkGray
    Write-Host ""

    $Doms = @("google.com","cloudflare.com","microsoft.com","amazon.com","youtube.com")
    $Log  = @("=== TEST DNS === $(Get-Date)", "")
    $F    = 0

    foreach ($D in $Doms) {
        $T0 = Get-Date
        try {
            $R  = [System.Net.Dns]::GetHostEntry($D)
            $Ms = [Math]::Round((New-TimeSpan -Start $T0 -End (Get-Date)).TotalMilliseconds)
            $IP = ($R.AddressList | Select-Object -First 2 | ForEach-Object { $_.IPAddressToString }) -join ", "
            $C  = if ($Ms -gt 500) { "Yellow" } else { "Green" }
            Write-Host "  [OK]    $D" -NoNewline -ForegroundColor $C
            Write-Host "   ${Ms}ms  ->  $IP" -ForegroundColor DarkGray
            if ($Ms -gt 500) { Write-Host "          WARNING: slow resolution. Router DNS may be congested." -ForegroundColor DarkYellow }
            $Log += "  [OK]    $D : ${Ms}ms -> $IP"
        } catch {
            $Ms = [Math]::Round((New-TimeSpan -Start $T0 -End (Get-Date)).TotalMilliseconds)
            Write-Host "  [FALLO] $D  (${Ms}ms)" -ForegroundColor Red
            $Log += "  [FALLO] $D : ${Ms}ms"
            $F++
        }
    }

    Write-Host ""
    if ($F -eq $Doms.Count) {
        Write-Host "  WARNING: All domains failed. No Internet or DNS completely down." -ForegroundColor Red
        Write-Host "  Quick fix: change DNS to 1.1.1.1 in the adapter configuration." -ForegroundColor Yellow
    } elseif ($F -gt 0) {
        Write-Host "  WARNING: $F domain(s) fallaron. Posible filtracion o cache DNS corrupta." -ForegroundColor Yellow
    }

    $script:HistorialSesion.Add("[F] Test DNS: $($Doms.Count - $F)/$($Doms.Count) domains OK")

    if (-not $Silencioso -and -not $script:ModoAuto) {
        $Exp = Read-Host "`n  Exportar informe a TXT? (Y/N)"
        if ($Exp -match '^[SsYy]$') { Exportar-Informe -Contenido $Log -NombreModulo "DNS" | Out-Null }
    }

    Esperar-Enter -Silencioso:$Silencioso
    return $Log
}

# ================================================================
#  MODULO H - PUERTOS WAN PELIGROSOS
# ================================================================
function Modulo-PuertosWAN {
    param([switch]$Silencioso)
    if (-not $Silencioso -and -not (Mostrar-InfoModulo "H")) { return @() }

    Clear-Host
    Write-Host ""
    Write-Host "  [ H ]  PUERTOS PELIGROSOS EN INTERNET (WAN)" -ForegroundColor Red
    Write-Host "  $("-" * 60)" -ForegroundColor DarkGray
    Write-Host "`n  Obteniendo IP publica..." -ForegroundColor DarkGray

    $IPP = $null
    foreach ($Srv in @("https://api.ipify.org","https://api.my-ip.io/ip","https://ifconfig.me/ip")) {
        try { $IPP = (Invoke-RestMethod -Uri $Srv -TimeoutSec 5 -ErrorAction Stop).Trim()
              if ($IPP -match '^\d{1,3}(\.\d{1,3}){3}$') { break } else { $IPP = $null }
        } catch { $IPP = $null }
    }

    if (-not $IPP) { Write-Host "  No se pudo obtener la IP publica." -ForegroundColor Red; Esperar-Enter -Silencioso:$Silencioso; return @() }

    Write-Host "  IP Publica: $IPP" -ForegroundColor White
    Write-Host "`n  Scanning puertos criticos desde Internet...`n" -ForegroundColor DarkGray

    $Puertos = @(
        @{ P = 21;   N = "FTP";      R = "CRITICO" }
        @{ P = 22;   N = "SSH";      R = "ALTO"    }
        @{ P = 23;   N = "Telnet";   R = "CRITICO" }
        @{ P = 80;   N = "HTTP";     R = "MEDIO"   }
        @{ P = 443;  N = "HTTPS";    R = "BAJO"    }
        @{ P = 3389; N = "RDP";      R = "CRITICO" }
        @{ P = 8080; N = "HTTP-Alt"; R = "MEDIO"   }
    )

    $Log     = @("=== PUERTOS WAN === $(Get-Date)", "IP Publica: $IPP", "")
    $Alertas = @()

    foreach ($E in $Puertos) {
        $Ok = Test-Puerto -Destino $IPP -Puerto $E.P -TimeoutMs 2000
        if ($Ok) {
            $C = switch ($E.R) { "CRITICO" { "Red" } "ALTO" { "Yellow" } default { "DarkYellow" } }
            Write-Host ("  [EXPUESTO]  Puerto {0,-5} ({1,-10}) RIESGO {2}" -f $E.P, $E.N, $E.R) -ForegroundColor $C
            $Log += "  [EXPUESTO]  Puerto $($E.P) ($($E.N)) [$($E.R)]"
            $Alertas += $E.P
        } else {
            Write-Host ("  [OK]        Puerto {0,-5} ({1,-10}) cerrado/filtrado" -f $E.P, $E.N) -ForegroundColor DarkGreen
            $Log += "  [OK]        Puerto $($E.P) ($($E.N))"
        }
    }

    Write-Host ""
    if ($Alertas.Count -gt 0) {
        Write-Host "  ACCION RECOMENDADA:" -ForegroundColor Yellow
        Write-Host "    Router panel (module C) -> Remote administration -> disable." -ForegroundColor Yellow
        Write-Host "    Or in Port Forwarding: remove rules for the marked ports." -ForegroundColor Yellow
    } else {
        Write-Host "  Sin puertos criticos expuestos. Router bien configurado." -ForegroundColor Green
    }

    $script:HistorialSesion.Add("[H] WAN $IPP | Expuestos: $(if ($Alertas.Count) { $Alertas -join ',' } else { 'None' })")

    if (-not $Silencioso -and -not $script:ModoAuto) {
        $Exp = Read-Host "`n  Exportar informe a TXT? (Y/N)"
        if ($Exp -match '^[SsYy]$') { Exportar-Informe -Contenido $Log -NombreModulo "WAN" | Out-Null }
    }

    Esperar-Enter -Silencioso:$Silencioso
    return $Log
}

# ================================================================
#  MODULO J - FABRICANTES POR MAC (OUI)
# ================================================================
function Modulo-Fabricantes {
    param([switch]$Silencioso)
    if (-not $Silencioso -and -not (Mostrar-InfoModulo "J")) { return }

    Clear-Host
    Write-Host ""
    Write-Host "  [ J ]  IDENTIFICACION DE FABRICANTES POR MAC" -ForegroundColor White
    Write-Host "  $("-" * 60)" -ForegroundColor DarkGray

    $RI = Obtener-Router
    if (-not $RI) { Write-Host "`n  No se pudo detectar el router." -ForegroundColor Red; Esperar-Enter -Silencioso:$Silencioso; return }
    $GW  = $RI.Gateway
    $Sub = Obtener-SubredBase -Gateway $GW -InterfaceIndex $RI.InterfaceIndex

    Write-Host "`n  Scanning ${Sub}.1 - ${Sub}.254 (tabla OUI local, sin Internet)..." -ForegroundColor DarkGray
    Write-Host ""

    $Ping    = New-Object System.Net.NetworkInformation.Ping
    $Grupos  = @{}   # Fabricante -> Lista de IPs
    $Log     = @("=== FABRICANTES POR MAC === $(Get-Date)", "Subred: ${Sub}.x", "")

    for ($i = 1; $i -le 254; $i++) {
        $IP = "$Sub.$i"
        try {
            if ($Ping.Send($IP, 150).Status -eq 'Success') {
                $null = arp -a 2>$null; Start-Sleep -Milliseconds 80
                $MAC = Get-MACDesdeARP -IP $IP
                $Fab = Get-Fabricante  -MAC $MAC
                $Tag = if ($IP -eq $GW) { " [ROUTER]" } else { "" }

                if (-not $Grupos.ContainsKey($Fab)) { $Grupos[$Fab] = [System.Collections.Generic.List[string]]::new() }
                $Grupos[$Fab].Add("$IP  |  $MAC$Tag")
            }
        } catch { }
    }

    Write-Host "  $("-" * 60)" -ForegroundColor DarkGray
    Write-Host "  RESULTADOS AGRUPADOS POR FABRICANTE`n" -ForegroundColor Cyan

    $Total = 0
    foreach ($Fab in ($Grupos.Keys | Sort-Object)) {
        $Alerta = $Fab -match "VMware|VirtualBox|QEMU|Raspberry Pi|Ubiquiti"
        $C = if ($Fab -eq "Desconocido") { "DarkGray" } elseif ($Alerta) { "Yellow" } else { "White" }
        Write-Host "  $Fab ($($Grupos[$Fab].Count) device(s))" -ForegroundColor $C
        $Log += "  $Fab ($($Grupos[$Fab].Count)):"
        foreach ($L in $Grupos[$Fab]) {
            Write-Host "    -> $L" -ForegroundColor DarkGray
            $Log += "    -> $L"
            $Total++
        }
        if ($Alerta) { Write-Host "    NOTE: Unusual manufacturer on home network. Verify." -ForegroundColor Yellow }
        $Log += ""
        Write-Host ""
    }

    Write-Host "  Total: $Total devices found." -ForegroundColor Yellow
    $script:HistorialSesion.Add("[J] Fabricantes ${Sub}.x | $Total devices | $($Grupos.Count) fabricantes")

    if (-not $Silencioso -and -not $script:ModoAuto) {
        $Exp = Read-Host "`n  Exportar informe a TXT? (Y/N)"
        if ($Exp -match '^[SsYy]$') { Exportar-Informe -Contenido $Log -NombreModulo "Fabricantes" | Out-Null }
    }

    Esperar-Enter -Silencioso:$Silencioso
}

# ================================================================
#  MODULO L - VERSION DE FIRMWARE DEL ROUTER
# ================================================================
function Modulo-Firmware {
    param([switch]$Silencioso)
    if (-not $Silencioso -and -not (Mostrar-InfoModulo "L")) { return }

    Clear-Host
    Write-Host ""
    Write-Host "  [ L ]  DETECCION DE FIRMWARE DEL ROUTER" -ForegroundColor DarkYellow
    Write-Host "  $("-" * 60)" -ForegroundColor DarkGray

    $RI = Obtener-Router
    if (-not $RI) { Write-Host "`n  No se pudo detectar el router." -ForegroundColor Red; Esperar-Enter -Silencioso:$Silencioso; return }
    $GW = $RI.Gateway

    Write-Host "`n  Probando rutas conocidas en $GW...`n" -ForegroundColor DarkGray

    # Rutas conocidas por fabricante (accesibles sin autenticacion en muchos modelos)
    $Rutas = @(
        @{ URL = "http://$GW/help/aboutinfo.htm";       Marca = "TP-Link (clasico)"  }
        @{ URL = "http://$GW/userRpm/AboutRpm.htm";     Marca = "TP-Link (alt)"      }
        @{ URL = "http://$GW/cgi-bin/status";           Marca = "TP-Link (cgi)"      }
        @{ URL = "http://$GW/about.html";               Marca = "D-Link"             }
        @{ URL = "http://$GW/info.html";                Marca = "D-Link (alt)"       }
        @{ URL = "http://$GW/Main_Analysis_Content.asp";Marca = "ASUS"               }
        @{ URL = "https://$GW/appGet.cgi?hook=get_system_info()"; Marca = "ASUS (HTTPS)" }
        @{ URL = "http://$GW/statusInfo.html";          Marca = "Huawei/Movistar"    }
        @{ URL = "http://$GW/html/status.html";         Marca = "Huawei (alt)"       }
        @{ URL = "http://$GW/firmware.html";            Marca = "Generico"           }
        @{ URL = "http://$GW/status.html";              Marca = "Generico (alt)"     }
    )

    $Encontrada = $false
    $Log = @("=== FIRMWARE DEL ROUTER === $(Get-Date)", "Gateway: $GW", "")

    foreach ($R in $Rutas) {
        Write-Host "  Probando: $($R.Marca)..." -ForegroundColor DarkGray -NoNewline
        try {
            $Resp = Invoke-WebRequest -Uri $R.URL -TimeoutSec 3 -UseBasicParsing `
                    -ErrorAction Stop -WarningAction SilentlyContinue
            $HTML = $Resp.Content

            # Patrones de version en el HTML
            $Version = $null
            $Patrones = @(
                'Firmware[^<:]*(?:Version)?[^<:]*:[^<"]*?([\d]+\.[\d]+[\d\.]*)',
                'Software Version[^<]*?([0-9]+\.[0-9]+[0-9A-Za-z\._-]*)',
                'FW Version[^<]*?([0-9]+\.[0-9]+[0-9A-Za-z\._-]*)',
                'HW Version[^<]*?([0-9]+\.[0-9]+[0-9A-Za-z\._-]*)',
                'Version[^<"]*?([0-9]+\.[0-9]+\.[0-9]+[0-9A-Za-z\._-]*)',
                '"firmware"[^"]*"([^"]+)"',
                'firmwareVersion[^"]*"([^"]+)"'
            )

            foreach ($Pat in $Patrones) {
                if ($HTML -match $Pat) {
                    $Version = $Matches[1].Trim()
                    break
                }
            }

            if ($Version) {
                Write-Host "  ENCONTRADO" -ForegroundColor Green
                Write-Host ""
                Write-Host "  Marca/Modelo detectado : $($R.Marca)" -ForegroundColor White
                Write-Host "  Version firmware       : $Version" -ForegroundColor Yellow
                Write-Host "  URL fuente             : $($R.URL)" -ForegroundColor DarkGray
                Write-Host ""
                Write-Host "  RECOMMENDATION: Compare this version with the one available on the web" -ForegroundColor Cyan
                Write-Host "  from the manufacturer. If older than 1 year, consider updating." -ForegroundColor Cyan
                $Log += "  Marca   : $($R.Marca)"
                $Log += "  Version : $Version"
                $Log += "  URL     : $($R.URL)"
                $Encontrada = $true
                break
            } elseif ($Resp.StatusCode -eq 200) {
                Write-Host "  responds (no parseable version)" -ForegroundColor DarkGray
            } else {
                Write-Host "  no access" -ForegroundColor DarkGray
            }
        } catch {
            Write-Host "  no access" -ForegroundColor DarkGray
        }
    }

    if (-not $Encontrada) {
        Write-Host ""
        Write-Host "  Firmware version not detected automatically." -ForegroundColor Yellow
        Write-Host "  Options manuales:" -ForegroundColor DarkGray
        Write-Host "    1. Use module C to access the router panel." -ForegroundColor Gray
        Write-Host "    2. Look for the version in: Administration > Firmware update." -ForegroundColor Gray
        Write-Host "    3. Check the physical label on the bottom of the router." -ForegroundColor Gray
        $Log += "  Resultado: No found de forma automatica."
    }

    $script:HistorialSesion.Add("[L] Firmware $GW | $(if ($Encontrada) { 'Encontrado' } else { 'No found' })")

    if (-not $Silencioso -and -not $script:ModoAuto) {
        $Exp = Read-Host "`n  Exportar informe a TXT? (Y/N)"
        if ($Exp -match '^[SsYy]$') { Exportar-Informe -Contenido $Log -NombreModulo "Firmware" | Out-Null }
    }

    Esperar-Enter -Silencioso:$Silencioso
}

# ================================================================
#  MODULO M - INFORME COMPLETO AUTOMATICO
# ================================================================
function Modulo-InformeCompleto {
    param([switch]$Silencioso)
    if (-not $Silencioso -and -not $script:ModoAuto -and -not (Mostrar-InfoModulo "M")) { return }

    Clear-Host
    Write-Host ""
    Write-Host "  [ M ]  INFORME COMPLETO AUTOMATICO" -ForegroundColor Green
    Write-Host "  $("-" * 60)" -ForegroundColor DarkGray
    Write-Host "`n  Running modules A, E, F and D in sequence..." -ForegroundColor DarkGray
    Write-Host "  Do not close this window. Will take 2-5 minutes.`n" -ForegroundColor Yellow

    $LogTotal = @(
        "================================================================"
        "  INFORME COMPLETO - Atlas PC Support  v3.0"
        "  Date: $(Get-Date)"
        "================================================================"
        ""
    )

    Write-Host "  [1/4]  Auditoria de Puertos..." -ForegroundColor Cyan
    $LA = Modulo-Auditoria -Silencioso
    $LogTotal += @("", "--- [ A ] AUDITORIA DE PUERTOS ---") + $LA

    Write-Host "`n  [2/4]  Adapter Info..." -ForegroundColor Cyan
    $LE = Modulo-InfoAdaptador -Silencioso
    $LogTotal += @("", "--- [ E ] INFO DEL ADAPTADOR ---") + $LE

    Write-Host "`n  [3/4]  Test DNS..." -ForegroundColor Cyan
    $LF = Modulo-TestDNS -Silencioso
    $LogTotal += @("", "--- [ F ] TEST DNS ---") + $LF

    Write-Host "`n  [4/4]  Diagnostico de Latencia..." -ForegroundColor Cyan
    $LD = Modulo-Latencia -Silencioso
    $LogTotal += @("", "--- [ D ] LATENCIA ---") + $LD

    $LogTotal += @("", "================================================================", "  End of report", "================================================================")

    Write-Host ""
    $Archivo = Exportar-Informe -Contenido $LogTotal -NombreModulo "InformeCompleto"

    $script:HistorialSesion.Add("[M] Informe completo generado: $Archivo")
    Write-Host "`n  Full report ready." -ForegroundColor Green

    Esperar-Enter -Silencioso:$Silencioso
}

# ================================================================
#  MODULO N - COMPARATIVA DE DISPOSITIVOS
# ================================================================
function Modulo-Comparativa {
    param([switch]$Silencioso)
    if (-not $Silencioso -and -not (Mostrar-InfoModulo "N")) { return }

    Clear-Host
    Write-Host ""
    Write-Host "  [ N ]  COMPARATIVA DE DISPOSITIVOS" -ForegroundColor Magenta
    Write-Host "  $("-" * 60)" -ForegroundColor DarkGray

    # Cargar estado previo
    $Previo = @{}
    if (Test-Path $script:ArchivoEstado) {
        $FechaMod = (Get-Item $script:ArchivoEstado).LastWriteTime
        Write-Host "`n  Estado previo found: $FechaMod" -ForegroundColor DarkGray
        foreach ($L in (Get-Content $script:ArchivoEstado)) {
            $P = $L -split '\|'
            if ($P.Count -ge 2) { $Previo[$P[0]] = @{ MAC = $P[1]; Host = if ($P.Count -ge 3) { $P[2] } else { "Oculto" } } }
        }
        Write-Host "  Devices en estado previo: $($Previo.Count)" -ForegroundColor DarkGray
    } else {
        Write-Host "`n  No hay estado previo saved." -ForegroundColor Yellow
        Write-Host "  Run module B first to save a baseline." -ForegroundColor Yellow
        Esperar-Enter -Silencioso:$Silencioso; return
    }

    Write-Host "`n  Scanning la red actual..." -ForegroundColor DarkGray
    $RI = Obtener-Router
    if (-not $RI) { Write-Host "  No se pudo detectar el router." -ForegroundColor Red; Esperar-Enter -Silencioso:$Silencioso; return }
    $Sub  = Obtener-SubredBase -Gateway $RI.Gateway -InterfaceIndex $RI.InterfaceIndex
    $Ping = New-Object System.Net.NetworkInformation.Ping

    $Actual = @{}
    for ($i = 1; $i -le 254; $i++) {
        $IP = "$Sub.$i"
        try {
            if ($Ping.Send($IP, 150).Status -eq 'Success') {
                $null = arp -a 2>$null; Start-Sleep -Milliseconds 60
                $MAC    = Get-MACDesdeARP -IP $IP
                $HostN  = "Oculto"
                try { $H = [System.Net.Dns]::GetHostEntry($IP); if ($H.HostName) { $HostN = $H.HostName } } catch { }
                $Actual[$IP] = @{ MAC = $MAC; Host = $HostN }
            }
        } catch { }
    }

    Write-Host "`n  $("-" * 60)" -ForegroundColor DarkGray
    Write-Host "  RESULTADO DE LA COMPARATIVA`n" -ForegroundColor Cyan

    $Log = @("=== COMPARATIVA DE DISPOSITIVOS === $(Get-Date)", "Subred: ${Sub}.x", "")

    # Devices nuevos
    $Nuevos = $Actual.Keys | Where-Object { -not $Previo.ContainsKey($_) }
    if ($Nuevos) {
        Write-Host "  NEW DEVICES (not present in previous scan)" -ForegroundColor Yellow
        $Log += "  NUEVOS:"
        foreach ($IP in ($Nuevos | Sort-Object)) {
            $Fab = Get-Fabricante -MAC $Actual[$IP].MAC
            Write-Host "  [+] $IP  |  $($Actual[$IP].MAC)  |  $Fab  |  $($Actual[$IP].Host)" -ForegroundColor Green
            $Log += "  [+] $IP | $($Actual[$IP].MAC) | $Fab | $($Actual[$IP].Host)"
        }
        $Log += ""
        Write-Host ""
    }

    # Devices desaparecidos
    $Idos = $Previo.Keys | Where-Object { -not $Actual.ContainsKey($_) }
    if ($Idos) {
        Write-Host "  MISSING DEVICES (were present before, no longer responding)" -ForegroundColor DarkGray
        $Log += "  DESAPARECIDOS:"
        foreach ($IP in ($Idos | Sort-Object)) {
            Write-Host "  [-] $IP  |  $($Previo[$IP].MAC)  |  $($Previo[$IP].Host)" -ForegroundColor DarkGray
            $Log += "  [-] $IP | $($Previo[$IP].MAC) | $($Previo[$IP].Host)"
        }
        $Log += ""
        Write-Host ""
    }

    # Sin cambios
    $Iguales = $Actual.Keys | Where-Object { $Previo.ContainsKey($_) }
    Write-Host "  SIN CAMBIOS: $($Iguales.Count) device(s)" -ForegroundColor DarkGray
    $Log += "  SIN CAMBIOS: $($Iguales.Count)"

    Write-Host ""
    if (-not $Nuevos -and -not $Idos) {
        Write-Host "  La red no ha cambiado desde el ultimo escaneo." -ForegroundColor Green
    }

    # Guardar el nuevo estado como el actual
    try {
        ($Actual.Keys | ForEach-Object { "$_|$($Actual[$_].MAC)|$($Actual[$_].Host)" }) |
        Out-File $script:ArchivoEstado -Encoding UTF8 -Force
    } catch { }

    $script:HistorialSesion.Add("[N] Comparativa | +$($Nuevos.Count) nuevos | -$($Idos.Count) desaparecidos")

    if (-not $Silencioso -and -not $script:ModoAuto) {
        $Exp = Read-Host "`n  Exportar informe a TXT? (Y/N)"
        if ($Exp -match '^[SsYy]$') { Exportar-Informe -Contenido $Log -NombreModulo "Comparativa" | Out-Null }
    }

    Esperar-Enter -Silencioso:$Silencioso
}

# ================================================================
#  MODULO P - TEST DE VELOCIDAD DE DESCARGA
# ================================================================
function Modulo-Velocidad {
    param([switch]$Silencioso)
    if (-not $Silencioso -and -not (Mostrar-InfoModulo "P")) { return }

    Clear-Host
    Write-Host ""
    Write-Host "  [ P ]  TEST DE VELOCIDAD DE DESCARGA" -ForegroundColor Yellow
    Write-Host "  $("-" * 60)" -ForegroundColor DarkGray
    Write-Host ""

    $URL_5MB  = "https://speed.cloudflare.com/__down?bytes=5242880"
    $URL_10MB = "https://speed.cloudflare.com/__down?bytes=10485760"

    $Resultados = @()
    $Log = @("=== TEST DE VELOCIDAD === $(Get-Date)", "Servidor: Cloudflare CDN", "")

    foreach ($Prueba in @(@{ URL = $URL_5MB; Tam = 5 }, @{ URL = $URL_10MB; Tam = 10 })) {
        Write-Host "  Downloading $($Prueba.Tam) MB desde Cloudflare..." -ForegroundColor DarkGray -NoNewline
        try {
            $T0   = Get-Date
            $null = Invoke-WebRequest -Uri $Prueba.URL -UseBasicParsing -TimeoutSec 60 -ErrorAction Stop
            $Secs = (New-TimeSpan -Start $T0 -End (Get-Date)).TotalSeconds
            $MBs  = [Math]::Round($Prueba.Tam / $Secs, 2)
            $Mbps = [Math]::Round($MBs * 8, 1)

            $C = if ($Mbps -lt 5) { "Red" } elseif ($Mbps -lt 25) { "Yellow" } else { "Green" }
            Write-Host " OK" -ForegroundColor Green
            Write-Host ("  Resultado ($($Prueba.Tam) MB):  {0,7} MB/s  =  {1,8} Mbps  (en {2:F1}s)" -f $MBs, $Mbps, $Secs) -ForegroundColor $C
            $Log     += "  Test $($Prueba.Tam) MB : $MBs MB/s = $Mbps Mbps en $([Math]::Round($Secs,1))s"
            $Resultados += $Mbps
        } catch {
            Write-Host " ERROR" -ForegroundColor Red
            Write-Host "  Could not download file. Check connection." -ForegroundColor Red
            $Log += "  Test $($Prueba.Tam) MB : ERROR"
        }
        Write-Host ""
    }

    if ($Resultados.Count -gt 0) {
        $Media = [Math]::Round(($Resultados | Measure-Object -Average).Average, 1)
        Write-Host "  Media aproximada: $Media Mbps" -ForegroundColor White
        Write-Host ""
        Write-Host "  REFERENCIA:" -ForegroundColor Cyan
        Write-Host "    < 5 Mbps    Very slow. Severe connection issues." -ForegroundColor Red
        Write-Host "    5 - 25 Mbps Basica. Navegacion y streaming SD." -ForegroundColor Yellow
        Write-Host "    25 - 100 Mbps Buena. Streaming HD y videollamadas." -ForegroundColor Green
        Write-Host "    > 100 Mbps  Excellent. Fit for any use." -ForegroundColor Cyan
        Write-Host ""
        Write-Host "  NOTE: Run on cable and WiFi to compare differences." -ForegroundColor DarkGray
        $Log += "  Media: $Media Mbps"
    }

    $script:HistorialSesion.Add("[P] Test velocidad | Media: $(if ($Resultados.Count) { ($Resultados | Measure-Object -Average).Average.ToString('F1') } else { 'ERROR' }) Mbps")

    if (-not $Silencioso -and -not $script:ModoAuto) {
        $Exp = Read-Host "`n  Exportar informe a TXT? (Y/N)"
        if ($Exp -match '^[SsYy]$') { Exportar-Informe -Contenido $Log -NombreModulo "Velocidad" | Out-Null }
    }

    Esperar-Enter -Silencioso:$Silencioso
}

# ================================================================
#  MODULO Q - DETECCION DE PORTAL CAUTIVO
# ================================================================
function Modulo-PortalCautivo {
    param([switch]$Silencioso)
    if (-not $Silencioso -and -not (Mostrar-InfoModulo "Q")) { return }

    Clear-Host
    Write-Host ""
    Write-Host "  [ Q ]  DETECCION DE PORTAL CAUTIVO" -ForegroundColor DarkYellow
    Write-Host "  $("-" * 60)" -ForegroundColor DarkGray
    Write-Host "`n  Verifying conectividad limpia a Internet...`n" -ForegroundColor DarkGray

    $Log = @("=== PORTAL CAUTIVO === $(Get-Date)", "")
    $Resultado = "DESCONOCIDO"

    try {
        # Google genera_204 es el estandar de deteccion de portal cautivo
        $R = Invoke-WebRequest -Uri "http://connectivitycheck.gstatic.com/generate_204" `
             -UseBasicParsing -TimeoutSec 5 -MaximumRedirection 0 -ErrorAction Stop

        if ($R.StatusCode -eq 204) {
            Write-Host "  RESULTADO: Connection limpia" -ForegroundColor Green
            Write-Host "  HTTP 204 recibido -> No hay portal cautivo activo." -ForegroundColor Green
            Write-Host "`n  Your device has direct Internet access with no interception." -ForegroundColor White
            $Resultado = "LIMPIA"
            $Log      += "  Resultado : Connection limpia (HTTP 204)"
        } elseif ($R.StatusCode -eq 200) {
            Write-Host "  RESULTADO: Portal cautivo detectado" -ForegroundColor Red
            Write-Host "  HTTP 200 instead of 204 -> Response was intercepted." -ForegroundColor Red
            Write-Host "`n  ACCION RECOMENDADA:" -ForegroundColor Yellow
            Write-Host "    Open the browser and navigate to http://neverssl.com" -ForegroundColor Yellow
            Write-Host "    The registration portal will open automatically." -ForegroundColor Yellow
            $Resultado = "PORTAL CAUTIVO"
            $Log      += "  Resultado : Portal cautivo detectado (HTTP 200)"
        } else {
            Write-Host "  RESULTADO: Response inesperada (HTTP $($R.StatusCode))" -ForegroundColor Yellow
            $Resultado = "INESPERADO ($($R.StatusCode))"
            $Log      += "  Resultado : Response inesperada HTTP $($R.StatusCode)"
        }
    } catch {
        # Una redireccion (30x) normalmente es portal cautivo
        $Msg = $_.Exception.Message
        if ($Msg -match "redirect|30[0-9]|Location") {
            Write-Host "  RESULTADO: Portal cautivo detectado (redireccion 3xx)" -ForegroundColor Red
            Write-Host "`n  ACCION RECOMENDADA:" -ForegroundColor Yellow
            Write-Host "    Open the browser and navigate to http://neverssl.com" -ForegroundColor Yellow
            $Resultado = "PORTAL CAUTIVO (redireccion)"
            $Log      += "  Resultado : Portal cautivo - redireccion detectada"
        } else {
            Write-Host "  RESULT: No Internet connection" -ForegroundColor Red
            Write-Host "  No se pudo alcanzar el servidor de verificacion." -ForegroundColor DarkGray
            Write-Host "`n  Check that WiFi/cable is connected and run module D." -ForegroundColor Yellow
            $Resultado = "SIN INTERNET"
            $Log      += "  Result  : No Internet connection"
        }
    }

    # Prueba adicional con Apple
    try {
        $R2 = Invoke-WebRequest -Uri "http://captive.apple.com/hotspot-detect.html" `
              -UseBasicParsing -TimeoutSec 5 -MaximumRedirection 0 -ErrorAction Stop
        $EsPortal2 = $R2.Content -notmatch "Success"
        $Log += "  Apple captive.apple.com : $(if ($EsPortal2) { 'Portal detectado' } else { 'Limpio' })"
    } catch { }

    $script:HistorialSesion.Add("[Q] Portal cautivo: $Resultado")

    if (-not $Silencioso -and -not $script:ModoAuto) {
        $Exp = Read-Host "`n  Exportar informe a TXT? (Y/N)"
        if ($Exp -match '^[SsYy]$') { Exportar-Informe -Contenido $Log -NombreModulo "PortalCautivo" | Out-Null }
    }

    Esperar-Enter -Silencioso:$Silencioso
}

# ================================================================
#  MODULO I - HISTORIAL DE SESION
# ================================================================
function Modulo-WiFiGuardadas {
    Clear-Host
    Write-Host ""
    Write-Host "  [ K ]  PASSWORDS WIFI GUARDADAS" -ForegroundColor Yellow
    Write-Host "  $("-" * 60)" -ForegroundColor DarkGray
    Write-Host ""
    Write-Host "  [!] WiFi networks saved on this PC will be shown" -ForegroundColor Cyan
    Write-Host "      along with their passwords (requires admin)." -ForegroundColor Cyan
    Write-Host "  [!] This is sensitive information. Use only on your own computers" -ForegroundColor Yellow
    Write-Host "      or with explicit owner authorization." -ForegroundColor Yellow
    Write-Host ""
    $ok = Read-Host "  Continuar? [Y/N]"
    if ($ok -notmatch '^[SsYy]$') { return }

    $isAdmin = ([Security.Principal.WindowsPrincipal][Security.Principal.WindowsIdentity]::GetCurrent()).IsInRole([Security.Principal.WindowsBuiltInRole]::Administrator)
    if (-not $isAdmin) {
        Write-Host ""
        Write-Host "  [X] Esta option requiere run como administrador." -ForegroundColor Red
        Esperar-Enter
        return
    }

    Write-Host ""
    Write-Host "  Consultando perfiles WLAN..." -ForegroundColor DarkGray

    $raw = netsh wlan show profiles 2>$null
    $perfiles = @()
    foreach ($line in $raw) {
        if ($line -match "Perfil de all users\s*:\s*(.+)$" -or $line -match "All User Profile\s*:\s*(.+)$") {
            $perfiles += ($matches[1]).Trim()
        }
    }

    if ($perfiles.Count -eq 0) {
        Write-Host "  [!] No se detectaron perfiles WLAN saved." -ForegroundColor Yellow
        Esperar-Enter
        return
    }

    $resultado = @()
    $resultado += "=== PASSWORDS WIFI GUARDADAS ==="
    $resultado += "Computer: $env:COMPUTERNAME"
    $resultado += "Date:  $(Get-Date -Format 'yyyy-MM-dd HH:mm:ss')"
    $resultado += ""
    $resultado += "{0,-40} {1,-15} {2}" -f "SSID", "Autenticacion", "Password"
    $resultado += ("-" * 80)

    foreach ($p in $perfiles) {
        $det = netsh wlan show profile name="$p" key=clear 2>$null
        $auth = ""
        $pass = ""
        foreach ($l in $det) {
            if ($l -match "Autenticaci.n\s*:\s*(.+)$" -or $l -match "Authentication\s*:\s*(.+)$") { $auth = ($matches[1]).Trim() }
            elseif ($l -match "Contenido de la clave\s*:\s*(.+)$" -or $l -match "Key Content\s*:\s*(.+)$") { $pass = ($matches[1]).Trim() }
        }
        if (-not $pass) { $pass = "(no password / open)" }
        if (-not $auth) { $auth = "?" }
        $linea = "{0,-40} {1,-15} {2}" -f $p, $auth, $pass
        $resultado += $linea
        Write-Host "  $linea" -ForegroundColor Green
    }

    Write-Host ""
    Write-Host "  Total perfiles: $($perfiles.Count)" -ForegroundColor Cyan
    Write-Host ""
    $x = Read-Host "  Export to TXT on Desktop? [Y/N]"
    if ($x -match '^[SsYy]$') { Exportar-Informe -Contenido $resultado -NombreModulo "WiFiGuardadas" }
    $script:HistorialSesion.Add("WiFi saved: $($perfiles.Count) perfiles") | Out-Null
    Esperar-Enter
}

function Modulo-PortScanGateway {
    Clear-Host
    Write-Host ""
    Write-Host "  [ O ]  ESCANEO DE PUERTOS DEL GATEWAY (ROUTER)" -ForegroundColor Yellow
    Write-Host "  $("-" * 60)" -ForegroundColor DarkGray
    Write-Host ""

    $gw = Obtener-Router
    if (-not $gw) {
        Write-Host "  [X] No se pudo determinar el gateway." -ForegroundColor Red
        Esperar-Enter; return
    }

    Write-Host "  Gateway: $gw" -ForegroundColor Cyan
    Write-Host ""
    Write-Host "  Scanning puertos tipicos abiertos..." -ForegroundColor DarkGray
    Write-Host ""

    $puertos = @(
        @{ p=21;    s="FTP"         },
        @{ p=22;    s="SSH"         },
        @{ p=23;    s="Telnet"      },
        @{ p=53;    s="DNS"         },
        @{ p=80;    s="HTTP (panel)"},
        @{ p=81;    s="HTTP alt"    },
        @{ p=123;   s="NTP"         },
        @{ p=139;   s="NetBIOS"     },
        @{ p=443;   s="HTTPS"       },
        @{ p=445;   s="SMB"         },
        @{ p=515;   s="LPD imp."    },
        @{ p=548;   s="AFP"         },
        @{ p=554;   s="RTSP"        },
        @{ p=631;   s="IPP imp."    },
        @{ p=1900;  s="UPnP"        },
        @{ p=5000;  s="UPnP alt"    },
        @{ p=5357;  s="WSD"         },
        @{ p=7547;  s="TR-069 CWMP" },
        @{ p=8080;  s="HTTP proxy"  },
        @{ p=8081;  s="HTTP alt"    },
        @{ p=8291;  s="MikroTik"    },
        @{ p=8443;  s="HTTPS alt"   },
        @{ p=8888;  s="HTTP alt"    },
        @{ p=9100;  s="JetDirect"   }
    )

    $resultado = @()
    $resultado += "=== ESCANEO PUERTOS GATEWAY ==="
    $resultado += "Gateway: $gw"
    $resultado += "Date:   $(Get-Date -Format 'yyyy-MM-dd HH:mm:ss')"
    $resultado += ""

    $abiertos = 0; $total = $puertos.Count; $n = 0
    foreach ($e in $puertos) {
        $n++
        Write-Progress -Activity "Scanning gateway ports" -Status ("Puerto {0}/{1} - {2}" -f $n, $total, $e.p) -PercentComplete (($n / $total) * 100)
        $ok = Test-Puerto -Destino $gw -Puerto $e.p -TimeoutMs 600
        if ($ok) {
            $line = ("  [OK] {0,5}/tcp  {1}" -f $e.p, $e.s)
            Write-Host $line -ForegroundColor Green
            $resultado += "ABIERTO {0,5}/tcp - {1}" -f $e.p, $e.s
            $abiertos++
        }
    }
    Write-Progress -Activity "Scanning gateway ports" -Completed

    Write-Host ""
    Write-Host "  Total abiertos: $abiertos / $total" -ForegroundColor Cyan
    Write-Host ""
    if ($abiertos -gt 0) {
        Write-Host "  NOTA: Un panel web (80/443/8080/8443) es normal." -ForegroundColor DarkGray
        Write-Host "  Ports such as Telnet (23), SMB (445), FTP (21) open on the router" -ForegroundColor Yellow
        Write-Host "  suelen indicar configuration insegura. Revisa el panel." -ForegroundColor Yellow
    }
    Write-Host ""
    $x = Read-Host "  Exportar TXT? [Y/N]"
    if ($x -match '^[SsYy]$') { Exportar-Informe -Contenido $resultado -NombreModulo "PortScanGateway" }
    $script:HistorialSesion.Add("PortScan Gateway: $abiertos abiertos en $gw") | Out-Null
    Esperar-Enter
}

function Modulo-ARPCompleto {
    Clear-Host
    Write-Host ""
    Write-Host "  [ R ]  DISPOSITIVOS EN LA LAN (ARP / NEIGHBOR)" -ForegroundColor Yellow
    Write-Host "  $("-" * 60)" -ForegroundColor DarkGray
    Write-Host ""

    $entries = @()

    try {
        $nbrs = Get-NetNeighbor -AddressFamily IPv4 -ErrorAction SilentlyContinue | Where-Object {
            $_.State -in 'Reachable','Stale','Permanent','Delay','Probe' -and
            $_.IPAddress -notmatch '^(224\.|239\.|255\.)' -and
            $_.LinkLayerAddress -and $_.LinkLayerAddress -ne '00-00-00-00-00-00'
        }
        foreach ($n in $nbrs) {
            $entries += [pscustomobject]@{
                IP = $n.IPAddress
                MAC = ($n.LinkLayerAddress -replace ':', '-').ToUpper()
                Estado = $n.State
                Fuente = 'Get-NetNeighbor'
            }
        }
    } catch { }

    # Fallback a arp -a
    if ($entries.Count -eq 0) {
        $raw = arp -a 2>$null
        foreach ($l in $raw) {
            if ($l -match '(\d+\.\d+\.\d+\.\d+)\s+([0-9a-fA-F]{2}[-:][0-9a-fA-F]{2}[-:][0-9a-fA-F]{2}[-:][0-9a-fA-F]{2}[-:][0-9a-fA-F]{2}[-:][0-9a-fA-F]{2})\s+(\w+)') {
                $m = ($matches[2] -replace ':', '-').ToUpper()
                if ($m -ne 'FF-FF-FF-FF-FF-FF' -and $m -ne '00-00-00-00-00-00') {
                    $entries += [pscustomobject]@{
                        IP = $matches[1]
                        MAC = $m
                        Estado = $matches[3]
                        Fuente = 'arp -a'
                    }
                }
            }
        }
    }

    if ($entries.Count -eq 0) {
        Write-Host "  [!] No devices detected. Try after pinging the gateway." -ForegroundColor Yellow
        Esperar-Enter; return
    }

    $gw = Obtener-Router

    $resultado = @()
    $resultado += "=== DISPOSITIVOS EN LA LAN ==="
    $resultado += "Gateway: $gw"
    $resultado += "Date:   $(Get-Date -Format 'yyyy-MM-dd HH:mm:ss')"
    $resultado += ""
    $resultado += "{0,-16} {1,-18} {2,-10} {3,-12} {4}" -f "IP", "MAC", "Estado", "Fuente", "Fabricante"
    $resultado += ("-" * 80)

    Write-Host ("  {0,-16} {1,-18} {2,-10} {3,-12} {4}" -f "IP", "MAC", "Estado", "Fuente", "Fabricante") -ForegroundColor Cyan
    Write-Host "  $('-' * 80)" -ForegroundColor DarkGray

    $porFabricante = @{}
    foreach ($e in ($entries | Sort-Object { [version]($_.IP -replace '^(\d+)\.(\d+)\.(\d+)\.(\d+)$', '$1.$2.$3.$4') } )) {
        $fab = Get-Fabricante -MAC $e.MAC
        $marker = if ($e.IP -eq $gw) { "*" } else { " " }
        $line = ("{0} {1,-15} {2,-18} {3,-10} {4,-12} {5}" -f $marker, $e.IP, $e.MAC, $e.Estado, $e.Fuente, $fab)
        Write-Host "  $line" -ForegroundColor White
        $resultado += $line.Trim()
        if (-not $porFabricante.ContainsKey($fab)) { $porFabricante[$fab] = 0 }
        $porFabricante[$fab]++
    }

    Write-Host ""
    Write-Host "  Total devices: $($entries.Count)  (* = gateway)" -ForegroundColor Cyan
    Write-Host ""
    Write-Host "  Summary by manufacturer:" -ForegroundColor DarkGray
    foreach ($k in ($porFabricante.Keys | Sort-Object)) {
        Write-Host ("    {0,-20} {1}" -f $k, $porFabricante[$k]) -ForegroundColor DarkGray
    }
    Write-Host ""

    $x = Read-Host "  Exportar TXT? [Y/N]"
    if ($x -match '^[SsYy]$') { Exportar-Informe -Contenido $resultado -NombreModulo "ARPCompleto" }
    $script:HistorialSesion.Add("ARP LAN: $($entries.Count) devices") | Out-Null
    Esperar-Enter
}

function Mostrar-Historial {
    Clear-Host
    Write-Host ""
    Write-Host "  [ I ]  HISTORIAL DE SESION" -ForegroundColor DarkGray
    Write-Host "  $("-" * 60)" -ForegroundColor DarkGray
    Write-Host ""
    if ($script:HistorialSesion.Count -eq 0) {
        Write-Host "  You have not run any tool in this session yet." -ForegroundColor DarkGray
    } else {
        Write-Host "  Actions performed this session:`n" -ForegroundColor Cyan
        $n = 1
        foreach ($E in $script:HistorialSesion) {
            Write-Host ("  {0,2}. {1}" -f $n, $E) -ForegroundColor White
            $n++
        }
    }
    Esperar-Enter
}

# ================================================================
#  MODO AUTO (-Auto): run informe completo y salir
# ================================================================
if ($script:ModoAuto) {
    Modulo-InformeCompleto -Silencioso
    return
}

# ================================================================
#  MENU PRINCIPAL
# ================================================================
while ($true) {
    Clear-Host
    Write-Host "`n"
    Escribir-Centrado "  +--------------------------------------------------------------+  " "DarkGray"
    Escribir-Centrado "  |                                                              |  " "Yellow"
    Escribir-Centrado "  |                   ATLAS PC SUPPORT                          |  " "Yellow"
    Escribir-Centrado "  |               HERRAMIENTAS DE RED  v3.0                     |  " "Yellow"
    Escribir-Centrado "  |                                                              |  " "Yellow"
    Escribir-Centrado "  +--------------------------------------------------------------+  " "DarkGray"
    Write-Host ""
    Escribir-Centrado "  +--- DIAGNOSTICO BASICO ------+---- HERRAMIENTAS AVANZADAS --+  " "DarkGray"
    Escribir-Centrado "  |                             |                              |  " "DarkGray"
    Escribir-Centrado "  |  [A]  LAN Ports Audit       |  [L]  Router Firmware       |  " "White"
    Escribir-Centrado "  |  [B]  Escaneo Devices  |  [M]  Informe Automatico    |  " "White"
    Escribir-Centrado "  |  [C]  Router Panel          |  [N]  Network Comparison    |  " "Cyan"
    Escribir-Centrado "  |  [D]  Latencia / Estabilidad|  [P]  Test de Velocidad     |  " "White"
    Escribir-Centrado "  |  [E]  Adapter Info          |  [Q]  Captive Portal        |  " "White"
    Escribir-Centrado "  |  [F]  Test de DNS           |                              |  " "White"
    Escribir-Centrado "  |  [H]  Puertos WAN           |  [J]  Fabricantes (MAC/OUI) |  " "White"
    Escribir-Centrado "  |                             |                              |  " "DarkGray"
    Escribir-Centrado "  +--- SEGURIDAD / RECON -------+------------------------------+  " "DarkGray"
    Escribir-Centrado "  |  [K]  Passwords WiFi      |  [O]  Scan puertos gateway  |  " "Cyan"
    Escribir-Centrado "  |  [R]  Devices LAN (ARP)|                              |  " "Cyan"
    Escribir-Centrado "  +--- SESION ------------------+------------------------------+  " "DarkGray"
    Escribir-Centrado "  |  [I]  Historial de Sesion   |  [S]  Salir                 |  " "DarkGray"
    Escribir-Centrado "  +-----------------------------+------------------------------+  " "DarkGray"
    Write-Host ""
    if ($script:HistorialSesion.Count -gt 0) {
        Escribir-Centrado "  Session actions: $($script:HistorialSesion.Count)  |  Info: $(if ($script:MostrarInfo) { 'on' } else { 'off' })  " "DarkGray"
        Write-Host ""
    }

    $Op = Read-Host "  Choose an option"

    switch ($Op.ToUpper()) {
        "A" { Modulo-Auditoria     }
        "B" { Modulo-Escaneo       }
        "C" { Modulo-Panel         }
        "D" { Modulo-Latencia      }
        "E" { Modulo-InfoAdaptador }
        "F" { Modulo-TestDNS       }
        "H" { Modulo-PuertosWAN    }
        "I" { Mostrar-Historial    }
        "J" { Modulo-Fabricantes   }
        "K" { Modulo-WiFiGuardadas }
        "L" { Modulo-Firmware      }
        "O" { Modulo-PortScanGateway }
        "R" { Modulo-ARPCompleto   }
        "M" { Modulo-InformeCompleto }
        "N" { Modulo-Comparativa   }
        "P" { Modulo-Velocidad     }
        "Q" { Modulo-PortalCautivo }
        "S" {
            if ($script:HistorialSesion.Count -gt 0) {
                Write-Host ""
                Write-Host "  --- RESUMEN DE SESION ---" -ForegroundColor Yellow
                $n = 1
                foreach ($E in $script:HistorialSesion) {
                    Write-Host ("  {0,2}. {1}" -f $n, $E) -ForegroundColor DarkGray
                    $n++
                }
            }
            Write-Host "`n  Closing herramientas... Hasta pronto, Atlas!" -ForegroundColor Yellow
            Start-Sleep -Seconds 1
            [console]::ResetColor()
            Clear-Host
            return
        }
        default {
            Write-Host "`n  Invalid option. Choose a letter from the menu." -ForegroundColor Red
            Start-Sleep -Seconds 1
        }
    }
}
}


# ---- tools\Invoke-DiagnosticoEventos.ps1 ----
function Invoke-DiagnosticoEventos {
    <#
    .SYNOPSIS
      Event Log Analyzer: reads the Windows Event Viewer and explains
      common errors in plain language with a suggested action.

    .DESCRIPTION
      - Filters events by category (reboots, hardware, crashes, drivers, security).
      - Translates the most common EventIDs into plain language + severity + recommendation.
      - Exports an HTML report to share with a customer or archive.
      - Runs isolated (ToolRunner), independent of launcher libraries.
      - Bilingual (en default + full es). Function name preserved for tools.json.
    #>

    $ErrorActionPreference = 'Stop'

    function _Atlas-DetectLang {
        if ($env:ATLAS_LANG) { return [string]$env:ATLAS_LANG }
        try {
            $cfg = Join-Path $env:LOCALAPPDATA 'AtlasPC\config.json'
            if (Test-Path -LiteralPath $cfg) {
                $obj = Get-Content -Raw -LiteralPath $cfg -Encoding UTF8 | ConvertFrom-Json
                if ($obj.language) { return [string]$obj.language }
            }
        } catch {}
        $sys = (Get-Culture).TwoLetterISOLanguageName
        if ($sys -eq 'es') { return 'es' }
        return 'en'
    }

    $T = @{
        en = @{
            HeaderBar    = '================================================================'
            HeaderTitle  = '  Event Log Analyzer (Windows Event Viewer)'
            ComputerLbl  = 'Computer'
            Menu1        = '  [1] Recent critical errors (24h)'
            Menu2        = '  [2] Unexpected reboots (7d)'
            Menu3        = '  [3] Hardware (WHEA / Disk) (7d)'
            Menu4        = '  [4] App crashes (7d)'
            Menu5        = '  [5] Drivers (7d)'
            Menu6        = '  [6] Security (7d) [requires admin]'
            Menu7        = '  [7] Export HTML report (last 7d)'
            Menu8        = '  [8] Look up by EventID (knowledge base)'
            MenuQ        = '  [Q] Quit'
            OptPrompt    = '  Option'
            EnterBack    = "`n  ENTER to go back"
            Section1     = 'Critical / Errors (System + Application, 24h)'
            Section2     = 'Unexpected reboots (7d)'
            Section3     = 'Hardware WHEA + Disk (7d)'
            Section4     = 'Application crashes (7d)'
            Section5     = 'Failed drivers (7d)'
            Section6     = 'Security (7d)'
            SecDenied    = '  [X] Access to Security log denied: {0}'
            SecRetry     = '      Relaunch the panel as Administrator.'
            HtmlBuilding = '  Generating HTML report (last 7d)... 5-15s...'
            HtmlSaved    = '  [OK] Saved: {0}'
            HtmlError    = '  [X] Error: {0}'
            AskEventId   = '  EventID to look up (e.g. 41, 6008, 4625)'
            BadId        = '  [X] Invalid ID.'
            EnterPrompt  = "`n  ENTER"
            KbLine1      = '  [{0}] EventID {1} - {2}'
            KbSeverity   = '      Severity : {0}'
            KbCause      = '      Cause    : {0}'
            KbAction     = '      Action   : {0}'
            KbNotInDB    = '  [i] EventID {0} is not in the knowledge base.'
            KbGoogle     = '      Look it up at: https://www.google.com/search?q=windows+event+id+{0}'
            KbRecent     = '  Recent occurrences in System + Application (last 30d, top 5)...'
            KbNoneRecent = '    (none in the last 30 days)'
            NoEvents     = '    (no events in the queried range)'
            FieldProvider= 'Provider'
            FieldEventId = 'EventID'
            FieldLast    = 'Latest'
            FieldCause   = 'Cause'
            FieldAction  = 'Action'
            HtmlTitle    = 'ATLAS PC SUPPORT - Event Log Analyzer'
            HtmlEquipo   = 'Computer'
            HtmlRange    = 'Range: last {0} days'
            HtmlGen      = 'Generated'
            HtmlPrint    = '🖨  Print / PDF'
            HtmlSecCrit  = 'Recent Criticals (System+App)'
            HtmlSecBoot  = 'Unexpected Reboots'
            HtmlSecHw    = 'Hardware (WHEA / Disk)'
            HtmlSecCrash = 'App Crashes'
            HtmlSecDrv   = 'Drivers'
            HtmlSecSec   = 'Security'
            HtmlNoEvents = 'No events.'
            HtmlLang     = 'en'
        }
        es = @{
            HeaderBar    = '================================================================'
            HeaderTitle  = '  Diagnostico Eventos (Windows Event Viewer)'
            ComputerLbl  = 'Equipo'
            Menu1        = '  [1] Ultimos errores criticos (24h)'
            Menu2        = '  [2] Reinicios inesperados (7d)'
            Menu3        = '  [3] Hardware (WHEA / Disk) (7d)'
            Menu4        = '  [4] App crashes (7d)'
            Menu5        = '  [5] Drivers (7d)'
            Menu6        = '  [6] Seguridad (7d) [requiere admin]'
            Menu7        = '  [7] Exportar reporte HTML (ultimos 7d)'
            Menu8        = '  [8] Buscar por EventID (base de conocimiento)'
            MenuQ        = '  [Q] Salir'
            OptPrompt    = '  Opcion'
            EnterBack    = "`n  ENTER para volver"
            Section1     = 'Criticos / Errores (System + Application, 24h)'
            Section2     = 'Reinicios inesperados (7d)'
            Section3     = 'Hardware WHEA + Disk (7d)'
            Section4     = 'Application crashes (7d)'
            Section5     = 'Drivers fallidos (7d)'
            Section6     = 'Seguridad (7d)'
            SecDenied    = '  [X] Acceso a Security log denegado: {0}'
            SecRetry     = '      Relanza el panel como Administrador.'
            HtmlBuilding = '  Generando reporte HTML (ultimos 7d)... puede tardar 5-15s...'
            HtmlSaved    = '  [OK] Guardado: {0}'
            HtmlError    = '  [X] Error: {0}'
            AskEventId   = '  EventID a buscar (ej. 41, 6008, 4625)'
            BadId        = '  [X] ID invalido.'
            EnterPrompt  = "`n  ENTER"
            KbLine1      = '  [{0}] EventID {1} - {2}'
            KbSeverity   = '      Severidad: {0}'
            KbCause      = '      Causa    : {0}'
            KbAction     = '      Accion   : {0}'
            KbNotInDB    = '  [i] EventID {0} no esta en la base de conocimiento.'
            KbGoogle     = '      Consulta en: https://www.google.com/search?q=windows+event+id+{0}'
            KbRecent     = '  Mostrando ocurrencias recientes en System + Application (30d, top 5)...'
            KbNoneRecent = '    (ninguna en los ultimos 30 dias)'
            NoEvents     = '    (sin eventos en el rango consultado)'
            FieldProvider= 'Provider'
            FieldEventId = 'EventID'
            FieldLast    = 'Ultima'
            FieldCause   = 'Causa'
            FieldAction  = 'Accion'
            HtmlTitle    = 'ATLAS PC SUPPORT - Diagnostico Eventos'
            HtmlEquipo   = 'Equipo'
            HtmlRange    = 'Rango: ultimos {0} dias'
            HtmlGen      = 'Generado'
            HtmlPrint    = '🖨  Imprimir / PDF'
            HtmlSecCrit  = 'Ultimos Criticos (System+App)'
            HtmlSecBoot  = 'Reinicios Inesperados'
            HtmlSecHw    = 'Hardware (WHEA / Disk)'
            HtmlSecCrash = 'App Crashes'
            HtmlSecDrv   = 'Drivers'
            HtmlSecSec   = 'Seguridad'
            HtmlNoEvents = 'Sin eventos.'
            HtmlLang     = 'es'
        }
    }
    $lang = _Atlas-DetectLang
    if (-not $T.ContainsKey($lang)) { $lang = 'en' }
    $L = $T[$lang]

    # ----- Bilingual EventID knowledge base -----
    # Two parallel hashtables; we pick by language.
    $kbEn = @{
        '*|*|41' = @{ Level='CRITICAL'; Title='Kernel-Power: unexpected shutdown'; Cause='The system powered off without flushing. Typical causes: power outage, faulty PSU, overheating, silent BSOD, hardware reset button.'; Action='Check CPU/GPU temperatures (Parts Upgrade tool). If there was a BSOD: analyze C:\Windows\Minidump\*.dmp with WinDbg or BlueScreenView. If recurring: bench-test the PSU.' }
        '*|*|6008' = @{ Level='WARN'; Title='Previous shutdown was unexpected'; Cause='The PC turned off without a clean shutdown. Normal after a Kernel-Power 41.'; Action='Correlate with event 41 on the same date. If there is no 41, may be a power cut or hardware reset.' }
        '*|*|6006' = @{ Level='INFO'; Title='Event Log stopped (clean shutdown)'; Cause='The Event Log service stopped cleanly. Happens on every shutdown.'; Action='Informational. Its absence next to a 6008 indicates a dirty reboot.' }
        '*|*|1074' = @{ Level='INFO'; Title='Reboot/shutdown initiated by user or app'; Cause='Some process requested the reboot. The message states who (e.g. "Windows Update", "user X", "explorer.exe").'; Action='If you do not recognize the initiator: may be Windows Update (normal) or malware forcing a reboot.' }
        '*|*|1001' = @{ Level='WARN'; Title='Windows Error Reporting / Bugcheck'; Cause='A BSOD crash was reported. The message contains the stopcode (e.g. 0x0000001A = MEMORY_MANAGEMENT).'; Action='Look up the stopcode in the message. Quick table: 0x3B=driver, 0x7E=SYSTEM_THREAD, 0x1A=RAM, 0x9F=power/driver, 0x133=DPC_WATCHDOG (slow IO).' }
        '*|*|1000' = @{ Level='WARN'; Title='Application Error (app crashed)'; Cause='An application closed unexpectedly. The message names the exe + faulty module + address.'; Action='If it always recurs with the same exe: reinstall the app. If ntdll.dll is faulty module: may be hardware (RAM/disk).' }
        '*|*|1026' = @{ Level='WARN'; Title='.NET Runtime: unhandled exception'; Cause='.NET app crashed with an unhandled exception (StackOverflow, OOM, InvalidOperationException, etc.).'; Action='Check the stacktrace in the message. StackOverflow: infinite recursion in third-party code.' }
        '*|*|219' = @{ Level='WARN'; Title='Driver failed to load'; Cause='A signed driver failed to initialize. The message names the driver.'; Action='Open Device Manager, find the device. Reinstall a fresh driver from the vendor (NOT Windows Update if needed).' }
        '*|*|7026' = @{ Level='WARN'; Title='Boot-start driver failed'; Cause='One or more essential boot drivers did not load.'; Action='Critical if the driver is for storage (AHCI, NVMe). Check the message: antivirus/VPN/virtualization is usually harmless.' }
        '*|*|7001' = @{ Level='WARN'; Title='Service dependency failed'; Cause='A service did not start because a service it depended on failed.'; Action='Open services.msc and try a manual start. Sometimes indicates broken WMI (repair with winmgmt /resetrepository).' }
        '*|*|7031' = @{ Level='WARN'; Title='Service crashed'; Cause='A Windows service terminated unexpectedly.'; Action='If recurring: re-enable from services.msc or uninstall associated app. If Explorer/Shell: sfc /scannow + dism.' }
        '*|*|7034' = @{ Level='WARN'; Title='Service ended without notice'; Cause='Similar to 7031 - service died without a clean shutdown.'; Action='Same as 7031.' }
        '*|*|7' = @{ Level='CRITICAL'; Title='Bad block on disk (Disk error)'; Cause='The physical disk has corrupt sectors. Typical message: "The device, \\Device\\HarddiskX, has a bad block".'; Action='URGENT. Run SMART check (CrystalDiskInfo). If health <100%, plan backup + replacement NOW. Parts Upgrade tool gives you the model.' }
        '*|*|51' = @{ Level='CRITICAL'; Title='Disk I/O error'; Cause='Windows had a read/write error on disk. Loose SATA cable, controller, or failing disk.'; Action='Check cables (open the case). SMART check. If NVMe: verify BIOS is up to date.' }
        '*|*|52' = @{ Level='WARN'; Title='Disk capacity low'; Cause='Free space below the critical threshold.'; Action='Deep Clean & Repair tool -> free up space.' }
        '*|*|55' = @{ Level='WARN'; Title='File system corrupt'; Cause='NTFS/ReFS detected structural corruption.'; Action='chkdsk C: /f (requires reboot). If recurring: disk is failing physically.' }
        '*|*|153' = @{ Level='WARN'; Title='IO operation retried'; Cause='IO operation to disk had to be retried. Early symptom of a dying drive.'; Action='SMART check is a priority. Plan replacement.' }
        '*|WHEA-Logger|1' = @{ Level='CRITICAL'; Title='Hardware error: CPU/Bus'; Cause='WHEA (Windows Hardware Error Architecture) detected an unrecoverable hardware fault. Typically CPU overheat, corrupt RAM, or unstable PCIe.'; Action='Test RAM with MemTest86 4+ passes. Check temperatures. BIOS to latest firmware.' }
        '*|WHEA-Logger|17' = @{ Level='WARN'; Title='Hardware error corrected'; Cause='Hardware error the system was able to correct (e.g. PCIe AER). Does not crash but indicates degradation.'; Action='If frequent: motherboard or expansion card issue. Reseat PCIe (GPU/SSD). BIOS update.' }
        '*|WHEA-Logger|18' = @{ Level='CRITICAL'; Title='Fatal hardware error (Machine Check)'; Cause='Machine Check Exception (MCE). CPU reports a fatal error. Hardware instability is highly likely.'; Action='Check CPU temp (HWiNFO). Remove OC. Test RAM. If recurring: CPU or board may be defective.' }
        '*|WHEA-Logger|19' = @{ Level='WARN'; Title='Hardware error corrected (PCIe)'; Cause='PCIe bus error corrected via AER.'; Action='GPU/SSD PCIe poorly seated or faulty cable. Reseat + BIOS update.' }
        '*|WHEA-Logger|46' = @{ Level='INFO'; Title='CPU thermal throttling'; Cause='CPU lowered frequency due to overheating.'; Action='Parts Upgrade tool -> see temps. Repaste + clean fans. Old laptop: nearly certain.' }
        '*|*|10016' = @{ Level='INFO'; Title='DCOM permissions error'; Cause='An app tried to call a COM component without permission. Almost always harmless.'; Action='Ignorable. Microsoft acknowledges it as noise. Do not touch DCOM permissions unless you have a concrete symptom.' }
        '*|Microsoft-Windows-Kernel-Boot|134' = @{ Level='INFO'; Title='Boot time recorded'; Cause='Windows recorded how long boot took. Informational.'; Action='If very high (>60s with SSD): startup defrag, sfc, review startup programs.' }
        '*|*|4625' = @{ Level='WARN'; Title='Logon failure'; Cause='Someone tried to log in with wrong credentials. Message contains source IP + attempted username.'; Action='If many and from external IPs: brute-force attack. Disable public RDP, use a VPN.' }
        '*|*|4720' = @{ Level='WARN'; Title='User account created'; Cause='A new local account was created.'; Action='Verify you created it. If not: malware / unauthorized access. See who created it.' }
        '*|*|4726' = @{ Level='WARN'; Title='User account deleted'; Cause='A local account was deleted.'; Action='Verify it was not accidental. If not yours: intrusion.' }
        '*|*|4724' = @{ Level='WARN'; Title='Admin password reset'; Cause='An admin reset another account password.'; Action='Normal in helpdesk. If you do not recognize source: unauthorized access.' }
        '*|*|4740' = @{ Level='INFO'; Title='Account locked by failed attempts'; Cause='Account lockout (policy).'; Action='User forgot password or attack attempt.' }
        '*|*|4672' = @{ Level='INFO'; Title='Special privileges assigned'; Cause='An admin logged in (normal).'; Action='Informational. Useful to audit who has access.' }
        '*|*|16' = @{ Level='INFO'; Title='Microsoft-Windows-Time-Service sync'; Cause='Late or failed NTP sync.'; Action='If recurring: restart w32time. sc config w32time start=auto + w32tm /resync.' }
        '*|*|36888' = @{ Level='INFO'; Title='Schannel fatal error'; Cause='TLS handshake failed. Common with old apps/browsers and sites that require TLS 1.2+.'; Action='If annoying: enable TLS 1.2 in Internet Options. Update Windows.' }
    }
    $kbEs = @{
        '*|*|41' = @{ Level='CRITICAL'; Title='Kernel-Power: apagado inesperado'; Cause='El sistema se apago sin flushear. Causas tipicas: corte de corriente, PSU defectuosa, sobrecalentamiento, BSOD silencioso, boton de reset fisico.'; Action='Revisa temperaturas CPU/GPU (tool Parts Upgrade). Si hay BSOD: analiza C:\Windows\Minidump\*.dmp con WinDbg o BlueScreenView. Si repite: test de PSU con multimetro.' }
        '*|*|6008' = @{ Level='WARN'; Title='Apagado anterior inesperado'; Cause='El PC se apago sin hacer shutdown limpio. Normal tras un 41 (Kernel-Power).'; Action='Correlaciona con evento 41 en la misma fecha. Si no hay 41, puede ser corte electrico o reset fisico.' }
        '*|*|6006' = @{ Level='INFO'; Title='Event Log detenido (apagado normal)'; Cause='El servicio Event Log fue detenido de forma limpia. Ocurre en cada shutdown.'; Action='Informativo. Si su ausencia contrasta con un 6008, hubo reboot sucio.' }
        '*|*|1074' = @{ Level='INFO'; Title='Reinicio/apagado iniciado por usuario o app'; Cause='Algun proceso pidio el reinicio. El mensaje dice quien (ej. "Windows Update", "usuario X", "explorer.exe").'; Action='Si no reconoces el iniciador: puede ser Windows Update (normal) o malware que fuerza reboot.' }
        '*|*|1001' = @{ Level='WARN'; Title='Windows Error Reporting / Bugcheck'; Cause='Un crash BSOD se reporto. El mensaje contiene el stopcode (ej. 0x0000001A = MEMORY_MANAGEMENT).'; Action='Mira el stopcode en el mensaje. Tabla rapida: 0x3B=driver, 0x7E=SYSTEM_THREAD, 0x1A=RAM, 0x9F=power/driver, 0x133=DPC_WATCHDOG (IO lento).' }
        '*|*|1000' = @{ Level='WARN'; Title='Application Error (app crashed)'; Cause='Una aplicacion se cerro inesperadamente. El mensaje indica el exe + modulo faulty + direccion.'; Action='Si se repite siempre con el mismo exe: reinstalar la app. Si es ntdll.dll como faulty module: puede ser hardware (RAM/disco).' }
        '*|*|1026' = @{ Level='WARN'; Title='.NET Runtime: excepcion no controlada'; Cause='App .NET crasheo con excepcion sin manejar (StackOverflow, OOM, InvalidOperationException, etc.).'; Action='Mira el stacktrace en el mensaje. Si es StackOverflow: recursion infinita en codigo de terceros.' }
        '*|*|219' = @{ Level='WARN'; Title='Driver fallo al cargar'; Cause='Un driver firmado fallo su inicializacion. Mensaje indica nombre del driver.'; Action='Abre Device Manager, busca el dispositivo con el driver problemarico. Reinstala driver fresh (fabricante, NO Windows Update si hace falta).' }
        '*|*|7026' = @{ Level='WARN'; Title='Boot-start driver fallo'; Cause='Uno o varios drivers esenciales no cargaron en arranque.'; Action='Critico si el driver es de disco (AHCI, NVMe). Revisa mensaje: si es antivirus/VPN/virtualizacion, probablemente inofensivo.' }
        '*|*|7001' = @{ Level='WARN'; Title='Servicio dependencia fallo'; Cause='Un servicio no arranco porque otro del que dependia fallo.'; Action='Mira services.msc, intenta start manual. A veces indica WMI roto (reparar con winmgmt /resetrepository).' }
        '*|*|7031' = @{ Level='WARN'; Title='Servicio crasheo'; Cause='Un servicio Windows terminio inesperadamente.'; Action='Si repite: rehabilitar via services.msc o desinstalar app asociada. Si es Explorer/Shell: sfc /scannow + dism.' }
        '*|*|7034' = @{ Level='WARN'; Title='Servicio termino sin previo aviso'; Cause='Similar a 7031 — servicio murio sin shutdown limpio.'; Action='Igual que 7031.' }
        '*|*|7' = @{ Level='CRITICAL'; Title='Bad block en disco (Disk error)'; Cause='El disco fisico tiene sectores corruptos. Mensaje tipico: "The device, \\Device\\HarddiskX, has a bad block".'; Action='URGENTE. Ejecuta SMART check (CrystalDiskInfo). Si salud no es 100%, plan backup + reemplazo de disco YA. Tool Parts Upgrade te da el modelo.' }
        '*|*|51' = @{ Level='CRITICAL'; Title='Disk I/O error'; Cause='Windows tuvo un error al leer/escribir al disco. Cable SATA suelto, controladora, o disco fallando.'; Action='Verifica cables (abre caja). SMART check. Si NVMe: revisa que la BIOS este actualizada.' }
        '*|*|52' = @{ Level='WARN'; Title='Disk capacidad baja'; Cause='Espacio libre menor al umbral critico.'; Action='Tool Mantenimiento PRO -> liberar espacio.' }
        '*|*|55' = @{ Level='WARN'; Title='File system corrupt'; Cause='NTFS/ReFS detecto corrupcion estructural.'; Action='chkdsk C: /f (requiere reboot). Si repite: disco fallando fisicamente.' }
        '*|*|153' = @{ Level='WARN'; Title='IO operation retried'; Cause='Operacion IO al disco tuvo que reintentarse. Sintoma temprano de disco moribundo.'; Action='SMART check prioritario. Plan de reemplazo.' }
        '*|WHEA-Logger|1' = @{ Level='CRITICAL'; Title='Hardware error: CPU/Bus'; Cause='WHEA (Windows Hardware Error Architecture) detecto fallo hardware no recuperable. Tipicamente CPU overheat, RAM corrupta, o PCIe inestable.'; Action='Test RAM con MemTest86 4+ pases. Check temperaturas. BIOS al ultimo firmware.' }
        '*|WHEA-Logger|17' = @{ Level='WARN'; Title='Hardware error corregido'; Cause='Error hardware que el sistema pudo corregir (ej. PCIe AER). No causa crash, pero indica degradacion.'; Action='Si es frecuente: problema de placa/tarjeta expansion. Re-asiente PCIe (GPU/SSD). BIOS update.' }
        '*|WHEA-Logger|18' = @{ Level='CRITICAL'; Title='Fatal hardware error (Machine Check)'; Cause='Machine Check Exception (MCE). CPU reporta error fatal. Muy probable inestabilidad hardware.'; Action='Check CPU temp (HWiNFO). Remove OC. Test RAM. Si repite: CPU o placa posiblemente defectuosa.' }
        '*|WHEA-Logger|19' = @{ Level='WARN'; Title='Hardware error corregido (PCIe)'; Cause='Error en bus PCIe corregido via AER.'; Action='GPU/SSD PCIe mal asentada o cable defectuoso. Reseat + BIOS update.' }
        '*|WHEA-Logger|46' = @{ Level='INFO'; Title='Throttling CPU por temperatura'; Cause='CPU redujo frecuencia por sobrecalentamiento.'; Action='Tool Parts Upgrade -> ver temps. Limpieza de pasta termica + ventilador. Notebook viejo: casi seguro.' }
        '*|*|10016' = @{ Level='INFO'; Title='DCOM error de permisos'; Cause='App intento llamar a un componente COM sin permisos. Casi siempre inofensivo.'; Action='Ignorable. Microsoft lo reconoce como ruido. No toques DCOM permissions salvo que tengas sintoma concreto.' }
        '*|Microsoft-Windows-Kernel-Boot|134' = @{ Level='INFO'; Title='Tiempo de arranque registrado'; Cause='Windows registro el tiempo que tardo el boot. Informativo.'; Action='Si ves tiempo muy alto (>60s con SSD): defrag autostart, sfc, revisar programas de inicio.' }
        '*|*|4625' = @{ Level='WARN'; Title='Logon fallido'; Cause='Alguien intento login con credenciales incorrectas. Mensaje contiene IP origen + usuario intentado.'; Action='Si son muchos y de IPs externas: ataque por fuerza bruta. Desactiva RDP publico, usa VPN.' }
        '*|*|4720' = @{ Level='WARN'; Title='Cuenta de usuario creada'; Cause='Una nueva cuenta local se creo.'; Action='Verifica que la creaste tu. Si no: malware / acceso no autorizado. Ver quien la creo.' }
        '*|*|4726' = @{ Level='WARN'; Title='Cuenta de usuario eliminada'; Cause='Una cuenta local se elimino.'; Action='Verifica que no fue accidente. Si no lo hiciste tu: intrusion.' }
        '*|*|4724' = @{ Level='WARN'; Title='Password reset admin'; Cause='Un admin reseteo el password de otra cuenta.'; Action='Normal en helpdesk. Si no reconoces origen: acceso no autorizado.' }
        '*|*|4740' = @{ Level='INFO'; Title='Cuenta bloqueada por intentos fallidos'; Cause='Account lockout (policy).'; Action='Usuario olvido password o intento de ataque.' }
        '*|*|4672' = @{ Level='INFO'; Title='Privilegios especiales asignados'; Cause='Un admin hizo login (normal).'; Action='Informativo. Util para auditar quien tiene acceso.' }
        '*|*|16' = @{ Level='INFO'; Title='Microsoft-Windows-Time-Service sync'; Cause='NTP sync tardio o fallido.'; Action='Si repite: reiniciar w32time. sc config w32time start=auto + w32tm /resync.' }
        '*|*|36888' = @{ Level='INFO'; Title='Schannel fatal error'; Cause='TLS handshake fallo. Frecuente con apps/navegadores antiguos y sitios que requieren TLS 1.2+.'; Action='Si molesta: habilitar TLS 1.2 en Internet Options. Update Windows.' }
    }
    $script:AtlasEventsKB = if ($lang -eq 'es') { $kbEs } else { $kbEn }

    function _Kb-Lookup {
        param([string]$LogName, [string]$Provider, [int]$EventId)
        if ($null -eq $script:AtlasEventsKB) { return $null }
        $keys = @(
            "$LogName|$Provider|$EventId",
            "*|$Provider|$EventId",
            "*|*|$EventId"
        )
        foreach ($k in $keys) {
            if ($script:AtlasEventsKB.ContainsKey($k)) { return $script:AtlasEventsKB[$k] }
        }
        return $null
    }

    function _Level-Color {
        param([string]$Level)
        switch ($Level) {
            'CRITICAL' { 'Red' }
            'WARN'     { 'Yellow' }
            'INFO'     { 'DarkCyan' }
            default    { 'Gray' }
        }
    }

    function _Level-Icon {
        param([string]$Level)
        switch ($Level) {
            'CRITICAL' { '[X]' }
            'WARN'     { '[!]' }
            'INFO'     { '[i]' }
            default    { '   ' }
        }
    }

    function _Query-Events {
        param(
            [string]$LogName = 'System',
            [int[]]$Levels = @(1,2,3,4),
            [int[]]$Ids = $null,
            [int]$Hours = 24,
            [int]$MaxEvents = 500
        )
        $since = (Get-Date).AddHours(-[int]$Hours)
        $filter = @{
            LogName      = $LogName
            Level        = $Levels
            StartTime    = $since
        }
        if ($Ids -and $Ids.Count -gt 0) { $filter['Id'] = $Ids }
        try {
            return @(Get-WinEvent -FilterHashtable $filter -MaxEvents $MaxEvents -ErrorAction Stop)
        } catch {
            return @()
        }
    }

    function _Render-Events {
        param([array]$Events, [string]$Heading)
        Write-Host ''
        Write-Host "  --- $Heading ---" -ForegroundColor Cyan
        if (-not $Events -or $Events.Count -eq 0) {
            Write-Host $L.NoEvents -ForegroundColor DarkGray
            return
        }
        $groups = $Events | Group-Object ProviderName, Id | Sort-Object Count -Descending
        foreach ($g in $groups) {
            $first = $g.Group[0]
            $kb = _Kb-Lookup $first.LogName $first.ProviderName ([int]$first.Id)
            $level = if ($kb) { $kb.Level } else { 'INFO' }
            $icon  = _Level-Icon $level
            $color = _Level-Color $level
            $title = if ($kb) { $kb.Title } else { "$($first.ProviderName) #$($first.Id)" }
            Write-Host ''
            Write-Host ("  $icon $title  [x$($g.Count)]") -ForegroundColor $color
            Write-Host ("     $($L.FieldProvider): $($first.ProviderName) - $($L.FieldEventId): $($first.Id) - $($L.FieldLast): $($first.TimeCreated.ToString('yyyy-MM-dd HH:mm'))") -ForegroundColor DarkGray
            if ($kb) {
                Write-Host ("     $($L.FieldCause) : $($kb.Cause)") -ForegroundColor Gray
                Write-Host ("     $($L.FieldAction): $($kb.Action)") -ForegroundColor White
            } else {
                $msg = ($first.Message -replace "`r?`n", ' ').Trim()
                if ($msg.Length -gt 180) { $msg = $msg.Substring(0,177) + '...' }
                Write-Host ("     $msg") -ForegroundColor Gray
            }
        }
    }

    function _Build-HtmlReport {
        param([string]$OutPath, [int]$Hours = 168)
        $sections = [ordered]@{}
        $sections[$L.HtmlSecCrit]  = (_Query-Events -LogName 'System'      -Levels @(1,2) -Hours $Hours -MaxEvents 200) +
                                     (_Query-Events -LogName 'Application' -Levels @(1,2) -Hours $Hours -MaxEvents 200)
        $sections[$L.HtmlSecBoot]  = _Query-Events -LogName 'System' -Ids @(41,6008,6006,1074) -Hours $Hours -MaxEvents 200
        $sections[$L.HtmlSecHw]    = _Query-Events -LogName 'System' -Ids @(1,17,18,19,46,47,7,51,52,55,153) -Hours $Hours -MaxEvents 200
        $sections[$L.HtmlSecCrash] = _Query-Events -LogName 'Application' -Ids @(1000,1001,1026) -Hours $Hours -MaxEvents 200
        $sections[$L.HtmlSecDrv]   = _Query-Events -LogName 'System' -Ids @(219,7026) -Hours $Hours -MaxEvents 200

        try {
            $sec = _Query-Events -LogName 'Security' -Ids @(4625,4720,4726,4724,4740) -Hours $Hours -MaxEvents 200
            if ($sec -and $sec.Count -gt 0) { $sections[$L.HtmlSecSec] = $sec }
        } catch {}

        $hostName  = $env:COMPUTERNAME
        $generated = (Get-Date).ToString('yyyy-MM-dd HH:mm:ss')
        $days = [int]([math]::Round($Hours/24))

        $htmlSections = ''
        foreach ($title in $sections.Keys) {
            $events = @($sections[$title])
            $htmlSections += "<section><h2>$([System.Net.WebUtility]::HtmlEncode($title)) <span class='count'>(" + $events.Count + ")</span></h2>"
            if ($events.Count -eq 0) {
                $htmlSections += "<p class='muted'>$($L.HtmlNoEvents)</p></section>"
                continue
            }
            $groups = $events | Group-Object ProviderName, Id | Sort-Object Count -Descending
            $htmlSections += "<div class='events'>"
            foreach ($g in $groups) {
                $first = $g.Group[0]
                $kb = _Kb-Lookup $first.LogName $first.ProviderName ([int]$first.Id)
                $level = if ($kb) { $kb.Level } else { 'INFO' }
                $cls = $level.ToLower()
                $evTitle = if ($kb) { $kb.Title } else { "$($first.ProviderName) #$($first.Id)" }
                $cause  = if ($kb) { [System.Net.WebUtility]::HtmlEncode($kb.Cause)  } else { '' }
                $action = if ($kb) { [System.Net.WebUtility]::HtmlEncode($kb.Action) } else { '' }
                $rawMsg = [System.Net.WebUtility]::HtmlEncode((($first.Message -replace "`r?`n", ' ').Trim()))
                if ($rawMsg.Length -gt 300) { $rawMsg = $rawMsg.Substring(0,297) + '...' }
                $htmlSections += "<div class='event $cls'>"
                $htmlSections += "<div class='ev-head'><span class='lvl'>$level</span><span class='ev-title'>$(([System.Net.WebUtility]::HtmlEncode($evTitle)))</span><span class='count'>x$($g.Count)</span></div>"
                $htmlSections += "<div class='meta'>$($L.FieldProvider): <code>$([System.Net.WebUtility]::HtmlEncode($first.ProviderName))</code> - $($L.FieldEventId): <code>$($first.Id)</code> - $($L.FieldLast): <code>$($first.TimeCreated.ToString('yyyy-MM-dd HH:mm'))</code></div>"
                if ($kb) {
                    $htmlSections += "<div class='kb'><div><strong>$($L.FieldCause):</strong> $cause</div><div><strong>$($L.FieldAction):</strong> $action</div></div>"
                } else {
                    $htmlSections += "<div class='kb'><div class='raw'>$rawMsg</div></div>"
                }
                $htmlSections += '</div>'
            }
            $htmlSections += '</div></section>'
        }

        $htmlLang = $L.HtmlLang
        $htmlTitle = $L.HtmlTitle
        $htmlEquipo = $L.HtmlEquipo
        $htmlRangeStr = ($L.HtmlRange -f $days)
        $htmlGenLbl = $L.HtmlGen
        $htmlPrintLbl = $L.HtmlPrint

        $html = @"
<!DOCTYPE html>
<html lang="$htmlLang"><head><meta charset="utf-8"/>
<title>$htmlTitle - $hostName</title>
<style>
  :root{--bg:#0f141b;--surf:#171d26;--surf2:#1e2631;--bord:#2c3444;--acc:#3b82f6;--text:#e5e7eb;--mut:#9ca3af;--ok:#22c55e;--warn:#eab308;--err:#ef4444}
  *{box-sizing:border-box}
  body{margin:0;background:var(--bg);color:var(--text);font-family:-apple-system,Segoe UI,Roboto,Helvetica,Arial,sans-serif;font-size:13px;line-height:1.5}
  .wrap{max-width:1000px;margin:0 auto;padding:24px}
  header{background:linear-gradient(135deg,var(--acc),#1d4ed8);color:white;padding:28px;border-radius:10px;margin-bottom:20px;box-shadow:0 6px 24px rgba(59,130,246,.25)}
  header h1{margin:0 0 4px;font-size:26px;letter-spacing:-.5px}
  header .meta{opacity:.8;font-size:12px;margin-top:8px}
  section{background:var(--surf);border:1px solid var(--bord);border-radius:10px;padding:18px 22px;margin-bottom:16px}
  section h2{margin:0 0 12px;font-size:15px;color:#60a5fa;text-transform:uppercase;letter-spacing:.5px;border-bottom:1px solid var(--bord);padding-bottom:8px}
  section h2 .count{color:var(--mut);font-size:12px;font-weight:400;margin-left:8px}
  .event{background:var(--surf2);border-radius:8px;padding:12px 14px;margin:8px 0;border-left:4px solid var(--bord)}
  .event.critical{border-left-color:var(--err)}
  .event.warn{border-left-color:var(--warn)}
  .event.info{border-left-color:#60a5fa}
  .ev-head{display:flex;align-items:center;gap:10px;margin-bottom:4px}
  .lvl{font-size:10px;font-weight:700;padding:2px 7px;border-radius:4px;background:var(--bord);color:white;text-transform:uppercase;letter-spacing:.5px}
  .event.critical .lvl{background:var(--err)}
  .event.warn .lvl{background:var(--warn);color:#1a1300}
  .event.info .lvl{background:#60a5fa;color:#0a1828}
  .ev-title{flex:1;font-weight:600;font-size:14px}
  .count{color:var(--mut);font-size:12px}
  .meta{color:var(--mut);font-size:11px;margin-bottom:6px}
  code{background:#0d121a;padding:1px 6px;border-radius:3px;color:#cbd5e1;font-size:11px}
  .kb{font-size:12.5px;line-height:1.55}
  .kb div{margin:3px 0}
  .kb strong{color:#60a5fa}
  .kb .raw{color:var(--mut);font-style:italic;font-size:12px}
  .muted{color:var(--mut);font-style:italic}
  .toolbar{position:sticky;top:10px;z-index:10;text-align:right;margin-bottom:12px}
  .btn{background:var(--acc);color:white;border:0;border-radius:6px;padding:9px 16px;font-size:12px;cursor:pointer;font-weight:500}
  .btn:hover{background:#60a5fa}
  @media print{
    body{background:white !important;color:black !important;font-size:11pt}
    header{background:white !important;color:black !important;border:2px solid #333;box-shadow:none}
    header h1{color:#1d4ed8 !important}
    section{background:white !important;border:1px solid #999 !important;color:black !important;page-break-inside:avoid}
    section h2{color:#1d4ed8 !important;border-color:#999}
    .event{background:#f7f8fa !important;color:black !important;break-inside:avoid}
    .event.critical{border-left:4px solid #c00 !important}
    .event.warn{border-left:4px solid #c90 !important}
    .meta,.muted{color:#555 !important}
    code{background:#eee !important;color:#333 !important}
    .kb strong{color:#1d4ed8 !important}
    .toolbar,.no-print{display:none !important}
  }
</style></head><body>
<div class="wrap">
<div class="toolbar no-print"><button class="btn" onclick="window.print()">$htmlPrintLbl</button></div>
<header>
  <h1>$htmlTitle</h1>
  <div>$htmlEquipo`: <strong>$hostName</strong> - $htmlRangeStr</div>
  <div class="meta">$htmlGenLbl`: $generated</div>
</header>
$htmlSections
</div></body></html>
"@

        Set-Content -LiteralPath $OutPath -Value $html -Encoding UTF8
        return $OutPath
    }

    while ($true) {
        Clear-Host
        Write-Host ''
        Write-Host $L.HeaderBar -ForegroundColor Cyan
        Write-Host $L.HeaderTitle -ForegroundColor Cyan
        Write-Host $L.HeaderBar -ForegroundColor Cyan
        Write-Host ''
        Write-Host "  $($L.ComputerLbl): $env:COMPUTERNAME"
        Write-Host ''
        Write-Host $L.Menu1 -ForegroundColor White
        Write-Host $L.Menu2 -ForegroundColor White
        Write-Host $L.Menu3 -ForegroundColor White
        Write-Host $L.Menu4 -ForegroundColor White
        Write-Host $L.Menu5 -ForegroundColor White
        Write-Host $L.Menu6 -ForegroundColor White
        Write-Host $L.Menu7 -ForegroundColor Yellow
        Write-Host $L.Menu8 -ForegroundColor White
        Write-Host $L.MenuQ -ForegroundColor DarkGray
        Write-Host ''
        $opt = Read-Host $L.OptPrompt
        $opt = $opt.Trim().ToUpper()

        switch ($opt) {
            '1' {
                $a = _Query-Events -LogName 'System'      -Levels @(1,2) -Hours 24 -MaxEvents 200
                $b = _Query-Events -LogName 'Application' -Levels @(1,2) -Hours 24 -MaxEvents 200
                _Render-Events @($a + $b) $L.Section1
                Read-Host $L.EnterBack
            }
            '2' {
                $e = _Query-Events -LogName 'System' -Ids @(41,6008,6006,1074) -Hours 168 -MaxEvents 200
                _Render-Events $e $L.Section2
                Read-Host $L.EnterBack
            }
            '3' {
                $e = _Query-Events -LogName 'System' -Ids @(1,17,18,19,46,47,7,51,52,55,153) -Hours 168 -MaxEvents 300
                _Render-Events $e $L.Section3
                Read-Host $L.EnterBack
            }
            '4' {
                $e = _Query-Events -LogName 'Application' -Ids @(1000,1001,1026) -Hours 168 -MaxEvents 300
                _Render-Events $e $L.Section4
                Read-Host $L.EnterBack
            }
            '5' {
                $e = _Query-Events -LogName 'System' -Ids @(219,7026) -Hours 168 -MaxEvents 200
                _Render-Events $e $L.Section5
                Read-Host $L.EnterBack
            }
            '6' {
                try {
                    $e = _Query-Events -LogName 'Security' -Ids @(4625,4720,4726,4724,4740) -Hours 168 -MaxEvents 300
                    _Render-Events $e $L.Section6
                } catch {
                    Write-Host ''
                    Write-Host ($L.SecDenied -f $_.Exception.Message) -ForegroundColor Red
                    Write-Host $L.SecRetry -ForegroundColor DarkGray
                }
                Read-Host $L.EnterBack
            }
            '7' {
                $stamp = Get-Date -Format 'yyyyMMdd-HHmmss'
                $desktop = [Environment]::GetFolderPath('Desktop')
                $out = Join-Path $desktop "atlas-events-$env:COMPUTERNAME-$stamp.html"
                Write-Host ''
                Write-Host $L.HtmlBuilding -ForegroundColor Yellow
                try {
                    $saved = _Build-HtmlReport -OutPath $out -Hours 168
                    Write-Host ($L.HtmlSaved -f $saved) -ForegroundColor Green
                    try { Start-Process $saved } catch {}
                } catch {
                    Write-Host ($L.HtmlError -f $_.Exception.Message) -ForegroundColor Red
                }
                Read-Host $L.EnterBack
            }
            '8' {
                Write-Host ''
                $idTxt = Read-Host $L.AskEventId
                $idN = 0
                if (-not [int]::TryParse($idTxt, [ref]$idN)) {
                    Write-Host $L.BadId -ForegroundColor Red
                    Read-Host $L.EnterPrompt
                    continue
                }
                $kb = _Kb-Lookup '*' '*' $idN
                Write-Host ''
                if ($kb) {
                    $color = _Level-Color $kb.Level
                    Write-Host ($L.KbLine1 -f (_Level-Icon $kb.Level), $idN, $kb.Title) -ForegroundColor $color
                    Write-Host ($L.KbSeverity -f $kb.Level) -ForegroundColor $color
                    Write-Host ($L.KbCause    -f $kb.Cause) -ForegroundColor Gray
                    Write-Host ($L.KbAction   -f $kb.Action) -ForegroundColor White
                } else {
                    Write-Host ($L.KbNotInDB -f $idN) -ForegroundColor Yellow
                    Write-Host ($L.KbGoogle  -f $idN) -ForegroundColor DarkGray
                }
                Write-Host ''
                Write-Host $L.KbRecent -ForegroundColor DarkGray
                $combined = @()
                foreach ($log in @('System','Application')) {
                    $r = _Query-Events -LogName $log -Ids @($idN) -Levels @(1,2,3,4) -Hours 720 -MaxEvents 20
                    $combined += $r
                }
                if ($combined.Count -eq 0) {
                    Write-Host $L.KbNoneRecent -ForegroundColor DarkGray
                } else {
                    $combined | Sort-Object TimeCreated -Descending | Select-Object -First 5 | ForEach-Object {
                        $msg = ($_.Message -replace "`r?`n", ' ').Trim()
                        if ($msg.Length -gt 140) { $msg = $msg.Substring(0,137) + '...' }
                        Write-Host ("    - $($_.TimeCreated.ToString('yyyy-MM-dd HH:mm')) [$($_.LogName)] $msg") -ForegroundColor DarkGray
                    }
                }
                Read-Host $L.EnterBack
            }
            'Q' { return }
            default { }
        }
    }
}


