$Host.UI.RawUI.BackgroundColor = "Black"
$Host.UI.RawUI.ForegroundColor = "White"
Clear-Host

function Escribir-Centrado {
    param([string]$texto, [string]$color)
    $anchoConsola = $Host.UI.RawUI.WindowSize.Width
    $espacios = " " * ([math]::Max(0, [math]::Floor(($anchoConsola - $texto.Length) / 2)))
    Write-Host ($espacios + $texto) -ForegroundColor $color
}

function Mostrar-Encabezado {
    Clear-Host
    Write-Host "`n"
    Escribir-Centrado " █████╗ ████████╗██╗      █████╗ ███████╗" "DarkYellow"
    Escribir-Centrado "██╔══██╗╚══██╔══╝██║     ██╔══██╗██╔════╝" "DarkYellow"
    Escribir-Centrado "███████║   ██║   ██║     ███████║███████╗" "DarkYellow"
    Escribir-Centrado "██╔══██║   ██║   ██║     ██╔══██║╚════██║" "DarkYellow"
    Escribir-Centrado "██║  ██║   ██║   ███████╗██║  ██║███████║" "DarkYellow"
    Escribir-Centrado "╚═╝  ╚═╝   ╚═╝   ╚══════╝╚═╝  ╚═╝╚══════╝" "DarkYellow"
    Escribir-Centrado $L.HeaderSub "DarkYellow"
    Escribir-Centrado $L.HdrBar "DarkGray"
    Write-Host "`n"
}

function Modificar-UsuarioActual {
    $userName = $env:USERNAME
    Escribir-Centrado ($L.CfgUser -f $userName) "Cyan"
    Write-Host ""
    Write-Host $L.CancelHint -ForegroundColor DarkGray
    Write-Host ""

    $newDisplayName = Read-Host $L.AskFullName
    if ($newDisplayName -eq "0") { return }

    Write-Host $L.AskPwdHint -ForegroundColor Yellow
    $securePassword = Read-Host $L.AskPwdLbl -AsSecureString

    try {
        if (![string]::IsNullOrWhiteSpace($newDisplayName)) {
            Set-LocalUser -Name $userName -FullName $newDisplayName
            Write-Host ("`n" + ($L.UpdName -f $newDisplayName)) -ForegroundColor Green
        }
        if ($securePassword.Length -gt 0) {
            Set-LocalUser -Name $userName -Password $securePassword
            Write-Host $L.UpdPwd -ForegroundColor Green
        } else {
            Write-Host ("`n" + $L.NoPwd) -ForegroundColor Green
        }
    } catch {
        Write-Host ("`n" + ($L.ErrFmt -f $_.Exception.Message)) -ForegroundColor Red
    }
    Write-Host $L.ReturnHint -ForegroundColor DarkGray
    Read-Host
}

function Crear-NuevoUsuario {
    Escribir-Centrado $L.CreateUser "Cyan"
    Write-Host ""
    Write-Host $L.CancelHint -ForegroundColor DarkGray
    Write-Host ""

    $newUser = Read-Host $L.AskNewLogon
    if ($newUser -eq "0" -or [string]::IsNullOrWhiteSpace($newUser)) { return }

    $newDisplayName = Read-Host $L.AskNewDisp
    if ($newDisplayName -eq "0") { return }

    Write-Host $L.AskPwdHint -ForegroundColor Yellow
    $securePassword = Read-Host $L.AskPwdLbl -AsSecureString

    $esAdmin = Read-Host $L.AskAdmin
    if ($esAdmin -eq "0") { return }

    try {
        if ($securePassword.Length -gt 0) {
            New-LocalUser -Name $newUser -FullName $newDisplayName -Password $securePassword -PasswordNeverExpires $true | Out-Null
        } else {
            New-LocalUser -Name $newUser -FullName $newDisplayName -NoPassword | Out-Null
        }
        Write-Host ("`n" + ($L.UserCreated -f $newUser)) -ForegroundColor Green

        if ($esAdmin -match "^[sSyY]") {
            $AdminGroup = Get-LocalGroup | Where-Object SID -eq "S-1-5-32-544"
            Add-LocalGroupMember -Group $AdminGroup -Member $newUser
            Write-Host $L.GrantedAdm -ForegroundColor Green
        } else {
            $UsersGroup = Get-LocalGroup | Where-Object SID -eq "S-1-5-32-545"
            Add-LocalGroupMember -Group $UsersGroup -Member $newUser
            Write-Host $L.GrantedStd -ForegroundColor Green
        }
    } catch {
        Write-Host ("`n" + ($L.ErrFmt -f $_.Exception.Message)) -ForegroundColor Red
    }
    Write-Host $L.ReturnHint -ForegroundColor DarkGray
    Read-Host
}

function Renombrar-Equipo {
    Escribir-Centrado $L.RenameTitle "Cyan"
    Write-Host ""
    $actual = $env:COMPUTERNAME
    Write-Host ($L.CurrName -f $actual) -ForegroundColor White
    Write-Host ""
    $nuevo = Read-Host $L.AskNewName
    if ($nuevo -eq "0" -or [string]::IsNullOrWhiteSpace($nuevo)) { return }
    if ($nuevo -notmatch '^[A-Za-z0-9\-]{1,15}$') {
        Write-Host $L.BadName -ForegroundColor Red
        Read-Host $L.EnterBack
        return
    }
    try {
        Rename-Computer -NewName $nuevo -Force -ErrorAction Stop
        Write-Host ("`n" + ($L.NameOk -f $nuevo)) -ForegroundColor Green
        Write-Host $L.NeedReboot -ForegroundColor Yellow
    } catch {
        Write-Host ("`n" + ($L.ErrFmt -f $_.Exception.Message)) -ForegroundColor Red
    }
    Read-Host $L.EnterBack
}

function _Esc-Html {
    param([string]$Text)
    if ($null -eq $Text) { return '' }
    return ([System.Net.WebUtility]::HtmlEncode($Text))
}

function _Row {
    param([string]$Label, [string]$Value)
    $v = _Esc-Html $Value
    $l = _Esc-Html $Label
    return "<tr><th>$l</th><td>$v</td></tr>"
}

function _Brighten-Hex {
    param([string]$Hex, [int]$Delta = 35)
    if (-not $Hex) { return $Hex }
    $h = $Hex.TrimStart('#')
    if ($h.Length -ne 6) { return $Hex }
    try {
        $r = [Math]::Min(255, [Convert]::ToInt32($h.Substring(0,2),16) + $Delta)
        $g = [Math]::Min(255, [Convert]::ToInt32($h.Substring(2,2),16) + $Delta)
        $b = [Math]::Min(255, [Convert]::ToInt32($h.Substring(4,2),16) + $Delta)
        return ('#{0:X2}{1:X2}{2:X2}' -f $r, $g, $b)
    } catch { return $Hex }
}

function _Darken-Hex {
    param([string]$Hex, [int]$Delta = 35)
    if (-not $Hex) { return $Hex }
    $h = $Hex.TrimStart('#')
    if ($h.Length -ne 6) { return $Hex }
    try {
        $r = [Math]::Max(0, [Convert]::ToInt32($h.Substring(0,2),16) - $Delta)
        $g = [Math]::Max(0, [Convert]::ToInt32($h.Substring(2,2),16) - $Delta)
        $b = [Math]::Max(0, [Convert]::ToInt32($h.Substring(4,2),16) - $Delta)
        return ('#{0:X2}{1:X2}{2:X2}' -f $r, $g, $b)
    } catch { return $Hex }
}

function _Load-AtlasBrand {
    $defaults = @{
        Name          = 'Atlas PC Support'
        Accent        = '#FF5500'
        Secondary     = '#002147'
    }
    $candidates = @()
    if ($env:USERPROFILE)    { $candidates += (Join-Path $env:USERPROFILE 'branding.json') }
    if ($env:LOCALAPPDATA)   { $candidates += (Join-Path $env:LOCALAPPDATA 'AtlasPC\branding.json') }
    if ($env:APPDATA)        { $candidates += (Join-Path $env:APPDATA 'AtlasPC\branding.json') }
    $candidates += (Join-Path (Get-Location) 'branding.json')
    foreach ($p in $candidates) {
        if ($p -and (Test-Path -LiteralPath $p)) {
            try {
                $obj = Get-Content -LiteralPath $p -Raw -Encoding UTF8 | ConvertFrom-Json -ErrorAction Stop
                if ($obj) {
                    if ($obj.brand -and $obj.brand.shortName) { $defaults.Name = [string]$obj.brand.shortName }
                    elseif ($obj.brand -and $obj.brand.name)  { $defaults.Name = [string]$obj.brand.name }
                    if ($obj.theme -and $obj.theme.accentColor)    { $defaults.Accent    = [string]$obj.theme.accentColor }
                    if ($obj.theme -and $obj.theme.secondaryColor) { $defaults.Secondary = [string]$obj.theme.secondaryColor }
                    break
                }
            } catch {}
        }
    }
    $defaults.AccentHover   = _Brighten-Hex $defaults.Accent 30
    $defaults.SecondaryDark = _Darken-Hex   $defaults.Secondary 15
    return $defaults
}

function Generar-ChecklistEntrega {
    Escribir-Centrado $L.BuildingHtml "Cyan"
    Write-Host ""
    Write-Host $L.Gathering -ForegroundColor Yellow

    $brand         = _Load-AtlasBrand
    $brandName     = $brand.Name
    $accent        = $brand.Accent
    $accentHover   = $brand.AccentHover
    $secondary     = $brand.Secondary
    $secondaryDark = $brand.SecondaryDark

    $now = Get-Date
    $generated = $now.ToString('yyyy-MM-dd HH:mm:ss')
    $hostName  = $env:COMPUTERNAME
    $userName  = $env:USERNAME

    $equipoRows = @()
    try {
        $cs   = Get-CimInstance Win32_ComputerSystem -ErrorAction Stop
        $bios = Get-CimInstance Win32_BIOS -ErrorAction Stop
        $os   = Get-CimInstance Win32_OperatingSystem -ErrorAction Stop
        $equipoRows += _Row $L.RowName  $hostName
        $equipoRows += _Row $L.RowMaker ($cs.Manufacturer)
        $equipoRows += _Row $L.RowModel ($cs.Model)
        $equipoRows += _Row $L.RowBios  ($bios.SerialNumber)
        $equipoRows += _Row $L.RowOs    ($os.Caption)
        $equipoRows += _Row $L.RowVer   ($os.Version)
        $equipoRows += _Row $L.RowBuild ($os.BuildNumber)
        $equipoRows += _Row $L.RowArch  ($os.OSArchitecture)
        $equipoRows += _Row $L.RowRam   (("{0:N1} GB" -f ($cs.TotalPhysicalMemory/1GB)))
    } catch {
        $equipoRows += "<tr><td colspan='2' class='err'>$($L.ErrEquipo -f (_Esc-Html $_.Exception.Message))</td></tr>"
    }

    $activacion = ''
    try {
        $licInfo = cscript.exe //Nologo "C:\Windows\System32\slmgr.vbs" /xpr 2>&1
        $activacion = _Esc-Html (($licInfo -join "`n").Trim())
    } catch {
        $activacion = "<span class='err'>$($L.ErrAct)</span>"
    }

    $usuariosHtml = ''
    $adminsHtml   = ''
    try {
        $ul = Get-LocalUser -ErrorAction Stop | Where-Object { $_.Enabled }
        $usuariosHtml = ($ul | ForEach-Object {
            "<li><strong>$(_Esc-Html $_.Name)</strong> <span class='muted'>$(_Esc-Html $_.FullName)</span></li>"
        }) -join ''
        $adminGroup = Get-LocalGroup | Where-Object SID -eq 'S-1-5-32-544'
        if ($adminGroup) {
            $members = Get-LocalGroupMember -Group $adminGroup -ErrorAction SilentlyContinue
            if ($members) {
                $adminsHtml = ($members | ForEach-Object { "<li>$(_Esc-Html $_.Name)</li>" }) -join ''
            }
        }
    } catch {
        $usuariosHtml = "<li class='err'>$($L.ErrUsers -f (_Esc-Html $_.Exception.Message))</li>"
    }

    $bitlockerRows = @()
    try {
        $vols = Get-BitLockerVolume -ErrorAction Stop
        foreach ($v in $vols) {
            $status = "$(_Esc-Html $v.VolumeStatus) - Protection: $(_Esc-Html $v.ProtectionStatus) - Enc: $($v.EncryptionPercentage)%"
            $rk = $v.KeyProtector | Where-Object { $_.KeyProtectorType -eq 'RecoveryPassword' }
            $keys = ''
            foreach ($r in $rk) {
                $keys += "<div class='key-block'><div class='muted small'>Key ID: $(_Esc-Html $r.KeyProtectorId)</div><code>$(_Esc-Html $r.RecoveryPassword)</code></div>"
            }
            $bitlockerRows += "<tr><th>$(_Esc-Html $v.MountPoint)</th><td>$status$keys</td></tr>"
        }
    } catch {
        $bitlockerRows += "<tr><td colspan='2' class='err'>$($L.BLNotAvail -f (_Esc-Html $_.Exception.Message))</td></tr>"
    }

    $discosHtml = ''
    try {
        $discosHtml += "<table class='mini'><thead><tr><th>$($L.ColModel)</th><th>$($L.ColSerial)</th><th>$($L.ColSize)</th><th>$($L.ColHealth)</th><th>$($L.ColType)</th></tr></thead><tbody>"
        Get-PhysicalDisk -ErrorAction Stop | ForEach-Object {
            $health = _Esc-Html "$($_.HealthStatus)"
            $cls = if ($_.HealthStatus -eq 'Healthy') { 'ok' } elseif ($_.HealthStatus -eq 'Warning') { 'warn' } else { 'err' }
            $discosHtml += "<tr><td>$(_Esc-Html $_.FriendlyName)</td><td><code>$(_Esc-Html $_.SerialNumber)</code></td><td>$("{0:N0} GB" -f ($_.Size/1GB))</td><td class='$cls'>$health</td><td>$(_Esc-Html $_.MediaType)</td></tr>"
        }
        $discosHtml += '</tbody></table>'
    } catch {
        $discosHtml = "<p class='err'>$($L.ErrDisks -f (_Esc-Html $_.Exception.Message))</p>"
    }

    $volumenesHtml = ''
    try {
        $volumenesHtml += "<table class='mini'><thead><tr><th>$($L.ColDrive)</th><th>$($L.ColLabel)</th><th>$($L.ColFree)</th><th>$($L.ColTotal)</th><th>$($L.ColFs)</th></tr></thead><tbody>"
        Get-Volume -ErrorAction Stop | Where-Object { $_.DriveLetter } | Sort-Object DriveLetter | ForEach-Object {
            $pctFree = if ($_.Size -gt 0) { [int](($_.SizeRemaining/$_.Size)*100) } else { 0 }
            $cls = if ($pctFree -lt 10) { 'err' } elseif ($pctFree -lt 20) { 'warn' } else { 'ok' }
            $volumenesHtml += "<tr><td><strong>$($_.DriveLetter):</strong></td><td>$(_Esc-Html $_.FileSystemLabel)</td><td class='$cls'>$("{0:N1} GB" -f ($_.SizeRemaining/1GB)) ($pctFree%)</td><td>$("{0:N1} GB" -f ($_.Size/1GB))</td><td>$(_Esc-Html $_.FileSystem)</td></tr>"
        }
        $volumenesHtml += '</tbody></table>'
    } catch {
        $volumenesHtml = "<p class='err'>$($L.ErrVols -f (_Esc-Html $_.Exception.Message))</p>"
    }

    $hotfixHtml = ''
    try {
        $hotfixHtml += "<table class='mini'><thead><tr><th>$($L.ColHotfix)</th><th>$($L.ColInstalled)</th><th>$($L.ColTypeKB)</th></tr></thead><tbody>"
        Get-HotFix -ErrorAction Stop | Sort-Object InstalledOn -Descending | Select-Object -First 10 | ForEach-Object {
            $installedDate = if ($_.InstalledOn) { $_.InstalledOn.ToString('yyyy-MM-dd') } else { '' }
            $hotfixHtml += "<tr><td><code>$(_Esc-Html $_.HotFixID)</code></td><td>$(_Esc-Html $installedDate)</td><td>$(_Esc-Html $_.Description)</td></tr>"
        }
        $hotfixHtml += '</tbody></table>'
    } catch {
        $hotfixHtml = "<p class='err'>$($L.ErrHotfix -f (_Esc-Html $_.Exception.Message))</p>"
    }

    $redHtml = ''
    try {
        $ips = Get-NetIPAddress -AddressFamily IPv4 -ErrorAction Stop | Where-Object { $_.IPAddress -notlike '169.*' -and $_.IPAddress -notlike '127.*' }
        if ($ips) {
            $redHtml = '<ul>'
            foreach ($ip in $ips) {
                $redHtml += "<li><strong>$(_Esc-Html $ip.InterfaceAlias):</strong> <code>$(_Esc-Html $ip.IPAddress)/$($ip.PrefixLength)</code></li>"
            }
            $redHtml += '</ul>'
        } else {
            $redHtml = "<p class='muted'>$($L.NoNet)</p>"
        }
    } catch {}

    $defenderRows = @()
    try {
        $mp = Get-MpComputerStatus -ErrorAction Stop
        $defenderRows += _Row $L.RowAvOn  ([string]$mp.AntivirusEnabled)
        $defenderRows += _Row $L.RowAvRT  ([string]$mp.RealTimeProtectionEnabled)
        $defenderRows += _Row $L.RowAvSig ([string]$mp.AntivirusSignatureLastUpdated)
    } catch {}

    $checklistItems = $L.ChkItems
    $checklistHtml = ''
    $i = 0
    foreach ($item in $checklistItems) {
        $i++
        $checklistHtml += "<label class='check'><input type='checkbox' id='c$i'><span>$(_Esc-Html $item)</span></label>"
    }

    $equipoTable    = $equipoRows    -join ''
    $bitlockerTable = $bitlockerRows -join ''
    $defenderTable  = $defenderRows  -join ''

    $titleStr = $L.HtmlTitle -f $brandName, $hostName
    $subtitleStr = $L.HtmlSubTitle -f $hostName
    $metaStr = $L.HtmlMeta -f $generated, $userName
    $htmlLang = $L.HtmlLang
    $titleEsc = _Esc-Html $titleStr

    $html = @"
<!DOCTYPE html>
<html lang="$htmlLang">
<head>
<meta charset="utf-8"/>
<title>$titleEsc</title>
<meta name="viewport" content="width=device-width,initial-scale=1"/>
<style>
  :root {
    --bg: #0f141b;
    --surface: #171d26;
    --surface-alt: #1e2631;
    --border: #2c3444;
    --accent: $accent;
    --accent-hover: $accentHover;
    --secondary: $secondary;
    --secondary-dark: $secondaryDark;
    --text: #e5e7eb;
    --muted: #9ca3af;
    --ok: #22c55e;
    --warn: #eab308;
    --err: #ef4444;
    --radius: 10px;
  }
  * { box-sizing: border-box; }
  body { margin: 0; background: var(--bg); color: var(--text); font-family: -apple-system, Segoe UI, Roboto, Helvetica, Arial, sans-serif; font-size: 14px; line-height: 1.5; }
  .wrap { max-width: 960px; margin: 0 auto; padding: 24px; }
  header { background: linear-gradient(135deg, var(--secondary) 0%, var(--accent) 100%); color: white; padding: 32px 24px; border-radius: var(--radius); margin-bottom: 24px; box-shadow: 0 6px 24px rgba(0,0,0,0.35); }
  header h1 { margin: 0 0 4px 0; font-size: 28px; letter-spacing: -0.5px; }
  header .subtitle { opacity: .85; font-size: 14px; }
  header .meta { margin-top: 12px; font-size: 12px; opacity: .75; }
  section { background: var(--surface); border: 1px solid var(--border); border-radius: var(--radius); padding: 20px 24px; margin-bottom: 16px; }
  section h2 { margin: 0 0 12px 0; font-size: 16px; color: var(--accent-hover); letter-spacing: .5px; text-transform: uppercase; border-bottom: 1px solid var(--border); padding-bottom: 8px; }
  table { border-collapse: collapse; width: 100%; font-size: 13px; }
  table th, table td { text-align: left; padding: 6px 10px; border-bottom: 1px solid var(--border); }
  table th { color: var(--muted); font-weight: 500; white-space: nowrap; width: 30%; }
  table.mini th, table.mini td { padding: 5px 8px; font-size: 12px; }
  table.mini thead th { background: var(--surface-alt); color: var(--accent-hover); font-weight: 600; text-transform: uppercase; font-size: 11px; letter-spacing: .5px; border-bottom: 2px solid var(--border); }
  code { background: var(--surface-alt); padding: 2px 6px; border-radius: 4px; font-size: 12px; color: #cbd5e1; }
  pre { background: var(--surface-alt); padding: 10px; border-radius: 6px; white-space: pre-wrap; font-size: 12px; }
  ul { margin: 4px 0; padding-left: 20px; }
  li { margin: 2px 0; }
  .muted { color: var(--muted); }
  .small { font-size: 11px; }
  .ok { color: var(--ok); font-weight: 500; }
  .warn { color: var(--warn); font-weight: 500; }
  .err { color: var(--err); font-weight: 500; }
  .key-block { margin-top: 4px; background: var(--surface-alt); padding: 8px; border-radius: 4px; border-left: 3px solid var(--warn); }
  .key-block code { background: transparent; color: var(--warn); font-size: 13px; font-weight: 600; letter-spacing: .5px; }
  .check { display: flex; align-items: flex-start; padding: 10px 12px; margin: 4px 0; background: var(--surface-alt); border-radius: 6px; cursor: pointer; transition: background .15s; border: 1px solid transparent; }
  .check:hover { background: #252d3a; border-color: var(--border); }
  .check input[type=checkbox] { flex-shrink: 0; width: 18px; height: 18px; margin-right: 10px; accent-color: var(--accent); cursor: pointer; }
  .check input[type=checkbox]:checked + span { color: var(--ok); text-decoration: line-through; opacity: .7; }
  .check span { flex: 1; }
  .signature-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 24px; margin-top: 16px; }
  .signature-box { padding: 30px 10px 10px; border-top: 2px solid var(--border); text-align: center; color: var(--muted); font-size: 12px; min-height: 80px; }
  .toolbar { position: sticky; top: 10px; z-index: 10; display: flex; gap: 10px; justify-content: flex-end; margin-bottom: 12px; }
  .btn { background: var(--accent); color: white; border: 0; border-radius: 6px; padding: 10px 18px; font-size: 13px; cursor: pointer; font-weight: 500; transition: background .15s; }
  .btn:hover { background: var(--accent-hover); }
  .btn.secondary { background: var(--surface-alt); color: var(--text); border: 1px solid var(--border); }
  footer { margin-top: 32px; padding: 16px; text-align: center; color: var(--muted); font-size: 11px; }
  @media print {
    body { background: white !important; color: black !important; font-size: 11pt; }
    .wrap { max-width: 100%; padding: 0; }
    header { background: white !important; color: black !important; border: 2px solid var(--secondary); box-shadow: none; page-break-after: avoid; }
    header h1, header .subtitle { color: var(--secondary) !important; }
    section { background: white !important; border: 1px solid #999 !important; color: black !important; page-break-inside: avoid; }
    section h2 { color: var(--secondary) !important; border-color: #999; }
    table th, table td { border-bottom: 1px solid #ccc !important; color: black !important; }
    table.mini thead th { background: #eee !important; color: var(--secondary) !important; }
    code, pre { background: #f5f5f5 !important; color: black !important; }
    .check { background: white !important; border: 1px solid #999 !important; break-inside: avoid; }
    .key-block { background: #fff8e6 !important; color: #666 !important; }
    .key-block code { color: #7a5a00 !important; }
    .muted { color: #666 !important; }
    .toolbar, .no-print { display: none !important; }
    .signature-box { border-top: 2px solid black; color: black; }
    a { color: black; text-decoration: none; }
  }
</style>
</head>
<body>
<div class="wrap">
<div class="toolbar no-print">
  <button class="btn" onclick="window.print()">$($L.BtnPrint)</button>
  <button class="btn secondary" onclick="toggleAll()">$($L.BtnCheckAll)</button>
</div>
<header>
  <h1>$(_Esc-Html $brandName)</h1>
  <div class="subtitle">$subtitleStr</div>
  <div class="meta">$metaStr</div>
</header>
<section><h2>$($L.HtmlSecEquipo)</h2><table>$equipoTable</table></section>
<section><h2>$($L.HtmlSecAct)</h2><pre>$activacion</pre></section>
<section>
  <h2>$($L.HtmlSecUsers)</h2>
  <div style="display:grid;grid-template-columns:1fr 1fr;gap:20px">
    <div><h3 style="margin:0 0 6px;font-size:13px;color:var(--muted);text-transform:uppercase">$($L.HtmlULocal)</h3><ul>$usuariosHtml</ul></div>
    <div><h3 style="margin:0 0 6px;font-size:13px;color:var(--muted);text-transform:uppercase">$($L.HtmlUAdmin)</h3><ul>$adminsHtml</ul></div>
  </div>
</section>
<section><h2>$($L.HtmlSecBL)</h2><table>$bitlockerTable</table><p class="small muted">$($L.HtmlBLNote)</p></section>
<section><h2>$($L.HtmlSecDisks)</h2>$discosHtml<h3 style="margin:16px 0 6px;font-size:13px;color:var(--muted);text-transform:uppercase">$($L.HtmlVolumes)</h3>$volumenesHtml</section>
<section><h2>$($L.HtmlSecNet)</h2>$redHtml</section>
<section><h2>$($L.HtmlSecDef)</h2><table>$defenderTable</table></section>
<section><h2>$($L.HtmlSecHF)</h2>$hotfixHtml</section>
<section><h2>$($L.HtmlSecChk)</h2>$checklistHtml</section>
<section>
  <h2>$($L.HtmlSecSig)</h2>
  <div class="signature-grid">
    <div class="signature-box">$($L.HtmlSigTech)<br/><span class="small">$(_Esc-Html $userName)</span></div>
    <div class="signature-box">$($L.HtmlSigCust)<br/><span class="small">_______________________</span></div>
  </div>
  <p class="small muted" style="margin-top:12px">$($L.HtmlDateLine)</p>
</section>
<footer>$($L.HtmlFooter)</footer>
</div>
<script>
function toggleAll(){
  var b=document.querySelectorAll(".check input[type=checkbox]");
  var all=true; for(var i=0;i<b.length;i++){ if(!b[i].checked){all=false;break;} }
  for(var j=0;j<b.length;j++){ b[j].checked=!all; }
}
</script>
</body>
</html>
"@

    try {
        $stamp = Get-Date -Format 'yyyyMMdd-HHmmss'
        $desktop = [Environment]::GetFolderPath('Desktop')
        $out = Join-Path $desktop "atlas-handover-$hostName-$stamp.html"
        Set-Content -Path $out -Value $html -Encoding UTF8
        Write-Host ""
        Write-Host $L.HtmlSavedOk -ForegroundColor Green
        Write-Host "   $out" -ForegroundColor White
        Write-Host ""
        Write-Host $L.OpeningBrw -ForegroundColor DarkGray
        try { Start-Process $out } catch {
            try { Start-Process 'explorer.exe' -ArgumentList $out } catch {}
        }
    } catch {
        Write-Host ""
        Write-Host ($L.CouldNotSave -f $_.Exception.Message) -ForegroundColor Red
    }
    Read-Host $L.EnterBack
}

while ($true) {
    Mostrar-Encabezado

    $l1 = $L.MainOpt1 -f $env:USERNAME
    $l2 = $L.MainOpt2
    $l3 = $L.MainOpt3
    $l4 = $L.MainOpt4
    $l5 = $L.MainOpt5

    $maxLen = [math]::Max($l1.Length, [math]::Max($l2.Length, [math]::Max($l3.Length, [math]::Max($l4.Length, $l5.Length))))

    Escribir-Centrado $l1.PadRight($maxLen) "White"
    Escribir-Centrado $l2.PadRight($maxLen) "White"
    Escribir-Centrado $l3.PadRight($maxLen) "White"
    Escribir-Centrado $l4.PadRight($maxLen) "Green"
    Escribir-Centrado $l5.PadRight($maxLen) "DarkGray"
    Write-Host ""

    $textoPrompt = $L.MainPrompt
    $ancho = $Host.UI.RawUI.WindowSize.Width
    $espacios = " " * ([math]::Max(0, [math]::Floor(($ancho - $textoPrompt.Length - 2) / 2)))
    Write-Host $espacios -NoNewline
    $opcion = Read-Host $textoPrompt

    switch ($opcion) {
        '1' { Mostrar-Encabezado; Modificar-UsuarioActual }
        '2' { Mostrar-Encabezado; Crear-NuevoUsuario }
        '3' { Mostrar-Encabezado; Renombrar-Equipo }
        '4' { Mostrar-Encabezado; Generar-ChecklistEntrega }
        '5' { Clear-Host; exit }
        default { Escribir-Centrado $L.BadOption "Red"; Start-Sleep -s 1 }
    }
}
}


# ---- tools\Invoke-ExtraerLicencias.ps1 ----
# ============================================================
# Invoke-ExtraerLicencias
# Migrado de: EXTAER+LICENCIAS.ps1
# Atlas PC Support — v1.0
# ============================================================

function Invoke-ExtraerLicencias {
    [CmdletBinding()]
    param()
# ============================================================================
# Script: Extractor de Licencias ATLAS y Auditor (Estable)
# Arquitectura: PowerShell (Compatible v2.0+)
# Objetivo: Extracción de BIOS, OS Actual y Detección de Originalidad
# ============================================================================

<#
.SYNOPSIS
    Fuerza la elevación de privilegios de Administrador de manera estable.
#>
$ErrorActionPreference = "Stop"

# (auto-elevación gestionada por Atlas Launcher)

<#
.SYNOPSIS
    Funciones de interfaz de usuario para alineación y formato estandarizado.
#>
$Host.UI.RawUI.WindowTitle = "ATLAS PC SUPPORT - Extract Product Keys"

function Write-Centered {
    param(
        [string]$Text,
        [ConsoleColor]$Color = 'White'
    )
    $windowWidth = $Host.UI.RawUI.WindowSize.Width
    if ($windowWidth -gt $Text.Length) {
        $padding = [math]::Max(0, [math]::Floor(($windowWidth - $Text.Length) / 2))
        $spaces = " " * $padding
        Write-Host "$spaces$Text" -ForegroundColor $Color
    } else {
        Write-Host $Text -ForegroundColor $Color
    }
}

function Show-Header {
    Clear-Host
    Write-Host "`n"
    Write-Centered -Text "========================================" -Color Yellow
    Write-Centered -Text "ATLAS PC SUPPORT" -Color Yellow
    Write-Centered -Text "========================================" -Color Yellow
    Write-Host "`n"
}

<#
.SYNOPSIS
    OPCIÓN 1: Extracción de clave inyectada en placa base (BIOS/UEFI)
#>
function Get-BiosKey {
    Show-Header
    Write-Centered -Text "--- BIOS/UEFI FACTORY KEY EXTRACTION ---" -Color Cyan
    Write-Host "`n"
    
    try {
        $wmiQuery = Get-WmiObject -Query 'select * from SoftwareLicensingService' -ErrorAction Stop
        $biosKey = $wmiQuery.OA3xOriginalProductKey
        $biosDesc = $wmiQuery.OA3xOriginalProductKeyDescription

        if ([string]::IsNullOrWhiteSpace($biosKey)) {
            Write-Centered -Text "[!] No OEM key found in BIOS/UEFI." -Color Red
            Write-Centered -Text "This computer did not come with Windows pre-installed from factory." -Color Gray
        } else {
            Write-Centered -Text "[+] BIOS KEY FOUND:" -Color Green
            if (-not [string]::IsNullOrWhiteSpace($biosDesc)) {
                Write-Centered -Text "Factory Edition: $biosDesc" -Color Cyan
            }
            Write-Centered -Text $biosKey -Color Yellow
            $biosKey | clip
            Write-Host "`n"
            Write-Centered -Text "(Copied to clipboard securely)" -Color Gray
        }
    } catch {
        Write-Centered -Text "[X] Error querying ACPI table: $($_.Exception.Message)" -Color Red
    }
    
    Write-Host "`n"
    Write-Centered -Text "Press ENTER to return to menu..." -Color White
    $null = Read-Host
}

<#
.SYNOPSIS
    OPTION 2: Extract currently installed key (Advanced Registry Base24)
#>
function Get-CurrentKey {
    Show-Header
    Write-Centered -Text "--- CURRENT KEY EXTRACTION (INSTALLED OS) ---" -Color Cyan
    Write-Host "`n"
    
    try {
        # 1. Mostrar la Clave de la BIOS como referencia cruzada
        $sls = Get-WmiObject -Query 'select * from SoftwareLicensingService' -ErrorAction SilentlyContinue
        $biosRefKey = $sls.OA3xOriginalProductKey
        $biosRefDesc = $sls.OA3xOriginalProductKeyDescription
        
        if (-not [string]::IsNullOrWhiteSpace($biosRefKey)) {
            Write-Centered -Text "[+] FACTORY KEY (BIOS) FOR REFERENCE:" -Color DarkCyan
            if (-not [string]::IsNullOrWhiteSpace($biosRefDesc)) {
                Write-Centered -Text "Factory Edition: $biosRefDesc" -Color Cyan
            }
            Write-Centered -Text $biosRefKey -Color Gray
            Write-Host "`n----------------------------------------`n" -ForegroundColor DarkGray
        }

        # 2. Búsqueda en el Registro para el OS Actual
        $regPath = "HKLM:\SOFTWARE\Microsoft\Windows NT\CurrentVersion\SoftwareProtectionPlatform"
        $backupKey = (Get-ItemProperty -Path $regPath -Name BackupProductKeyDefault -ErrorAction SilentlyContinue).BackupProductKeyDefault

        $hexPath = "HKLM:\SOFTWARE\Microsoft\Windows NT\CurrentVersion"
        
        # Corrección: Leer edición real desde WMI para evitar el falso "Windows 10" del registro de Win 11
        $currentEdition = (Get-WmiObject -Class Win32_OperatingSystem -ErrorAction SilentlyContinue).Caption -replace '^Microsoft\s+', ''
        
        $digitalProductId = (Get-ItemProperty -Path $hexPath -Name DigitalProductId -ErrorAction SilentlyContinue).DigitalProductId
        
        $decodedKey = $null
        $isKMSOrDigital = $false

        if ($digitalProductId -ne $null -and $digitalProductId.Length -ge 67) {
            $isWin8Or10 = [math]::Floor($digitalProductId[66] / 6) -band 1
            $digitalProductId[66] = ($digitalProductId[66] -band 0xF7) -bOr (($isWin8Or10 -band 2) * 4)
            $chars = "BCDFGHJKMPQRTVWXY2346789"
            $decodedKeyStr = ""
            for ($i = 24; $i -ge 0; $i--) {
                $current = 0
                for ($j = 14; $j -ge 0; $j--) {
                    $current = $current * 256 + $digitalProductId[$j + 52]
                    $digitalProductId[$j + 52] = [math]::Floor($current / 24)
                    $current = $current % 24
                }
                $decodedKeyStr = $chars[$current] + $decodedKeyStr
                $last = $current
            }
            if ($isWin8Or10 -eq 1) {
                $decodedKeyStr = $decodedKeyStr.Substring(1, $last) + "N" + $decodedKeyStr.Substring($last + 1)
            }
            $decodedKey = $decodedKeyStr.Insert(5, "-").Insert(11, "-").Insert(17, "-").Insert(23, "-")
            
            if ($decodedKey -eq "BBBBB-BBBBB-BBBBB-BBBBB-BBBBB") {
                $decodedKey = $null
                $isKMSOrDigital = $true
            }
        }

        $activeWmi = Get-WmiObject -Query "SELECT PartialProductKey, Description FROM SoftwareLicensingProduct WHERE LicenseStatus = 1 AND PartialProductKey IS NOT NULL" -ErrorAction SilentlyContinue

        if ($activeWmi) {
            Write-Centered -Text "[+] ACTIVATION ENGINE EVIDENCE (ONLY REAL DATA):" -Color Cyan
            foreach ($lic in $activeWmi) {
                Write-Centered -Text "Partial: ******-******-******-******-$($lic.PartialProductKey)" -Color White
            }
            Write-Host ""
        }

        if (-not [string]::IsNullOrWhiteSpace($currentEdition)) {
            Write-Centered -Text "Installed Edition: $currentEdition" -Color Cyan
            Write-Host ""
        }

        if ($isKMSOrDigital) {
            Write-Centered -Text "[!] TECHNICAL ALERT: KEY HIDDEN BY DESIGN" -Color Yellow
            Write-Centered -Text "Windows has removed the key from registry for corporate security." -Color Gray
            Write-Centered -Text "The license is MAK or Digital and does not reside physically on disk." -Color Gray
        } elseif (-not [string]::IsNullOrWhiteSpace($decodedKey)) {
            Write-Centered -Text "[+] DECODED KEY FROM REGISTRY:" -Color Green
            Write-Centered -Text $decodedKey -Color Yellow
            $decodedKey | clip
        }

        if (-not [string]::IsNullOrWhiteSpace($backupKey)) {
            Write-Host ""
            Write-Centered -Text "[+] BACKUP KEY FOUND:" -Color DarkCyan
            Write-Centered -Text $backupKey -Color Gray
        }

    } catch {
        Write-Centered -Text "[X] Critical decoding error." -Color Red
    }
    
    Write-Host "`n"
    Write-Centered -Text "Press ENTER to return to menu..." -Color White
    $null = Read-Host
}

<#
.SYNOPSIS
    OPTION 3: Native audit via SLMGR
#>
function Invoke-NativeAudit {
    Show-Header
    Write-Centered -Text "--- NATIVE SYSTEM AUDIT (SLMGR) ---" -Color Cyan
    Write-Host "`n"
    Write-Centered -Text "Starting official Microsoft tool..." -Color Gray
    
    # Ejecuta el comando nativo de Windows para mostrar información de la licencia
    cscript //nologo C:\Windows\System32\slmgr.vbs /dli
    
    Write-Host "`n"
    Write-Centered -Text "--- AUTHENTICITY ANALYSIS ---" -Color Cyan
    try {
        $wmi = Get-WmiObject -Query "SELECT Description, LicenseStatus FROM SoftwareLicensingProduct WHERE LicenseStatus = 1 AND PartialProductKey IS NOT NULL"
        foreach ($item in $wmi) {
            if ($item.Description -match "VOLUME_KMSCLIENT") {
                Write-Centered -Text "[!] DETECTED: KMS CHANNEL (Possible emulator activation)" -Color Yellow
            } elseif ($item.Description -match "VOLUME_MAK|RETAIL|OEM") {
                Write-Centered -Text "[+] DETECTED: ORIGINAL CHANNEL ($($item.Description -replace '.*, ', ''))" -Color Green
            }
        }
    } catch {}

    Write-Host "`n"
    Write-Centered -Text "Press ENTER to return to menu..." -Color White
    $null = Read-Host
}

<#
.SYNOPSIS
    OPTION 4: System Information (Includes BIOS Key, Current Key and Visual Audit)
#>
function Get-OsInfo {
    Show-Header
    Write-Centered -Text "--- OPERATING SYSTEM INFORMATION ---" -Color Cyan
    Write-Host "`n"
    
    # Variables para almacenar el reporte exportable
    $reportTxt = "========================================`r`nATLAS PC SUPPORT - SYSTEM REPORT`r`n========================================`r`n`r`n"
    $reportHtml = "<html><head><meta charset='UTF-8'><title>ATLAS Report</title><style>body{font-family:'Segoe UI',Tahoma,sans-serif;background:#121212;color:#e0e0e0;text-align:center} .container{max-width:700px;margin:auto;background:#1e1e1e;padding:20px;border-radius:10px;box-shadow:0 4px 8px rgba(0,0,0,0.5)} h2{color:#f1c40f} .ok{color:#2ecc71} .warn{color:#f39c12} .info{color:#3498db;font-style:italic;font-size:0.9em;margin-top:5px;}</style></head><body><div class='container'><h2>ATLAS PC SUPPORT<br><small>License Report</small></h2><hr>"

    try {
        # Obtener datos del OS
        $os = Get-WmiObject -Class Win32_OperatingSystem
        Write-Centered -Text "System: $($os.Caption)" -Color White
        Write-Centered -Text "Version: $($os.Version)" -Color White
        Write-Centered -Text "Architecture: $($os.OSArchitecture)" -Color White
        Write-Centered -Text "OS Serial: $($os.SerialNumber)" -Color White
        
        $reportTxt += "--- OPERATING SYSTEM ---`r`nSystem: $($os.Caption)`r`nVersion: $($os.Version)`r`nArchitecture: $($os.OSArchitecture)`r`nSerial: $($os.SerialNumber)`r`n`r`n"
        $reportHtml += "<h3>OPERATING SYSTEM</h3><p>System: $($os.Caption)<br>Version: $($os.Version)<br>Architecture: $($os.OSArchitecture)<br>Serial: $($os.SerialNumber)</p><hr>"
        
        Write-Host "`n----------------------------------------`n" -ForegroundColor DarkGray
        
        # ---------------------------------------------------------
        # Obtener datos de la BIOS (Punto 1 integrado)
        # ---------------------------------------------------------
        Write-Centered -Text "--- FACTORY KEY (BIOS/UEFI) ---" -Color Cyan
        $sls = Get-WmiObject -Query 'select * from SoftwareLicensingService'
        $biosKey = $sls.OA3xOriginalProductKey
        $biosDesc = $sls.OA3xOriginalProductKeyDescription
        
        $reportTxt += "--- FACTORY KEY (BIOS/UEFI) ---`r`n"
        $reportHtml += "<h3>FACTORY KEY (BIOS/UEFI)</h3>"

        if ([string]::IsNullOrWhiteSpace($biosKey)) {
            Write-Centered -Text "BIOS Key: Not found (computer without factory Windows)" -Color Gray
            $reportTxt += "Status: Not found.`r`n`r`n"
            $reportHtml += "<p>Status: Not found.</p><hr>"
        } else {
            $descText = if ([string]::IsNullOrWhiteSpace($biosDesc)) { "Unknown Version" } else { $biosDesc }
            Write-Centered -Text "Factory Version: $descText" -Color Cyan
            Write-Centered -Text "BIOS Key: $biosKey" -Color Green
            Write-Centered -Text "[i] NOTE: Keys injected into BIOS (OEM) come from the" -Color DarkCyan
            Write-Centered -Text "computer manufacturer and are genuine licenses by nature." -Color DarkCyan

            $reportTxt += "Factory Version: $descText`r`nBIOS Key: $biosKey`r`n[i] NOTE: Keys injected into BIOS (OEM) come from the computer manufacturer and are genuine licenses by nature.`r`n`r`n"
            $reportHtml += "<p>Factory Version: <strong style='color:#3498db'>$descText</strong></p><p>BIOS Key: <strong class='ok'>$biosKey</strong></p><p class='info'>[i] NOTE: Keys injected into BIOS (OEM) come from the computer manufacturer and are genuine licenses by nature.</p><hr>"
        }
        
        Write-Host "`n----------------------------------------`n" -ForegroundColor DarkGray

        # ---------------------------------------------------------
        # Obtener datos de la Clave Actual (Punto 2 integrado)
        # ---------------------------------------------------------
        Write-Centered -Text "--- CURRENT KEY (INSTALLED OS) ---" -Color Cyan
        
        $regPath = "HKLM:\SOFTWARE\Microsoft\Windows NT\CurrentVersion\SoftwareProtectionPlatform"
        $backupKey = (Get-ItemProperty -Path $regPath -Name BackupProductKeyDefault -ErrorAction SilentlyContinue).BackupProductKeyDefault

        $hexPath = "HKLM:\SOFTWARE\Microsoft\Windows NT\CurrentVersion"
        
        # Corrección WMI:
        $currentEdition = (Get-WmiObject -Class Win32_OperatingSystem -ErrorAction SilentlyContinue).Caption -replace '^Microsoft\s+', ''
        
        $digitalProductId = (Get-ItemProperty -Path $hexPath -Name DigitalProductId -ErrorAction SilentlyContinue).DigitalProductId
        
        $decodedKey = $null
        $isKMSOrDigital = $false

        if ($digitalProductId -ne $null -and $digitalProductId.Length -ge 67) {
            $isWin8Or10 = [math]::Floor($digitalProductId[66] / 6) -band 1
            $digitalProductId[66] = ($digitalProductId[66] -band 0xF7) -bOr (($isWin8Or10 -band 2) * 4)
            $chars = "BCDFGHJKMPQRTVWXY2346789"
            $decodedKeyStr = ""
            for ($i = 24; $i -ge 0; $i--) {
                $current = 0
                for ($j = 14; $j -ge 0; $j--) {
                    $current = $current * 256 + $digitalProductId[$j + 52]
                    $digitalProductId[$j + 52] = [math]::Floor($current / 24)
                    $current = $current % 24
                }
                $decodedKeyStr = $chars[$current] + $decodedKeyStr
                $last = $current
            }
            if ($isWin8Or10 -eq 1) {
                $decodedKeyStr = $decodedKeyStr.Substring(1, $last) + "N" + $decodedKeyStr.Substring($last + 1)
            }
            $decodedKey = $decodedKeyStr.Insert(5, "-").Insert(11, "-").Insert(17, "-").Insert(23, "-")
            
            if ($decodedKey -eq "BBBBB-BBBBB-BBBBB-BBBBB-BBBBB") {
                $decodedKey = $null
                $isKMSOrDigital = $true
            }
        }

        $reportTxt += "--- CURRENT KEY (INSTALLED OS) ---`r`n"
        $reportHtml += "<h3>CURRENT KEY (INSTALLED OS)</h3>"

        $edText = if ([string]::IsNullOrWhiteSpace($currentEdition)) { "Unknown Edition" } else { $currentEdition }
        Write-Centered -Text "Installed Edition: $edText" -Color Cyan
        $reportTxt += "Installed Edition: $edText`r`n"
        $reportHtml += "<p>Installed Edition: <strong style='color:#3498db'>$edText</strong></p>"

        if ($isKMSOrDigital) {
            Write-Centered -Text "Decoded Key: [Hidden by corporate security]" -Color Yellow
            $reportTxt += "Status: Physical key hidden (MAK/KMS or Digital).`r`n"
            $reportHtml += "<p class='warn'>Status: Physical key hidden (MAK/KMS or Digital).</p>"
        } elseif (-not [string]::IsNullOrWhiteSpace($decodedKey)) {
            Write-Centered -Text "Decoded Key: $decodedKey" -Color Green
            $reportTxt += "Decoded Key: $decodedKey`r`n"
            $reportHtml += "<p>Decoded Key: <strong class='ok'>$decodedKey</strong></p>"
        } else {
            Write-Centered -Text "Decoded Key: Not found" -Color Gray
            $reportTxt += "Decoded Key: Not found`r`n"
            $reportHtml += "<p>Decoded Key: Not found</p>"
        }

        if (-not [string]::IsNullOrWhiteSpace($backupKey)) {
            Write-Centered -Text "Backup Key: $backupKey" -Color DarkCyan
            $reportTxt += "Backup Key: $backupKey`r`n"
            $reportHtml += "<p>Backup Key: <strong>$backupKey</strong></p>"
        }

        $reportTxt += "`r`n"
        $reportHtml += "<hr>"
        Write-Host "`n----------------------------------------`n" -ForegroundColor DarkGray

        # ---------------------------------------------------------
        # Obtener datos de Originalidad Visual (Punto 3 integrado)
        # ---------------------------------------------------------
        Write-Centered -Text "--- AUTHENTICITY ANALYSIS ---" -Color Cyan
        $wmiLic = Get-WmiObject -Query "SELECT Description, LicenseStatus FROM SoftwareLicensingProduct WHERE LicenseStatus = 1 AND PartialProductKey IS NOT NULL"
        
        $reportTxt += "--- AUTHENTICITY ANALYSIS ---`r`n"
        $reportHtml += "<h3>AUTHENTICITY ANALYSIS</h3>"

        if (-not $wmiLic) {
            Write-Centered -Text "[!] No active license detected on system." -Color Red
            $reportTxt += "Status: No active license.`r`n"
            $reportHtml += "<p class='warn'>Status: No active license.</p>"
        } else {
            foreach ($item in $wmiLic) {
                $cleanDesc = $item.Description -replace '.*, ', ''
                if ($item.Description -match "VOLUME_KMSCLIENT") {
                    Write-Centered -Text "[!] DETECTED: KMS CHANNEL ($cleanDesc)" -Color Yellow
                    Write-Centered -Text "[i] NOTE: Volume activation. If this computer does not belong" -Color DarkCyan
                    Write-Centered -Text "to a company, it was very likely activated using an emulator (Pirated)." -Color DarkCyan

                    $reportTxt += "[!] DETECTED: KMS CHANNEL ($cleanDesc)`r`n[i] NOTE: Volume activation. If this computer does not belong to a company, it was very likely activated using an emulator (Pirated).`r`n"
                    $reportHtml += "<p class='warn'>[!] DETECTED: KMS CHANNEL ($cleanDesc)</p><p class='info'>[i] NOTE: Volume activation. If this computer does not belong to a company, it was very likely activated using an emulator (Pirated).</p>"
                } elseif ($item.Description -match "VOLUME_MAK|RETAIL|OEM") {
                    Write-Centered -Text "[+] DETECTED: ORIGINAL CHANNEL ($cleanDesc)" -Color Green
                    Write-Centered -Text "[i] NOTE: Verified with the Windows licensing engine" -Color DarkCyan
                    Write-Centered -Text "that the current channel is official and legally ACTIVATED." -Color DarkCyan

                    $reportTxt += "[+] DETECTED: ORIGINAL CHANNEL ($cleanDesc)`r`n[i] NOTE: Verified with the Windows licensing engine that the current channel is official and legally ACTIVATED.`r`n"
                    $reportHtml += "<p class='ok'>[+] DETECTED: ORIGINAL CHANNEL ($cleanDesc)</p><p class='info'>[i] NOTE: Verified with the Windows licensing engine that the current channel is official and legally ACTIVATED.</p>"
                } else {
                    Write-Centered -Text "[?] DETECTED: UNKNOWN CHANNEL ($cleanDesc)" -Color Gray
                    
                    $reportTxt += "[?] DETECTED: UNKNOWN CHANNEL ($cleanDesc)`r`n"
                    $reportHtml += "<p>[?] DETECTED: UNKNOWN CHANNEL ($cleanDesc)</p>"
                }
            }
        }
        $reportHtml += "</div></body></html>"
        
    } catch {
        Write-Centered -Text "[X] Error retrieving system information." -Color Red
    }
    
    # Export menu
    Write-Host "`n----------------------------------------`n" -ForegroundColor DarkGray
    Write-Centered -Text "--- EXPORT THIS REPORT ---" -Color Yellow
    Write-Centered -Text "[ 1 ] Save as Text Document (.txt)" -Color White
    Write-Centered -Text "[ 2 ] Save as Web Page (.html)" -Color White
    Write-Centered -Text "[ 0 ] Back to menu without saving" -Color Red
    Write-Host "`n"

    $exportLoop = $true
    while ($exportLoop) {
        $expSel = Read-Host " Select an option"
        $desktopPath = [Environment]::GetFolderPath("Desktop")
        
        switch ($expSel) {
            '1' {
                $outPath = "$desktopPath\ATLAS_License_Report.txt"
                [System.IO.File]::WriteAllText($outPath, $reportTxt)
                Write-Host "`n"
                Write-Centered -Text "[+] Successfully saved to your Desktop:" -Color Green
                Write-Centered -Text "ATLAS_License_Report.txt" -Color Gray
                $exportLoop = $false
            }
            '2' {
                $outPath = "$desktopPath\ATLAS_License_Report.html"
                [System.IO.File]::WriteAllText($outPath, $reportHtml, [System.Text.Encoding]::UTF8)
                Write-Host "`n"
                Write-Centered -Text "[+] Successfully saved to your Desktop:" -Color Green
                Write-Centered -Text "ATLAS_License_Report.html" -Color Gray
                $exportLoop = $false
            }
            '0' {
                $exportLoop = $false
            }
            default {
                Write-Centered -Text "[!] Invalid selection. Please try again." -Color Red
            }
        }
    }

    Write-Host "`n"
    Write-Centered -Text "Press ENTER to return to main menu..." -Color White
    $null = Read-Host
}

# ============================================================================
#  OPCION 5: Claves de Office (SPP/OSPP + registro)
# ============================================================================
function Get-OfficeKeys {
    Show-Header
    Write-Centered -Text "--- OFFICE PRODUCT KEYS (SPP/OSPP) ---" -Color Cyan
    Write-Host ""

    $encontradas = @()

    # 5.1 Via OSPP / SPP: listar las licencias activas de Office via WMI
    try {
        $lics = Get-WmiObject -Query "SELECT * FROM SoftwareLicensingProduct WHERE ApplicationID='59A52881-A989-479D-AF46-F275C6370663' AND PartialProductKey IS NOT NULL" -ErrorAction Stop
        foreach ($l in $lics) {
            $statusMap = @{ 0='Unlicensed'; 1='Licensed'; 2='OOB Grace'; 3='OOT Grace'; 4='Non-Genuine Grace'; 5='Notification'; 6='Extended Grace' }
            $status = if ($statusMap.ContainsKey([int]$l.LicenseStatus)) { $statusMap[[int]$l.LicenseStatus] } else { "Code $($l.LicenseStatus)" }
            $encontradas += [pscustomobject]@{
                Producto = $l.Name
                Descripcion = $l.Description
                ParcialPK = "XXXXX-XXXXX-XXXXX-XXXXX-$($l.PartialProductKey)"
                Estado = $status
                Fuente = 'OSPP / SoftwareLicensingProduct'
            }
        }
    } catch {
        Write-Centered -Text "[!] Could not query OSPP: $($_.Exception.Message)" -Color Yellow
    }

    # 5.2 Buscar keys en registro HKLM:\SOFTWARE\Microsoft\Office\*\Registration\*\DigitalProductId
    try {
        $baseKeys = @(
            'HKLM:\SOFTWARE\Microsoft\Office',
            'HKLM:\SOFTWARE\WOW6432Node\Microsoft\Office'
        )
        foreach ($bk in $baseKeys) {
            if (-not (Test-Path $bk)) { continue }
            $regs = Get-ChildItem -Path "$bk\*\Registration\*" -ErrorAction SilentlyContinue
            foreach ($r in $regs) {
                $dpi = (Get-ItemProperty -Path $r.PSPath -Name DigitalProductId -ErrorAction SilentlyContinue).DigitalProductId
                $prodName = (Get-ItemProperty -Path $r.PSPath -Name ProductName -ErrorAction SilentlyContinue).ProductName
                if ($dpi) {
                    $key = Decode-DigitalProductId -BinKey $dpi
                    if ($key) {
                        $encontradas += [pscustomobject]@{
                            Producto = if ($prodName) { $prodName } else { $r.PSChildName }
                            Descripcion = 'DigitalProductId in Registry'
                            ParcialPK = $key
                            Estado = 'Active (registry)'
                            Fuente = 'Registry Office'
                        }
                    }
                }
            }
        }
    } catch { }

    if ($encontradas.Count -eq 0) {
        Write-Centered -Text "[!] No active Office keys detected." -Color Yellow
    } else {
        foreach ($e in $encontradas) {
            Write-Centered -Text ("Product : {0}" -f $e.Producto) -Color White
            Write-Centered -Text ("Status  : {0}" -f $e.Estado) -Color Cyan
            Write-Centered -Text ("Key     : {0}" -f $e.ParcialPK) -Color Yellow
            Write-Centered -Text ("Source  : {0}" -f $e.Fuente) -Color DarkGray
            Write-Host ""
        }
    }

    Write-Host ""
    $exp = Read-Host " Export results to TXT on Desktop? [Y/N]"
    if ($exp -match '^[SsYy]$') {
        $out = [Environment]::GetFolderPath('Desktop') + "\ATLAS_OfficeKeys_$(Get-Date -Format 'yyyyMMdd_HHmm').txt"
        $txt = "=== ATLAS - OFFICE PRODUCT KEYS ===`r`nDate: $(Get-Date)`r`n`r`n"
        foreach ($e in $encontradas) {
            $txt += "Product     : $($e.Producto)`r`nStatus      : $($e.Estado)`r`nKey         : $($e.ParcialPK)`r`nSource      : $($e.Fuente)`r`n`r`n"
        }
        [System.IO.File]::WriteAllText($out, $txt, [System.Text.UTF8Encoding]::new($true))
        Write-Centered -Text "[OK] Saved: $out" -Color Green
    }

    Write-Host ""
    Read-Host " Press ENTER to return"
}

# ============================================================================
#  Helper: Decodificar DigitalProductId (algoritmo Microsoft)
# ============================================================================
function Decode-DigitalProductId {
    param([byte[]]$BinKey)
    if (-not $BinKey -or $BinKey.Length -lt 67) { return $null }
    $isWin8 = ($BinKey[66] -band 0x8) -eq 0x8
    $chars = 'BCDFGHJKMPQRTVWXY2346789'
    $keyOffset = 52
    $out = ''

    if ($isWin8) {
        # Algoritmo Win8+ (25 chars, con N al 10)
        $bin = @($BinKey[$keyOffset..($keyOffset + 14)])
        $bin[14] = ($bin[14] -band 0xF7)
        $lastIdx = 0
        $decoded = New-Object 'System.Collections.Generic.List[char]'
        for ($i = 24; $i -ge 0; $i--) {
            $cur = 0
            for ($j = 14; $j -ge 0; $j--) {
                $cur = ($cur * 256) -bxor $bin[$j]
                $bin[$j] = [byte]([Math]::Floor($cur / 24))
                $cur = $cur % 24
            }
            $decoded.Insert(0, [char]$chars[$cur])
            $lastIdx = $cur
        }
        $first = $decoded[0]
        $decoded.RemoveAt(0)
        $decoded.Insert($lastIdx, 'N')
        $decoded.Insert(0, $first)
        $s = -join $decoded
        # Formato XXXXX-XXXXX-XXXXX-XXXXX-XXXXX (25 chars agrupados 5+5+5+5+5)
        $parts = @()
        for ($i = 0; $i -lt 25; $i += 5) { $parts += $s.Substring($i, [Math]::Min(5, 25 - $i)) }
        return ($parts -join '-')
    } else {
        # Algoritmo legacy
        $bin = @($BinKey[$keyOffset..($keyOffset + 14)])
        $decoded = New-Object 'System.Collections.Generic.List[char]'
        for ($i = 24; $i -ge 0; $i--) {
            $cur = 0
            for ($j = 14; $j -ge 0; $j--) {
                $cur = ($cur * 256) -bxor $bin[$j]
                $bin[$j] = [byte]([Math]::Floor($cur / 24))
                $cur = $cur % 24
            }
            $decoded.Insert(0, [char]$chars[$cur])
        }
        $s = -join $decoded
        $parts = @()
        for ($i = 0; $i -lt 25; $i += 5) { $parts += $s.Substring($i, [Math]::Min(5, 25 - $i)) }
        return ($parts -join '-')
    }
}

# ============================================================================
#  OPCION 6: Claves de productos instalados (DigitalProductId en Registry)
# ============================================================================
function Get-InstalledProductKeys {
    Show-Header
    Write-Centered -Text "--- INSTALLED PRODUCT KEYS (DigitalProductId) ---" -Color Cyan
    Write-Host ""
    Write-Centered -Text "Scanning HKLM and HKCU for DigitalProductId..." -Color DarkGray
    Write-Host ""

    $roots = @(
        'HKLM:\SOFTWARE\Microsoft\Windows NT\CurrentVersion',
        'HKLM:\SOFTWARE\WOW6432Node\Microsoft\Office',
        'HKCU:\SOFTWARE\Microsoft\Office'
    )

    $resultados = @()
    foreach ($root in $roots) {
        if (-not (Test-Path $root)) { continue }
        try {
            $hits = Get-ChildItem -Path $root -Recurse -ErrorAction SilentlyContinue | Where-Object {
                $_.GetValue('DigitalProductId') -ne $null
            }
            foreach ($h in $hits) {
                $bin = $h.GetValue('DigitalProductId')
                $prod = $h.GetValue('ProductName')
                if (-not $prod) { $prod = $h.GetValue('ProductID') }
                if (-not $prod) { $prod = $h.PSChildName }
                $key = Decode-DigitalProductId -BinKey $bin
                if ($key -match '^[A-Z0-9]{5}(-[A-Z0-9]{5}){4}$') {
                    $resultados += [pscustomobject]@{
                        Producto = $prod
                        Clave = $key
                        Ruta = $h.PSPath -replace '^Microsoft\.PowerShell\.Core\\Registry::', ''
                    }
                }
            }
        } catch { }
    }

    if ($resultados.Count -eq 0) {
        Write-Centered -Text "[!] No decodable DigitalProductIds found." -Color Yellow
    } else {
        foreach ($r in ($resultados | Sort-Object Producto -Unique)) {
            Write-Centered -Text ("{0}" -f $r.Producto) -Color White
            Write-Centered -Text ("  Key: {0}" -f $r.Clave) -Color Yellow
            Write-Centered -Text ("  {0}" -f $r.Ruta) -Color DarkGray
            Write-Host ""
        }
    }

    Write-Host ""
    $exp = Read-Host " Export to TXT? [Y/N]"
    if ($exp -match '^[SsYy]$') {
        $out = [Environment]::GetFolderPath('Desktop') + "\ATLAS_ProductKeys_$(Get-Date -Format 'yyyyMMdd_HHmm').txt"
        $txt = "=== ATLAS - PRODUCT KEYS (DigitalProductId) ===`r`nDate: $(Get-Date)`r`n`r`n"
        foreach ($r in ($resultados | Sort-Object Producto -Unique)) {
            $txt += "Product : $($r.Producto)`r`nKey     : $($r.Clave)`r`nPath    : $($r.Ruta)`r`n`r`n"
        }
        [System.IO.File]::WriteAllText($out, $txt, [System.Text.UTF8Encoding]::new($true))
        Write-Centered -Text "[OK] Saved: $out" -Color Green
    }

    Write-Host ""
    Read-Host " Press ENTER to return"
}

# ============================================================================
#  OPCION 7: Navegadores (Edge / Chrome) - con consentimiento explicito
# ============================================================================
function Get-BrowserPasswords {
    Show-Header
    Write-Centered -Text "--- BROWSER PASSWORDS (Edge / Chrome) ---" -Color Red
    Write-Host ""
    Write-Centered -Text "!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!" -Color Yellow
    Write-Centered -Text "                  LEGAL WARNING" -Color Yellow
    Write-Centered -Text "!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!" -Color Yellow
    Write-Host ""
    Write-Centered -Text " - This function extracts credentials stored in the browser" -Color White
    Write-Centered -Text "   of the CURRENT Windows USER." -Color White
    Write-Centered -Text " - This is EXTREMELY sensitive information." -Color White
    Write-Centered -Text " - Only use on your own equipment or with EXPLICIT WRITTEN" -Color White
    Write-Centered -Text "   AUTHORIZATION from the equipment owner." -Color White
    Write-Centered -Text " - The Windows user must confirm acceptance of extraction." -Color White
    Write-Centered -Text " - Atlas PC Support does not store or transmit this data." -Color White
    Write-Host ""
    $c1 = Read-Host " Type exactly: AUTHORIZE  to continue"
    if ($c1 -ne 'AUTHORIZE' -and $c1 -ne 'AUTORIZO') {
        Write-Centered -Text "[X] Cancelled. No passwords were extracted." -Color Red
        Write-Host ""
        Read-Host " Press ENTER to return"
        return
    }

    $results = @()

    # Browsers basados en Chromium: Edge, Chrome, Brave, Opera GX
    $profiles = @(
        @{ Nombre='Edge';   Base="$env:LOCALAPPDATA\Microsoft\Edge\User Data" },
        @{ Nombre='Chrome'; Base="$env:LOCALAPPDATA\Google\Chrome\User Data" },
        @{ Nombre='Brave';  Base="$env:LOCALAPPDATA\BraveSoftware\Brave-Browser\User Data" },
        @{ Nombre='Opera';  Base="$env:APPDATA\Opera Software\Opera Stable" }
    )

    try {
        Add-Type -AssemblyName System.Security -ErrorAction SilentlyContinue
    } catch { }

    foreach ($br in $profiles) {
        if (-not (Test-Path $br.Base)) { continue }
        Write-Host ""
        Write-Centered -Text ("--- Analyzing {0} ---" -f $br.Nombre) -Color Cyan

        # Obtener master key (DPAPI)
        $localState = Join-Path $br.Base 'Local State'
        $masterKey = $null
        if (Test-Path $localState) {
            try {
                $ls = Get-Content $localState -Raw -Encoding UTF8 | ConvertFrom-Json
                $b64 = $ls.os_crypt.encrypted_key
                if ($b64) {
                    $buf = [Convert]::FromBase64String($b64)
                    # Prefijo "DPAPI" de 5 bytes
                    $dpapiBlob = $buf[5..($buf.Length - 1)]
                    $mk = [System.Security.Cryptography.ProtectedData]::Unprotect($dpapiBlob, $null, 'CurrentUser')
                    $masterKey = $mk
                }
            } catch {
                Write-Centered -Text ("[!] Could not get master key from {0}: {1}" -f $br.Nombre, $_.Exception.Message) -Color Yellow
            }
        }
        if (-not $masterKey) {
            Write-Centered -Text ("[!] Without master key, passwords from {0} cannot be decrypted." -f $br.Nombre) -Color Yellow
            continue
        }

        # Enumerar todos los perfiles ("Default", "Profile 1", etc)
        $dirs = @(Get-ChildItem -Path $br.Base -Directory -ErrorAction SilentlyContinue | Where-Object { $_.Name -eq 'Default' -or $_.Name -like 'Profile*' })
        if ($br.Nombre -eq 'Opera') { $dirs = @([PSCustomObject]@{ FullName = $br.Base; Name = 'Opera Stable' }) }

        foreach ($d in $dirs) {
            $loginDb = Join-Path $d.FullName 'Login Data'
            if (-not (Test-Path $loginDb)) { continue }
            $tmp = Join-Path $env:TEMP "atlas_logindb_$([guid]::NewGuid().ToString('N')).db"
            try {
                Copy-Item $loginDb $tmp -Force -ErrorAction Stop
            } catch {
                Write-Centered -Text ("[!] Could not copy DB of {0} ({1}). Close the browser." -f $br.Nombre, $d.Name) -Color Yellow
                continue
            }
            try {
                Add-Type -Path 'System.Data.SQLite.dll' -ErrorAction SilentlyContinue
            } catch { }
            # Sin System.Data.SQLite no podemos leer la DB directamente. Dejamos el info:
            Write-Centered -Text ("   Login DB: {0}" -f $loginDb) -Color DarkGray
            Write-Centered -Text "   [i] SQLite extraction not available without external dependency." -Color DarkGray
            Write-Centered -Text "       Copy the DB manually with a SQLite viewer if you need to see entries." -Color DarkGray
            $results += [pscustomobject]@{
                Navegador = $br.Nombre
                Perfil = $d.Name
                Ruta = $loginDb
                Estado = 'DB located; decryption requires external SQLite tool'
            }
            Remove-Item $tmp -Force -ErrorAction SilentlyContinue
        }
    }

    Write-Host ""
    if ($results.Count -eq 0) {
        Write-Centered -Text "[!] No browsers detected with accessible credentials." -Color Yellow
    } else {
        Write-Centered -Text "[i] Browsers with located DB:" -Color Cyan
        foreach ($r in $results) {
            Write-Centered -Text ("  - {0} / {1}" -f $r.Navegador, $r.Perfil) -Color White
        }
        Write-Host ""
        Write-Centered -Text "To export passwords legitimately:" -Color Yellow
        Write-Centered -Text "  Edge:   edge://settings/passwords -> menu ... -> Export passwords" -Color Gray
        Write-Centered -Text "  Chrome: chrome://settings/passwords -> ... -> Export passwords" -Color Gray
        Write-Centered -Text "  Brave:  brave://settings/passwords -> ... -> Export" -Color Gray
        Write-Centered -Text "(This official method asks for the current user's Windows password.)" -Color DarkGray
    }

    Write-Host ""
    Read-Host " Press ENTER to return"
}

# Bucle principal
$menuLoop = $true
while ($menuLoop) {
    Show-Header
    Write-Centered -Text "M A I N   M E N U" -Color Cyan
    Write-Host "`n"
    Write-Centered -Text "[ 1 ] Extract Factory Key (BIOS/UEFI)" -Color White
    Write-Centered -Text "[ 2 ] Extract and Diagnose Current Key (Registry)" -Color White
    Write-Centered -Text "[ 3 ] Native Audit and Authenticity (SLMGR)" -Color White
    Write-Centered -Text "[ 4 ] Full Report (OS, BIOS, Current and Authenticity)" -Color White
    Write-Centered -Text "[ 5 ] Extract Office Keys (OSPP/SPP + Registry)" -Color Cyan
    Write-Centered -Text "[ 6 ] Installed product keys (DigitalProductId)" -Color Cyan
    Write-Centered -Text "[ 7 ] Browsers (Edge/Chrome) - REQUIRES AUTHORIZATION" -Color Yellow
    Write-Centered -Text "[ 0 ] Exit" -Color Red
    Write-Host "`n"
    
    $selection = Read-Host " Select an option"
    
    switch ($selection) {
        '1' { Get-BiosKey }
        '2' { Get-CurrentKey }
        '3' { Invoke-NativeAudit }
        '4' { Get-OsInfo }
        '5' { Get-OfficeKeys }
        '6' { Get-InstalledProductKeys }
        '7' { Get-BrowserPasswords }
        '0' { $menuLoop = $false }
    }
}
}


# ---- tools\Invoke-Fase0.ps1 ----
# ============================================================
# Invoke-Fase0  ->  Disable Legacy IPv6 Tunnels
#
# i18n: Option A (en default + full es secondary). Tool-internal
# function name kept as Invoke-Fase0 so tools.json registry, USB
# offline copies, and existing client config.json keep working.
#
# Atlas PC Support
# ============================================================

function Invoke-Fase0 {
    [CmdletBinding()]
    param()
<#
    .SYNOPSIS
    ATLAS PC SUPPORT - Disable Legacy IPv6 Tunnels (Teredo / 6to4 / ISATAP)
#>

# --- 0. Language detection ---
function _Atlas-DetectLang {
    if ($env:ATLAS_LANG) { return [string]$env:ATLAS_LANG }
    try {
        $cfg = Join-Path $env:LOCALAPPDATA 'AtlasPC\config.json'
        if (Test-Path -LiteralPath $cfg) {
            $obj = Get-Content -Raw -LiteralPath $cfg -Encoding UTF8 | ConvertFrom-Json
            if ($obj.language) { return [string]$obj.language }
        }
    } catch {}
    $sys = (Get-Culture).TwoLetterISOLanguageName
    if ($sys -eq 'es') { return 'es' }
    return 'en'
}

$T = @{
    en = @{
        Brand          = 'ATLAS PC SUPPORT'
        Subtitle       = 'DISABLE LEGACY IPv6 TUNNELS'
        Sep            = '================================'
        LogActive      = '[ REC ] LOG ACTIVE'
        LogInactive    = '[   ] LOG INACTIVE'
        LogStarted     = 'Log started.'
        LogAlready     = 'Log already running.'
        ReportSaved    = 'Report saved.'
        ReportHeader   = "=========================================`n ATLAS PC SUPPORT - TECHNICAL REPORT`n=========================================`nStart      : {0}`nClient PC  : {1}`nUser       : {2}`n=========================================`n"
        SessionEnd     = '--- SESSION END ---'
        ApplyHeader    = '[ APPLYING HARDENING PROTOCOL ]'
        ApplyStart     = '-> STARTING IPv6 TUNNEL HARDENING'
        DisablingTeredo = 'Disabling Teredo Tunneling... [OK]'
        Disabling6to4   = 'Disabling 6to4 Interface... [OK]'
        DisablingIsatap = 'Disabling ISATAP Tunneling... [OK]'
        ApplyDone       = '-> HARDENING COMPLETE.'
        Done            = 'HARDENING COMPLETE.'
        PressKey        = '[ Press any key to return ]'
        UndoHeader      = '[ RESTORING DEFAULTS ]'
        UndoStart       = '-> REVERTING CHANGES (RESTORE DEFAULTS)'
        RestoringTeredo = 'Restoring Teredo... [OK]'
        Restoring6to4   = 'Restoring 6to4... [OK]'
        RestoringIsatap = 'Restoring ISATAP... [OK]'
        UndoDone        = '-> WARNING: machine returned to default (vulnerable) state.'
        Warn            = 'WARN: machine returned to vulnerable state.'
        StatusHeader    = '[ CURRENT NETWORK STATE ]'
        StatusReq       = '-> REQUESTING CURRENT INTERFACE STATE'
        TeredoState     = '--- TEREDO STATE ---'
        SixToFourState  = '--- 6to4 STATE ---'
        Menu1           = '[1] Start log                    '
        Menu2           = '[2] APPLY HARDENING (recommended)'
        Menu3           = '[3] Check current state          '
        Menu4           = '[4] Restore defaults (undo)      '
        Menu5           = '[5] Stop log                     '
        MenuQ           = '[Q] Quit                         '
        Prompt          = "`n      > Atlas_Admin@Terminal: "
        ExecLabel       = '[EXEC] '
        Result          = 'Result: '
        ReportFolderName = 'ATLAS_SUPPORT'
        ReportFilePrefix = 'Report_LegacyIPv6_'
    }
    es = @{
        Brand          = 'ATLAS PC SUPPORT'
        Subtitle       = 'SEGURIDAD FASE 0'
        Sep            = '================================'
        LogActive      = '[ REC ] BITACORA ACTIVA'
        LogInactive    = '[   ] BITACORA INACTIVA'
        LogStarted     = 'Bitacora iniciada correctamente.'
        LogAlready     = 'La bitacora ya esta iniciada.'
        ReportSaved    = 'Reporte guardado exitosamente.'
        ReportHeader   = "=========================================`n ATLAS PC SUPPORT - REPORTE TECNICO`n=========================================`nFecha de inicio : {0}`nEquipo Cliente  : {1}`nUsuario         : {2}`n=========================================`n"
        SessionEnd     = '--- CIERRE DE SESION ---'
        ApplyHeader    = '[ APLICANDO PROTOCOLO DE BLINDAJE ]'
        ApplyStart     = '-> INICIANDO PROTOCOLO DE BLINDAJE (FASE 0)'
        DisablingTeredo = 'Desactivando Teredo Tunneling... [OK]'
        Disabling6to4   = 'Desactivando 6to4 Interface... [OK]'
        DisablingIsatap = 'Desactivando ISATAP Tunneling... [OK]'
        ApplyDone       = '-> FASE 0 COMPLETADA CON EXITO.'
        Done            = 'FASE 0 COMPLETADA.'
        PressKey        = '[ Presiona cualquier tecla para volver ]'
        UndoHeader      = '[ RESTAURANDO VALORES DE FABRICA ]'
        UndoStart       = '-> REVIRTIENDO CAMBIOS (RESTAURACION DE FABRICA)'
        RestoringTeredo = 'Restaurando Teredo... [OK]'
        Restoring6to4   = 'Restaurando 6to4... [OK]'
        RestoringIsatap = 'Restaurando ISATAP... [OK]'
        UndoDone        = '-> ADVERTENCIA: El equipo ha sido devuelto a su estado predeterminado.'
        Warn            = 'WARN: El equipo ha vuelto a su estado vulnerable.'
        StatusHeader    = '[ ESTADO ACTUAL DE LA RED ]'
        StatusReq       = '-> SOLICITANDO ESTADO ACTUAL DE INTERFACES'
        TeredoState     = '--- TEREDO STATE ---'
        SixToFourState  = '--- 6to4 STATE ---'
        Menu1           = '[1] Iniciar bitacora               '
        Menu2           = '[2] EJECUTAR BLINDAJE (recomendado)'
        Menu3           = '[3] Verificar estado actual        '
        Menu4           = '[4] Restaurar configuracion (undo) '
        Menu5           = '[5] Finalizar bitacora             '
        MenuQ           = '[Q] Salir                          '
        Prompt          = "`n      > Atlas_Admin@Terminal: "
        ExecLabel       = '[EJECUTANDO] '
        Result          = 'Resultado: '
        ReportFolderName = 'ATLAS_SUPPORT'
        ReportFilePrefix = 'Reporte_Fase0_'
    }
}
$lang = _Atlas-DetectLang
if (-not $T.ContainsKey($lang)) { $lang = 'en' }
$L = $T[$lang]

# --- 1. INITIAL CONFIG ---
[Console]::OutputEncoding = [System.Text.Encoding]::UTF8

$AtlasOrange = "$([char]0x1b)[38;2;255;102;0m"
$AtlasWhite  = "$([char]0x1b)[38;2;255;255;255m"
$AtlasGray   = "$([char]0x1b)[38;2;100;100;100m"
$AtlasGreen  = "$([char]0x1b)[38;2;0;255;0m"
$AtlasRed    = "$([char]0x1b)[38;2;255;50;50m"
$Reset       = "$([char]0x1b)[0m"

$Host.UI.RawUI.BackgroundColor = "Black"
Clear-Host

# Globals for the log subsystem
$global:IsLogging = $false
$global:LogFile = ""

# --- 2. AUTO-ELEVATION ---
# (auto-elevation handled by Atlas Launcher)

# --- 3. VISUAL HELPERS ---
function Write-Centered {
    param([string]$Text, [string]$Color = $AtlasWhite)
    $WindowWidth = $Host.UI.RawUI.WindowSize.Width
    $Padding = [math]::Max(0, [int](($WindowWidth - $Text.Length) / 2))
    $LeftSpaces = " " * $Padding
    Write-Host "$LeftSpaces$Color$Text$Reset"
}

function Show-Header {
    Clear-Host
    Write-Host "`n`n`n"
    Write-Centered $L.Brand $AtlasOrange
    Write-Centered $L.Subtitle $AtlasWhite
    Write-Centered $L.Sep $AtlasGray

    if ($global:IsLogging) {
        Write-Centered $L.LogActive $AtlasRed
    } else {
        Write-Centered $L.LogInactive $AtlasGray
    }
    Write-Host "`n`n"
}

# --- 4. CUSTOM LOG ENGINE ---
function Write-AtlasLog {
    param([string]$Message)
    if ($global:IsLogging -and $global:LogFile) {
        $Timestamp = Get-Date -Format "HH:mm:ss"
        "[$Timestamp] $Message" | Out-File -FilePath $global:LogFile -Append -Encoding UTF8
    }
}

function Start-AtlasLog {
    if ($global:IsLogging) {
        Show-Header; Write-Centered $L.LogAlready $AtlasOrange; Start-Sleep -Seconds 2; return
    }

    $DesktopPath = [Environment]::GetFolderPath("Desktop")
    $LogFolder = Join-Path -Path $DesktopPath -ChildPath $L.ReportFolderName
    if (-not (Test-Path -Path $LogFolder)) { New-Item -ItemType Directory -Path $LogFolder -Force | Out-Null }

    $TimeString = Get-Date -Format "yyyyMMdd_HHmmss"
    $global:LogFile = Join-Path -Path $LogFolder -ChildPath ('{0}{1}.txt' -f $L.ReportFilePrefix, $TimeString)
    $global:IsLogging = $true

    $ReportHeader = $L.ReportHeader -f (Get-Date -Format 'dd/MM/yyyy HH:mm:ss'), $env:COMPUTERNAME, $env:USERNAME
    $ReportHeader | Out-File -FilePath $global:LogFile -Encoding UTF8

    Show-Header
    Write-Centered $L.LogStarted $AtlasGreen
    Start-Sleep -Seconds 1
}

function Stop-AtlasLog {
    if (-not $global:IsLogging) { return }

    Write-AtlasLog $L.SessionEnd
    $global:IsLogging = $false

    Show-Header
    Write-Centered $L.ReportSaved $AtlasGreen
    Start-Sleep -Seconds 1
}

# --- 5. ACTION FUNCTIONS WITH LOGGING ---
function Hardening-Apply {
    Show-Header
    Write-Centered $L.ApplyHeader $AtlasWhite
    Write-Host "`n"

    Write-AtlasLog $L.ApplyStart

    Write-Centered $L.DisablingTeredo $AtlasGreen
    Write-AtlasLog ($L.ExecLabel + $L.DisablingTeredo)
    $res1 = netsh interface teredo set state disabled
    Write-AtlasLog ($L.Result + $res1)

    Write-Centered $L.Disabling6to4 $AtlasGreen
    Write-AtlasLog ($L.ExecLabel + $L.Disabling6to4)
    $res2 = netsh interface ipv6 6to4 set state state=disabled undoonstop=disabled
    Write-AtlasLog ($L.Result + $res2)

    Write-Centered $L.DisablingIsatap $AtlasGreen
    Write-AtlasLog ($L.ExecLabel + $L.DisablingIsatap)
    $res3 = netsh interface ipv6 isatap set state state=disabled
    Write-AtlasLog ($L.Result + $res3)

    Write-AtlasLog $L.ApplyDone

    Write-Host "`n"
    Write-Centered $L.Done $AtlasOrange
    Write-Host "`n"
    Write-Centered $L.PressKey $AtlasGray
    $null = $Host.UI.RawUI.ReadKey("NoEcho,IncludeKeyDown")
}

function Restore-Defaults {
    Show-Header
    Write-Centered $L.UndoHeader $AtlasRed
    Write-Host "`n"

    Write-AtlasLog $L.UndoStart

    Write-Centered $L.RestoringTeredo $AtlasWhite
    $res1 = netsh interface teredo set state type=default
    Write-AtlasLog ($L.ExecLabel + $L.RestoringTeredo + ' ' + $L.Result + $res1)

    Write-Centered $L.Restoring6to4 $AtlasWhite
    $res2 = netsh interface ipv6 6to4 set state state=enabled
    Write-AtlasLog ($L.ExecLabel + $L.Restoring6to4 + ' ' + $L.Result + $res2)

    Write-Centered $L.RestoringIsatap $AtlasWhite
    $res3 = netsh interface ipv6 isatap set state state=enabled
    Write-AtlasLog ($L.ExecLabel + $L.RestoringIsatap + ' ' + $L.Result + $res3)

    Write-AtlasLog $L.UndoDone

    Write-Host "`n"
    Write-Centered $L.Warn $AtlasWhite
    Write-Host "`n"
    Write-Centered $L.PressKey $AtlasGray
    $null = $Host.UI.RawUI.ReadKey("NoEcho,IncludeKeyDown")
}

function Check-Status {
    Show-Header
    Write-Centered $L.StatusHeader $AtlasWhite
    Write-Host "`n"

    Write-AtlasLog $L.StatusReq

    $Teredo = (netsh interface teredo show state | Out-String).Trim()
    $6to4 = (netsh interface ipv6 6to4 show state | Out-String).Trim()

    Write-AtlasLog ($L.TeredoState + "`n" + $Teredo)
    Write-AtlasLog ($L.SixToFourState + "`n" + $6to4)

    Write-Centered $L.TeredoState $AtlasGray
    Write-Centered $Teredo $AtlasWhite
    Write-Host "`n"
    Write-Centered $L.SixToFourState $AtlasGray
    Write-Centered $6to4 $AtlasWhite
    Write-Host "`n"
    Write-Centered $L.PressKey $AtlasGray
    $null = $Host.UI.RawUI.ReadKey("NoEcho,IncludeKeyDown")
}

# --- 6. MAIN MENU ---
do {
    Show-Header

    Write-Centered $L.Menu1 $AtlasGreen
    Write-Centered $L.Menu2 $AtlasWhite
    Write-Centered $L.Menu3 $AtlasWhite
    Write-Centered $L.Menu4 $AtlasRed
    Write-Centered $L.Menu5 $AtlasGray
    Write-Centered $L.MenuQ $AtlasGray

    Write-Host $L.Prompt -NoNewline -ForegroundColor DarkYellow
    $Selection = Read-Host

    switch ($Selection) {
        '1' { Start-AtlasLog }
        '2' { Hardening-Apply }
        '3' { Check-Status }
        '4' { Restore-Defaults }
        '5' { Stop-AtlasLog }
        'q' { Stop-AtlasLog; exit }
        'Q' { Stop-AtlasLog; exit }
    }
} while ($true)
}


# ---- tools\Invoke-FastCopy.ps1 ----
# ============================================================
# Invoke-FastCopy
# Migrado de: FastCopy.ps1
# Atlas PC Support — v1.0
# ============================================================

function Invoke-FastCopy {
    [CmdletBinding()]
    param()
# ========================================================
# ATLAS PC SUPPORT - FASTCOPY EDITION v3 (PowerShell)
# Multi-origen + Perfiles + Comparar + Notificacion
# MD5 + Speed adapt + Summary exportable + Exclusiones
# ========================================================

$Host.UI.RawUI.BackgroundColor = "Black"
$Host.UI.RawUI.ForegroundColor = "Gray"
$Host.UI.RawUI.WindowTitle = "ATLAS PC SUPPORT - FastCopy v3"
try { $Host.UI.RawUI.WindowSize = New-Object System.Management.Automation.Host.Size(110, 48) } catch {}
$ErrorActionPreference = "Continue"

# ==================== BUSCAR FASTCOPY ====================

function Find-FastCopy {
    $atlasApps = if ($env:LOCALAPPDATA) { Join-Path $env:LOCALAPPDATA 'AtlasPC\apps\FastCopy' } else { $null }
    $searchPaths = @(
        (Join-Path $PSScriptRoot "FastCopy.exe"),
        (Join-Path $PSScriptRoot "fastcopy\FastCopy.exe"),
        (Join-Path $PSScriptRoot "..\Apps\FastCopy\FastCopy.exe"),
        (Join-Path $PSScriptRoot "Apps\FastCopy\FastCopy.exe"),
        "C:\Program Files\FastCopy\FastCopy.exe",
        "C:\Program Files (x86)\FastCopy\FastCopy.exe",
        (Join-Path $env:LOCALAPPDATA "FastCopy\FastCopy.exe")
    )
    if ($atlasApps) { $searchPaths += (Join-Path $atlasApps 'FastCopy.exe') }
    foreach ($path in $searchPaths) {
        if ($path -and (Test-Path $path)) { return (Resolve-Path $path).Path }
    }
    $inPath = Get-Command "FastCopy.exe" -ErrorAction SilentlyContinue
    if ($inPath) { return $inPath.Source }
    if ($PSScriptRoot) {
        $found = Get-ChildItem -Path $PSScriptRoot -Filter "FastCopy.exe" -Recurse -ErrorAction SilentlyContinue | Select-Object -First 1
        if ($found) { return $found.FullName }
    }
    return $null
}

function Install-FastCopyAuto {
    # Descarga el installer oficial de FastCopy (fastcopy.jp redirige a GitHub),
    # lo ejecuta silenciosamente a %LOCALAPPDATA%\AtlasPC\apps\FastCopy y
    # devuelve la ruta al .exe.
    $targetDir = Join-Path $env:LOCALAPPDATA 'AtlasPC\apps\FastCopy'
    if (-not (Test-Path $targetDir)) {
        New-Item -ItemType Directory -Path $targetDir -Force | Out-Null
    }

    # URLs en orden de preferencia (version mas reciente primero).
    # fastcopy.jp hace redirect 302 a GitHub/FastCopyLab.
    $urls = @(
        'https://fastcopy.jp/archive/FastCopy5.11.2_installer.exe',
        'https://github.com/FastCopyLab/FastCopyDist2/raw/main/FastCopy5.11.2_installer.exe',
        'https://fastcopy.jp/archive/FastCopy5.9.0_installer.exe'
    )

    $installerPath = Join-Path $env:TEMP ("FastCopy-installer-" + [guid]::NewGuid().ToString('N').Substring(0,8) + ".exe")
    $ok = $false
    foreach ($url in $urls) {
        Write-Host "    Descargando: $url" -ForegroundColor Gray
        try {
            $ProgressPreference = 'SilentlyContinue'
            Invoke-WebRequest -Uri $url -OutFile $installerPath -UseBasicParsing -TimeoutSec 120 -ErrorAction Stop
            if ((Get-Item $installerPath).Length -gt 200KB) { $ok = $true; break }
        } catch {
            Write-Host "    Fallo: $($_.Exception.Message)" -ForegroundColor Yellow
        }
    }
    if (-not $ok) { throw "No se pudo descargar el installer de FastCopy." }

    # El installer oficial de FastCopy NO es InnoSetup; es custom.
    # Switches (segun el propio installedr):
    #   /SILENT ... silent install
    #   /DIR=<dir> ... target dir
    #   /EXTRACT64 ... extraer only archivos (sin instalar)
    #   /NOSUBDIR ... no crear subcarpeta
    #   /AGREE_LICENSE ... aceptar licencia
    # Usamos /EXTRACT64 para only dejar los archivos en $targetDir
    # sin modificar menu inicio / Program Files / registro.
    Write-Host "    Extracting FastCopy a $targetDir ..." -ForegroundColor Gray
    $procArgs = @('/EXTRACT64', '/NOSUBDIR', '/AGREE_LICENSE', ("/DIR=`"$targetDir`""))
    try {
        $p = Start-Process -FilePath $installerPath -ArgumentList $procArgs -Wait -PassThru -ErrorAction Stop
        if ($p.ExitCode -ne 0) {
            Write-Host "    /EXTRACT64 finished with code $($p.ExitCode). Trying /SILENT install..." -ForegroundColor Yellow
            $p2 = Start-Process -FilePath $installerPath -ArgumentList @('/SILENT', '/AGREE_LICENSE', ("/DIR=`"$targetDir`"")) -Wait -PassThru -ErrorAction Stop
            if ($p2.ExitCode -ne 0) {
                Write-Host "    /SILENT also failed. Running in interactive mode..." -ForegroundColor Yellow
                Start-Process -FilePath $installerPath -Wait
            }
        }
    } catch {
        throw "Fallo ejecutando el installedr: $($_.Exception.Message)"
    } finally {
        Remove-Item $installerPath -ErrorAction SilentlyContinue
    }

    # Buscar el .exe en target (el installer puede poner FastCopy.exe directo o en subcarpeta).
    $exe = Get-ChildItem -Path $targetDir -Filter 'FastCopy.exe' -Recurse -ErrorAction SilentlyContinue | Select-Object -First 1
    if (-not $exe) {
        # Si el user eligio el default (Program Files), buscar ahi.
        $fallbacks = @(
            "$env:ProgramFiles\FastCopy\FastCopy.exe",
            "${env:ProgramFiles(x86)}\FastCopy\FastCopy.exe"
        )
        foreach ($fb in $fallbacks) {
            if (Test-Path $fb) { $exe = Get-Item $fb; break }
        }
    }
    if (-not $exe) { throw "FastCopy.exe not found after installation." }
    return $exe.FullName
}

# ==================== FUNCIONES BASE ====================

function Write-Centered {
    param ([string]$Text, [string]$Color = "White")
    $W = try { $Host.UI.RawUI.WindowSize.Width } catch { 80 }
    $Pad = [math]::Max(0, [math]::Floor(($W - $Text.Length) / 2))
    Write-Host (" " * $Pad + $Text) -ForegroundColor $Color
}

function Clean-Path {
    param([string]$RawPath)
    return $RawPath.Trim().Trim('"').Trim("'").TrimEnd('\')
}

function Format-Size {
    param([long]$Bytes)
    if ($Bytes -ge 1GB) { return "{0:N2} GB" -f ($Bytes / 1GB) }
    if ($Bytes -ge 1MB) { return "{0:N1} MB" -f ($Bytes / 1MB) }
    if ($Bytes -ge 1KB) { return "{0:N0} KB" -f ($Bytes / 1KB) }
    return "$Bytes B"
}

function Format-Duration {
    param([TimeSpan]$Duration)
    if ($Duration.TotalHours -ge 1) { return "{0}h {1}m {2}s" -f [int]$Duration.TotalHours, $Duration.Minutes, $Duration.Seconds }
    if ($Duration.TotalMinutes -ge 1) { return "{0}m {1}s" -f [int]$Duration.TotalMinutes, $Duration.Seconds }
    return "{0:N1}s" -f $Duration.TotalSeconds
}

function Get-FolderStats {
    param([string]$Path)
    $items = Get-ChildItem -Path $Path -Recurse -File -ErrorAction SilentlyContinue
    $totalSize = ($items | Measure-Object Length -Sum -ErrorAction SilentlyContinue).Sum
    if (-not $totalSize) { $totalSize = 0 }
    return @{ Files = $items.Count; Size = $totalSize; SizeMB = [math]::Round($totalSize / 1MB, 1) }
}

function Detect-DriveType {
    param([string]$DriveLetter)
    $letter = $DriveLetter.TrimEnd(':', '\')
    try {
        $vol = Get-Volume -DriveLetter $letter -ErrorAction Stop
        if ($vol.DriveType -eq 'Removable') {
            return @{ Type = "USB"; Speed = "autoslow"; Desc = "USB Removible"; Color = "Yellow"; Label = $vol.FileSystemLabel; FreeBytes = $vol.SizeRemaining }
        }
        $part = Get-Partition -DriveLetter $letter -ErrorAction Stop
        $disk = Get-Disk -Number $part.DiskNumber -ErrorAction Stop
        $phys = Get-PhysicalDisk -ErrorAction SilentlyContinue | Where-Object { $_.DeviceId -eq $disk.Number.ToString() }
        if ($disk.BusType -eq 'USB') {
            return @{ Type = "USB"; Speed = "autoslow"; Desc = "USB Externo"; Color = "Yellow"; Label = $vol.FileSystemLabel; FreeBytes = $vol.SizeRemaining }
        }
        if ($disk.BusType -eq 'NVMe' -or ($phys -and $phys.MediaType -match 'SSD')) {
            return @{ Type = "SSD"; Speed = "full"; Desc = "SSD/NVMe"; Color = "Green"; Label = $vol.FileSystemLabel; FreeBytes = $vol.SizeRemaining }
        }
        return @{ Type = "HDD"; Speed = "full"; Desc = "HDD Mecanico"; Color = "Cyan"; Label = $vol.FileSystemLabel; FreeBytes = $vol.SizeRemaining }
    } catch {
        return @{ Type = "UNKNOWN"; Speed = "autoslow"; Desc = "No detectado"; Color = "Gray"; Label = ""; FreeBytes = 0 }
    }
}

# ==================== EXPLORADOR DE ARCHIVOS ====================

function Select-FolderDialog {
    param([string]$Description = "Select a folder")
    Add-Type -AssemblyName System.Windows.Forms -ErrorAction SilentlyContinue
    $dialog = New-Object System.Windows.Forms.FolderBrowserDialog
    $dialog.Description = $Description
    $dialog.ShowNewFolderButton = $true
    if ($dialog.ShowDialog() -eq [System.Windows.Forms.DialogResult]::OK) { return $dialog.SelectedPath }
    return $null
}

function Select-FileDialog {
    param([string]$Title = "Selecciona un archivo")
    Add-Type -AssemblyName System.Windows.Forms -ErrorAction SilentlyContinue
    $dialog = New-Object System.Windows.Forms.OpenFileDialog
    $dialog.Title = $Title
    $dialog.Filter = "All files (*.*)|*.*"
    if ($dialog.ShowDialog() -eq [System.Windows.Forms.DialogResult]::OK) { return $dialog.FileName }
    return $null
}

function Get-PathFromUser {
    param([string]$Prompt = "RUTA", [string]$Mode = "any")
    Write-Host ""
    Write-Host "  DRAG, type a path, or use the explorer:" -ForegroundColor White
    Write-Host "      [E] Abrir explorador" -ForegroundColor Cyan
    Write-Host "      [B] Volver  [S] Salir" -ForegroundColor DarkGray
    Write-Host ""
    $userInput = Read-Host "      ${Prompt}"
    if ($userInput -eq "S" -or $userInput -eq "s") { return "EXIT" }
    if ($userInput -eq "B" -or $userInput -eq "b") { return "BACK" }
    if ($userInput -eq "E" -or $userInput -eq "e") {
        if ($Mode -eq "folder") {
            $path = Select-FolderDialog -Description "Selecciona carpeta"
        } else {
            Write-Host "      [1] Carpeta  [2] Archivo" -ForegroundColor White
            $tipo = Read-Host "      >"
            if ($tipo -eq "2") { $path = Select-FileDialog } else { $path = Select-FolderDialog }
        }
        if (-not $path) { return "BACK" }
        return $path
    }
    return Clean-Path $userInput
}

# ==================== PERFILES DE RESPALDO ====================

function Get-UserProfile {
    $userRoot = [Environment]::GetFolderPath("UserProfile")
    
    $profiles = @{
        "1" = @{
            Name = "RESPALDO COMPLETO DE USER"
            Desc = "Desktop + Documentos + Fotos + Videos + Descargas + Favoritos"
            Paths = @(
                (Join-Path $userRoot "Desktop"),
                (Join-Path $userRoot "Documents"),
                (Join-Path $userRoot "Pictures"),
                (Join-Path $userRoot "Videos"),
                (Join-Path $userRoot "Downloads"),
                (Join-Path $userRoot "Favorites")
            )
        }
        "2" = @{
            Name = "SOLO DOCUMENTOS Y ESCRITORIO"
            Desc = "Desktop + Documentos (lo mas critico)"
            Paths = @(
                (Join-Path $userRoot "Desktop"),
                (Join-Path $userRoot "Documents")
            )
        }
        "3" = @{
            Name = "FOTOS Y VIDEOS"
            Desc = "Pictures + Videos"
            Paths = @(
                (Join-Path $userRoot "Pictures"),
                (Join-Path $userRoot "Videos")
            )
        }
        "4" = @{
            Name = "OUTLOOK + CORREO"
            Desc = "PST/OST de Outlook + Signatures"
            Paths = @(
                (Join-Path $userRoot "Documents\Outlook Files"),
                (Join-Path $env:LOCALAPPDATA "Microsoft\Outlook"),
                (Join-Path $env:APPDATA "Microsoft\Signatures")
            )
        }
        "5" = @{
            Name = "NAVEGADORES (Favoritos/Bookmarks)"
            Desc = "Chrome + Edge + Firefox bookmarks"
            Paths = @(
                (Join-Path $env:LOCALAPPDATA "Google\Chrome\User Data\Default"),
                (Join-Path $env:LOCALAPPDATA "Microsoft\Edge\User Data\Default"),
                (Join-Path $env:APPDATA "Mozilla\Firefox\Profiles")
            )
        }
    }
    return $profiles
}

function Show-ProfileMenu {
    Write-Host ""
    Write-Centered "=== PERFILES DE RESPALDO RAPIDO ===" "DarkYellow"
    Write-Host ""
    
    $profiles = Get-UserProfile
    foreach ($key in ($profiles.Keys | Sort-Object)) {
        $p = $profiles[$key]
        Write-Host "      [${key}] $($p.Name)" -ForegroundColor White
        Write-Host "          $($p.Desc)" -ForegroundColor DarkGray
        
        # Contar carpetas que existen
        $existCount = ($p.Paths | Where-Object { Test-Path $_ }).Count
        $totalCount = $p.Paths.Count
        $existColor = if ($existCount -eq $totalCount) { "Green" } elseif ($existCount -gt 0) { "Yellow" } else { "Red" }
        Write-Host "          Carpetas: ${existCount}/${totalCount} found" -ForegroundColor $existColor
        Write-Host ""
    }
    
    Write-Host "      [B] Volver" -ForegroundColor DarkGray
    Write-Host ""
    $sel = Read-Host "      >"
    
    if ($sel -eq "B" -or $sel -eq "b") { return $null }
    if ($profiles.ContainsKey($sel)) {
        $selected = $profiles[$sel]
        $validPaths = @($selected.Paths | Where-Object { Test-Path $_ })
        if ($validPaths.Count -eq 0) {
            Write-Host "      [ERROR] No folder from profile exists." -ForegroundColor Red
            return $null
        }
        return @{ Name = $selected.Name; Paths = $validPaths }
    }
    Write-Host "      Option no valida." -ForegroundColor Red
    return $null
}

# ==================== MULTI-ORIGEN ====================

function Get-MultipleOrigins {
    $origins = @()
    Write-Host ""
    Write-Centered "=== MULTI-ORIGEN ===" "DarkYellow"
    Write-Host ""
    Write-Host "      Add folders/files one by one." -ForegroundColor DarkGray
    Write-Host "      Type [OK] when done." -ForegroundColor DarkGray
    
    while ($true) {
        Write-Host ""
        Write-Host "      Origenes agregados: $($origins.Count)" -ForegroundColor $(if ($origins.Count -gt 0) { "Green" } else { "Gray" })
        if ($origins.Count -gt 0) {
            foreach ($o in $origins) {
                $oName = Split-Path $o -Leaf
                Write-Host "        -> ${oName}" -ForegroundColor Cyan
            }
        }
        
        $pathResult = Get-PathFromUser -Prompt "ADD (or [OK] to continue)" -Mode "any"
        
        if ($pathResult -eq "EXIT") { return "EXIT" }
        if ($pathResult -eq "BACK") {
            if ($origins.Count -gt 0) { return $origins }
            return "BACK"
        }
        if ($pathResult -eq "OK" -or $pathResult -eq "ok") {
            if ($origins.Count -eq 0) {
                Write-Host "      [ERROR] Add at least one source." -ForegroundColor Red
                continue
            }
            return $origins
        }
        
        if (-not (Test-Path $pathResult)) {
            Write-Host "      [ERROR] No existe: ${pathResult}" -ForegroundColor Red
            continue
        }
        
        if ($origins -contains $pathResult) {
            Write-Host "      [!] Already in list." -ForegroundColor Yellow
            continue
        }
        
        $origins += $pathResult
        $itemName = Split-Path $pathResult -Leaf
        $itemType = if (Test-Path $pathResult -PathType Container) { "CARPETA" } else { "ARCHIVO" }
        Write-Host "      [+] ${itemType}: ${itemName}" -ForegroundColor Green
    }
}

# ==================== COMPARAR ANTES DE COPIAR ====================

function Compare-BeforeCopy {
    param([string[]]$Origins, [string]$Destino)
    
    Write-Host ""
    Write-Centered "ANALIZANDO DIFERENCIAS..." "Yellow"
    Write-Host ""
    
    $totalNew = 0; $totalModified = 0; $totalEqual = 0; $totalSizeNew = 0; $totalSizeMod = 0
    
    foreach ($origen in $Origins) {
        $srcName = Split-Path $origen -Leaf
        $isFile = -not (Test-Path $origen -PathType Container)
        
        if ($isFile) {
            $srcFile = Get-Item $origen
            $dstFile = Join-Path $Destino $srcFile.Name
            if (-not (Test-Path $dstFile)) {
                $totalNew++; $totalSizeNew += $srcFile.Length
            } elseif ($srcFile.LastWriteTime -gt (Get-Item $dstFile).LastWriteTime) {
                $totalModified++; $totalSizeMod += $srcFile.Length
            } else {
                $totalEqual++
            }
        } else {
            $dstSubFolder = Join-Path $Destino $srcName
            $srcFiles = Get-ChildItem -Path $origen -Recurse -File -ErrorAction SilentlyContinue
            
            foreach ($sf in $srcFiles) {
                $relPath = $sf.FullName.Substring($origen.Length).TrimStart('\')
                $df = Join-Path $dstSubFolder $relPath
                
                if (-not (Test-Path $df)) {
                    $totalNew++; $totalSizeNew += $sf.Length
                } elseif ($sf.LastWriteTime -gt (Get-Item $df -ErrorAction SilentlyContinue).LastWriteTime) {
                    $totalModified++; $totalSizeMod += $sf.Length
                } else {
                    $totalEqual++
                }
            }
        }
    }
    
    $totalTransfer = $totalSizeNew + $totalSizeMod
    
    Write-Host "    NUEVOS:      ${totalNew} archivos ($(Format-Size $totalSizeNew))" -ForegroundColor Green
    Write-Host "    MODIFICADOS: ${totalModified} archivos ($(Format-Size $totalSizeMod))" -ForegroundColor Yellow
    Write-Host "    EQUAL:       ${totalEqual} files (unchanged)" -ForegroundColor DarkGray
    Write-Host ""
    Write-Host "    TRANSFERIR:  $($totalNew + $totalModified) archivos ($(Format-Size $totalTransfer))" -ForegroundColor Cyan
    
    return @{
        New = $totalNew; Modified = $totalModified; Equal = $totalEqual
        SizeNew = $totalSizeNew; SizeModified = $totalSizeMod; SizeTotal = $totalTransfer
    }
}

# ==================== EXCLUSIONES ====================

function Get-Exclusions {
    Write-Host ""
    Write-Host "  [?] EXCLUSIONES:" -ForegroundColor Cyan
    Write-Host "      [1] None (copiar todo)" -ForegroundColor White
    Write-Host "      [2] Temporales (.tmp, .log, .bak, cache)" -ForegroundColor White
    Write-Host "      [3] ISOs y VMs (.iso, .vhd, .wim)" -ForegroundColor White
    Write-Host "      [4] Personalizado (escribir extensiones)" -ForegroundColor White
    Write-Host "      [B] Volver" -ForegroundColor DarkGray
    Write-Host ""
    $sel = Read-Host "      >"
    
    switch ($sel) {
        "2" {
            Write-Host "      [OK] Excluyendo temporales y cache" -ForegroundColor Green
            return @{ 
                Files = @("*.tmp", "*.log", "*.bak", "*.cache", "*.temp", "~*")
                Dirs = @("Temp", "tmp", "Cache", "__pycache__", "node_modules", ".git")
                Label = "Temporales/Cache"
            }
        }
        "3" {
            Write-Host "      [OK] Excluyendo ISOs y VMs" -ForegroundColor Green
            return @{
                Files = @("*.iso", "*.vhd", "*.vhdx", "*.wim", "*.esd", "*.vmdk")
                Dirs = @()
                Label = "ISOs/VMs"
            }
        }
        "4" {
            Write-Host "      Extensions separated by comma (e.g.: .mp4,.avi,.mkv):" -ForegroundColor White
            $custom = Read-Host "      >"
            if (-not [string]::IsNullOrWhiteSpace($custom)) {
                $exts = ($custom -split ',') | ForEach-Object {
                    $e = $_.Trim()
                    if ($e -notmatch '^\*') { $e = "*${e}" }
                    $e
                }
                Write-Host "      [OK] Excluyendo: $($exts -join ', ')" -ForegroundColor Green
                return @{ Files = $exts; Dirs = @(); Label = "Personalizado" }
            }
            return @{ Files = @(); Dirs = @(); Label = "None" }
        }
        "B" { return "BACK" }
        default { return @{ Files = @(); Dirs = @(); Label = "None" } }
    }
}

# ==================== NOTIFICACION ====================

function Send-Notification {
    param([string]$Title, [string]$Message, [bool]$Success = $true)
    
    # Sonido
    if ($Success) {
        [Console]::Beep(800, 200); [Console]::Beep(1000, 200); [Console]::Beep(1200, 300)
    } else {
        [Console]::Beep(400, 500); [Console]::Beep(300, 500)
    }
    
    # Toast notification de Windows
    try {
        Add-Type -AssemblyName System.Windows.Forms -ErrorAction Stop
        $notify = New-Object System.Windows.Forms.NotifyIcon
        $notify.Icon = [System.Drawing.SystemIcons]::Information
        $notify.BalloonTipTitle = $Title
        $notify.BalloonTipText = $Message
        $notify.BalloonTipIcon = if ($Success) { "Info" } else { "Error" }
        $notify.Visible = $true
        $notify.ShowBalloonTip(5000)
        
        Start-Sleep -Seconds 6
        $notify.Dispose()
    } catch {}
}

# ==================== RESUMEN EXPORTABLE ====================

function Export-CopyReport {
    param(
        [string[]]$Origins, [string]$Destino, [string]$Mode, [string]$DiskType,
        [hashtable]$Result, [hashtable]$Integrity, [hashtable]$Comparison,
        [string]$ExclusionLabel, [string]$Cliente
    )
    
    $reportFile = Join-Path ([Environment]::GetFolderPath("Desktop")) "Summary_Atlas_${Cliente}_$(Get-Date -Format 'yyyy-MM-dd_HHmm').txt"
    
    $r = @()
    $r += "================================================================"
    $r += "  ATLAS PC SUPPORT - COPY SUMMARY"
    $r += "================================================================"
    $r += ""
    $r += "DATE:        $(Get-Date -Format 'dd/MM/yyyy HH:mm:ss')"
    $r += "COMPUTER:    $env:COMPUTERNAME"
    $r += "USER:        $env:USERNAME"
    $r += "PROJECT:     ${Cliente}"
    $r += ""
    $r += "--- CONFIGURATION ---"
    $r += "ENGINE:      FastCopy"
    $r += "MODE:        ${Mode}"
    $r += "DISK:        ${DiskType}"
    $r += "EXCLUSIONS:  ${ExclusionLabel}"
    $r += ""
    $r += "--- SOURCES ---"
    foreach ($o in $Origins) { $r += "  -> ${o}" }
    $r += ""
    $r += "--- TARGET ---"
    $r += "  -> ${Destino}"
    $r += ""
    $r += "--- RESULT ---"
    $r += "STATUS:      $(if ($Result.OK) { 'SUCCESS' } else { 'WITH ERRORS' })"
    $r += "TIME:        $(Format-Duration $Result.Elapsed)"
    $r += "COPIED:      $(Format-Size $Result.BytesCopied)"
    $r += "SPEED:       $($Result.SpeedMBps) MB/s"
    
    if ($Comparison) {
        $r += ""
        $r += "--- PRE-COPY ANALYSIS ---"
        $r += "NEW:         $($Comparison.New) files"
        $r += "MODIFIED:    $($Comparison.Modified) files"
        $r += "EQUAL:       $($Comparison.Equal) files"
    }
    
    if ($Integrity) {
        $r += ""
        $r += "--- MD5 VERIFICATION ---"
        $r += "VERIFIED:    $($Integrity.Checked) files"
        $r += "OK:          $($Integrity.Passed)"
        $r += "FAILED:      $($Integrity.Failed)"
        $r += "MISSING:     $($Integrity.Missing)"
        $r += "RESULT:      $(if ($Integrity.OK) { 'INTEGRITY VERIFIED' } else { 'ISSUES DETECTED' })"
    }
    
    $r += ""
    $r += "--- LOG ---"
    $r += "FILE:        $(if ($Result.LogFile) { $Result.LogFile } else { 'N/A' })"
    $r += ""
    $r += "================================================================"
    $r += "  Generated by ATLAS PC SUPPORT - FastCopy v3"
    $r += "================================================================"
    
    ($r -join "`r`n") | Out-File -FilePath $reportFile -Encoding UTF8
    return $reportFile
}

# ==================== VERIFICACIÓN MD5 ====================

function Test-CopyIntegrity {
    param([string]$Origen, [string]$Destino, [int]$SampleSize = 15)
    Write-Host ""
    Write-Centered "VERIFYING MD5 INTEGRITY..." "Yellow"
    Write-Host ""

    $srcStats = Get-FolderStats $Origen
    $dstStats = Get-FolderStats $Destino
    Write-Host "    Files    - Source: $($srcStats.Files) | Target: $($dstStats.Files)" -ForegroundColor Gray
    Write-Host "    Size     - Source: $(Format-Size $srcStats.Size) | Target: $(Format-Size $dstStats.Size)" -ForegroundColor Gray

    $countMatch = ($srcStats.Files -eq $dstStats.Files)
    Write-Host "    Count:   $(if ($countMatch) { 'MATCH' } else { 'DIFFERENT (may be normal)' })" -ForegroundColor $(if ($countMatch) { "Green" } else { "Yellow" })

    $srcFiles = Get-ChildItem -Path $Origen -Recurse -File -ErrorAction SilentlyContinue
    if (-not $srcFiles -or $srcFiles.Count -eq 0) {
        Write-Host "    Sin archivos." -ForegroundColor Gray
        return @{ OK = $true; Checked = 0; Passed = 0; Failed = 0; Missing = 0 }
    }

    Write-Host ""; Write-Host "    Hash MD5 (muestra de ${SampleSize})..." -ForegroundColor DarkGray

    $bySize = $srcFiles | Sort-Object Length -Descending | Select-Object -First 5
    $byDate = $srcFiles | Sort-Object LastWriteTime -Descending | Select-Object -First 5
    $randomCount = [math]::Min([math]::Max(1, $SampleSize - 10), $srcFiles.Count)
    $random = $srcFiles | Get-Random -Count $randomCount
    $sample = @($bySize) + @($byDate) + @($random) | Sort-Object FullName -Unique | Select-Object -First $SampleSize

    $checked = 0; $passed = 0; $failed = 0; $missing = 0; $failedFiles = @()

    foreach ($sf in $sample) {
        $checked++
        $relPath = $sf.FullName.Substring($Origen.Length).TrimStart('\')
        $dstFile = Join-Path $Destino $relPath
        $pct = [math]::Round(($checked / $sample.Count) * 100, 0)
        Write-Host "`r    [${pct}%] ${checked}/$($sample.Count)..." -NoNewline -ForegroundColor DarkGray

        if (-not (Test-Path $dstFile)) { $missing++; $failedFiles += "FALTA: ${relPath}"; continue }
        try {
            $h1 = (Get-FileHash $sf.FullName -Algorithm MD5 -ErrorAction Stop).Hash
            $h2 = (Get-FileHash $dstFile -Algorithm MD5 -ErrorAction Stop).Hash
            if ($h1 -eq $h2) { $passed++ } else { $failed++; $failedFiles += "CORRUPTO: ${relPath}" }
        } catch { $failed++; $failedFiles += "ERROR: ${relPath}" }
    }

    Write-Host ""; Write-Host ""
    if ($failed -eq 0 -and $missing -eq 0) {
        Write-Host "    [OK] INTEGRIDAD: ${passed}/${checked} verificados" -ForegroundColor Green
    } else {
        Write-Host "    [!!] OK=${passed} | FALLOS=${failed} | FALTANTES=${missing}" -ForegroundColor Red
        foreach ($f in $failedFiles) { Write-Host "         $f" -ForegroundColor Red }
    }
    return @{ OK = ($failed -eq 0 -and $missing -eq 0); Checked = $checked; Passed = $passed; Failed = $failed; Missing = $missing }
}

# ==================== EJECUTAR FASTCOPY ====================

function Start-FastCopy {
    param(
        [string]$FastCopyExe, [string[]]$Origins, [string]$Destino,
        [string]$Mode, [string]$SpeedMode, [string]$DiskType,
        [array]$ExcludeFiles, [array]$ExcludeDirs
    )

    Write-Host ""
    Write-Centered "EJECUTANDO FASTCOPY (${DiskType} | ${Mode} | speed=${SpeedMode})" "Yellow"
    Write-Host ""

    $sw = [System.Diagnostics.Stopwatch]::StartNew()
    $allResults = @()
    $totalBytesCopied = 0
    $allOK = $true
    $logFile = Join-Path ([Environment]::GetFolderPath("Desktop")) "Log_FastCopy_$(Get-Date -Format 'yyyy-MM-dd_HHmm').log"

    foreach ($origen in $Origins) {
        $srcName = Split-Path $origen -Leaf
        Write-Host "    Copiando: ${srcName}..." -ForegroundColor Cyan
        
        $fcArgs = @()
        switch ($Mode) {
            "COMPLETA"    { $fcArgs += "/cmd=force_copy" }
            "INCREMENTAL" { $fcArgs += "/cmd=diff" }
            "MOVER"       { $fcArgs += "/cmd=move" }
            "SINCRONIZAR" { $fcArgs += "/cmd=sync" }
            default       { $fcArgs += "/cmd=force_copy" }
        }

        $fcArgs += "/speed=${SpeedMode}"
        $fcArgs += "/estimate"
        $fcArgs += "/auto_close"
        $fcArgs += "/error_stop=FALSE"
        $fcArgs += "/log"
        $fcArgs += "/logfile=`"${logFile}`""

        if (-not (Test-Path $Destino)) {
            New-Item -ItemType Directory -Path $Destino -Force | Out-Null
        }

        # Exclusiones
        if ($ExcludeFiles -and $ExcludeFiles.Count -gt 0) {
            $exclStr = ($ExcludeFiles -join ";")
            $fcArgs += "/exclude=`"${exclStr}`""
        }

        $fcArgs += "`"${origen}`""
        $fcArgs += "/to=`"${Destino}\`""

        $argString = $fcArgs -join " "

        $preSize = 0
        if (Test-Path $Destino) {
            try { $preSize = (Get-ChildItem $Destino -Recurse -File -ErrorAction SilentlyContinue | Measure-Object Length -Sum).Sum } catch {}
            if (-not $preSize) { $preSize = 0 }
        }

        $process = Start-Process -FilePath $FastCopyExe -ArgumentList $argString -PassThru -Wait
        $exitCode = $process.ExitCode

        $postSize = 0
        if (Test-Path $Destino) {
            try { $postSize = (Get-ChildItem $Destino -Recurse -File -ErrorAction SilentlyContinue | Measure-Object Length -Sum).Sum } catch {}
            if (-not $postSize) { $postSize = 0 }
        }
        $copied = [math]::Max(0, $postSize - $preSize)
        $totalBytesCopied += $copied

        if ($exitCode -ne 0) { $allOK = $false }

        $statusIcon = if ($exitCode -eq 0) { "[OK]" } else { "[!!]" }
        $statusColor = if ($exitCode -eq 0) { "Green" } else { "Red" }
        Write-Host "    ${statusIcon} ${srcName} - $(Format-Size $copied)" -ForegroundColor $statusColor
    }

    $sw.Stop(); $elapsed = $sw.Elapsed
    $speedMBps = if ($elapsed.TotalSeconds -gt 0) { [math]::Round(($totalBytesCopied / 1MB) / $elapsed.TotalSeconds, 1) } else { 0 }

    Write-Host ""
    Write-Host "    ========================================================" -ForegroundColor White
    $resultColor = if ($allOK) { "Green" } else { "Red" }
    $resultMsg = if ($allOK) { "COMPLETADO EXITOSAMENTE" } else { "COMPLETADO CON ERRORES - revisa el log" }
    Write-Host "    RESULTADO: ${resultMsg}" -ForegroundColor $resultColor
    Write-Host "    ========================================================" -ForegroundColor White
    Write-Host ""
    Write-Host "    Origenes:  $($Origins.Count)" -ForegroundColor Gray
    Write-Host "    Tiempo:    $(Format-Duration $elapsed)" -ForegroundColor Gray
    Write-Host "    Copiado:   $(Format-Size $totalBytesCopied)" -ForegroundColor Gray
    Write-Host "    Velocidad: ${speedMBps} MB/s" -ForegroundColor Gray
    Write-Host "    Log:       $(Split-Path $logFile -Leaf)" -ForegroundColor DarkGray

    return @{
        ExitCode = $(if ($allOK) { 0 } else { 1 }); OK = $allOK; Elapsed = $elapsed
        BytesCopied = $totalBytesCopied; SpeedMBps = $speedMBps; LogFile = $logFile
    }
}

# ==================== INICIO ====================

Clear-Host

$fastCopyExe = Find-FastCopy

if (-not $fastCopyExe) {
    Write-Host ""
    Write-Centered "============================================" "Red"
    Write-Centered "FASTCOPY NO ENCONTRADO" "Red"
    Write-Centered "============================================" "Red"
    Write-Host ""
    Write-Host "    Searched in:" -ForegroundColor DarkGray
    Write-Host "    - Script folder ($PSScriptRoot)" -ForegroundColor DarkGray
    Write-Host "    - Program Files" -ForegroundColor DarkGray
    Write-Host "    - System PATH" -ForegroundColor DarkGray
    Write-Host "    - $env:LOCALAPPDATA\AtlasPC\apps\FastCopy" -ForegroundColor DarkGray
    Write-Host ""
    Write-Host "    Options:" -ForegroundColor Yellow
    Write-Host "      [D] Download automatically from fastcopy.jp (recommended)" -ForegroundColor White
    Write-Host "      [S] Salir e instalarlo manualmente" -ForegroundColor White
    Write-Host ""
    $choice = Read-Host "    Seleccion [D/S]"

    if ($choice -match '^[Dd]$') {
        Write-Host ""
        Write-Host "    Downloading FastCopy..." -ForegroundColor Cyan
        try {
            $fastCopyExe = Install-FastCopyAuto
            Write-Host ""
            Write-Host "    FastCopy installed: $fastCopyExe" -ForegroundColor Green
            Start-Sleep -Seconds 1
        } catch {
            Write-Host ""
            Write-Host "    Download ERROR: $($_.Exception.Message)" -ForegroundColor Red
            Write-Host "    Descarga manual: https://fastcopy.jp" -ForegroundColor Yellow
            Read-Host "    ENTER to exit"
            return
        }
    } else {
        Write-Host "    Open https://fastcopy.jp and place FastCopy.exe at:" -ForegroundColor Gray
        Write-Host "      $env:LOCALAPPDATA\AtlasPC\apps\FastCopy\" -ForegroundColor Gray
        Read-Host "    ENTER to exit"
        return
    }
}

# ==================== BUCLE PRINCIPAL ====================

do {
    Clear-Host
    Write-Host "`n"
    Write-Centered "==========================================================" "Cyan"
    Write-Centered "|       ATLAS PC SUPPORT - FASTCOPY EDITION v3           |" "Yellow"
    Write-Centered "==========================================================" "Cyan"
    Write-Host ""
    Write-Host "    Motor: $(Split-Path $fastCopyExe -Leaf)" -ForegroundColor DarkGray
    Write-Host ""
    Write-Centered "[ 1 ] Copia normal (un origen)" "White"
    Write-Centered "[ 2 ] Multi-origen (varias carpetas)" "White"
    Write-Centered "[ 3 ] Perfil rapido (respaldo de user)" "Cyan"
    Write-Centered "[ S ] Salir" "DarkGray"
    Write-Host ""
    
    $menuSel = Read-Host "      >"
    if ($menuSel -eq "S" -or $menuSel -eq "s") { exit }

    # =============================================
    # OBTENER ORIGENES
    # =============================================
    $origenes = @()
    $isMulti = $false
    $isProfile = $false
    $profileName = ""

    switch ($menuSel) {
        "1" {
            # Un only origen
            :askSingle while ($true) {
                Write-Host ""
                Write-Host "  [1] ORIGEN:" -ForegroundColor White
                $pathResult = Get-PathFromUser -Prompt "ORIGEN" -Mode "any"
                if ($pathResult -eq "EXIT") { exit }
                if ($pathResult -eq "BACK") { break }
                if (-not (Test-Path $pathResult)) {
                    Write-Host "      [ERROR] No existe: ${pathResult}" -ForegroundColor Red
                    continue
                }
                $origenes = @($pathResult)
                break
            }
        }
        "2" {
            $multiResult = Get-MultipleOrigins
            if ($multiResult -eq "EXIT") { exit }
            if ($multiResult -eq "BACK") { continue }
            $origenes = @($multiResult)
            $isMulti = $true
        }
        "3" {
            $profile = Show-ProfileMenu
            if (-not $profile) { continue }
            $origenes = @($profile.Paths)
            $isProfile = $true
            $profileName = $profile.Name
        }
        default { continue }
    }

    if ($origenes.Count -eq 0) { continue }

    # Mostrar origenes selecteds
    Write-Host ""
    $totalSize = 0; $totalFiles = 0
    foreach ($o in $origenes) {
        $oName = Split-Path $o -Leaf
        if (Test-Path $o -PathType Container) {
            $stats = Get-FolderStats $o
            $totalSize += $stats.Size; $totalFiles += $stats.Files
            Write-Host "      [OK] ${oName} ($($stats.Files) archivos, $(Format-Size $stats.Size))" -ForegroundColor Green
        } else {
            $fi = Get-Item $o
            $totalSize += $fi.Length; $totalFiles++
            Write-Host "      [OK] ${oName} ($(Format-Size $fi.Length))" -ForegroundColor Green
        }
    }
    $srcStats = @{ Files = $totalFiles; Size = $totalSize; SizeMB = [math]::Round($totalSize / 1MB, 1) }
    Write-Host ""
    Write-Host "      TOTAL: ${totalFiles} archivos | $(Format-Size $totalSize)" -ForegroundColor White

    # =============================================
    # DESTINO
    # =============================================
    $destino = $null; $driveInfo = $null

    :askDest while ($true) {
        Write-Host ""
        Write-Host "  [2] DESTINO:" -ForegroundColor White
        $pathResult = Get-PathFromUser -Prompt "DESTINO" -Mode "folder"
        if ($pathResult -eq "EXIT") { exit }
        if ($pathResult -eq "BACK") { break }
        if (-not (Test-Path $pathResult)) {
            Write-Host "      [ERROR] No accesible: ${pathResult}" -ForegroundColor Red
            continue
        }

        # Validar que ningun origen sea el destino
        $conflict = $false
        foreach ($o in $origenes) {
            try {
                $fO = (Resolve-Path $o).Path; $fD = (Resolve-Path $pathResult).Path
                if ($fO -eq $fD) { Write-Host "      [ERROR] Origen = Target: $o" -ForegroundColor Red; $conflict = $true; break }
            } catch {}
        }
        if ($conflict) { continue }

        $destDriveLetter = $pathResult.Substring(0, 1)
        $driveInfo = Detect-DriveType $destDriveLetter
        $labelDisplay = if ($driveInfo.Label) { " ($($driveInfo.Label))" } else { "" }
        Write-Host "      [OK] Disk: $($driveInfo.Desc)${labelDisplay}" -ForegroundColor $driveInfo.Color
        Write-Host "      Libre: $(Format-Size $driveInfo.FreeBytes)" -ForegroundColor Gray

        if ($driveInfo.FreeBytes -gt 0 -and $totalSize -gt $driveInfo.FreeBytes) {
            Write-Host "      [!!!] ESPACIO INSUFICIENTE" -ForegroundColor Red
            Write-Host "      Necesitas: $(Format-Size $totalSize) | Disponible: $(Format-Size $driveInfo.FreeBytes)" -ForegroundColor Red
            Write-Host "      [F] Forzar  [B] Volver" -ForegroundColor Yellow
            $espOp = Read-Host "      >"
            if ($espOp -ne "F" -and $espOp -ne "f") { continue }
        }
        $destino = $pathResult; break
    }
    if (-not $destino) { continue }

    # =============================================
    # NOMBRE
    # =============================================
    Write-Host ""
    Write-Host "  [3] Project name (ENTER = Backup):" -ForegroundColor White
    $cliente = Read-Host "      NOMBRE"
    if ([string]::IsNullOrWhiteSpace($cliente)) {
        if ($isProfile) { $cliente = $profileName -replace '\s+', '_' }
        else { $cliente = "Respaldo" }
    }
    $cliente = $cliente -replace '[\\/:*?"<>|]', '_'
    $fechaHoy = Get-Date -Format 'yyyy-MM-dd'
    $rutaFinal = Join-Path $destino "${cliente}_${fechaHoy}"

    # =============================================
    # MODO
    # =============================================
    Write-Host ""
    Write-Host "  [4] MODO DE COPIA:" -ForegroundColor Cyan
    Write-Host "      [1] COMPLETA     - Copia todo" -ForegroundColor White
    Write-Host "      [2] INCREMENTAL  - Only nuevos/modificados" -ForegroundColor White
    Write-Host "      [3] SINCRONIZAR  - Espejo exacto" -ForegroundColor White
    Write-Host "      [4] MOVER        - Mueve (borra origen)" -ForegroundColor Red
    Write-Host "      [B] Volver" -ForegroundColor DarkGray
    Write-Host ""
    $modoSel = Read-Host "      >"
    if ($modoSel -eq "B" -or $modoSel -eq "b") { continue }
    $modo = switch ($modoSel) {
        "2" { "INCREMENTAL" }
        "3" { "SINCRONIZAR" }
        "4" {
            Write-Host "      [!!!] Will delete files from SOURCE. Sure? [Y/N]" -ForegroundColor Red
            $mc = Read-Host "      >"
            if ($mc -match '^[SsYy]$') { "MOVER" } else { "SKIP" }
        }
        default { "COMPLETA" }
    }
    if ($modo -eq "SKIP") { continue }

    # =============================================
    # EXCLUSIONES
    # =============================================
    $exclusions = @{ Files = @(); Dirs = @(); Label = "None" }
    if ($origenes.Count -ge 1) {
        $exclResult = Get-Exclusions
        if ($exclResult -eq "BACK") { continue }
        if ($exclResult) { $exclusions = $exclResult }
    }

    # =============================================
    # COMPARAR (only incremental o si hay destino previo)
    # =============================================
    $comparison = $null
    if (Test-Path $rutaFinal) {
        Write-Host ""
        Write-Host "      Destino ya existe. Analizar diferencias? [Y/N]" -ForegroundColor Yellow
        $compSel = Read-Host "      >"
        if ($compSel -match '^[SsYy]$') {
            $comparison = Compare-BeforeCopy -Origins $origenes -Destino $rutaFinal
        }
    }

    # =============================================
    # PREVIEW
    # =============================================
    Clear-Host
    Write-Host "`n"
    Write-Centered "==================== PREVIEW ====================" "White"
    Write-Host ""
    
    if ($isProfile) {
        Write-Host "    PERFIL:    ${profileName}" -ForegroundColor Cyan
    }
    Write-Host "    ORIGENES:  $($origenes.Count)" -ForegroundColor Gray
    foreach ($o in $origenes) {
        Write-Host "               $(Split-Path $o -Leaf)" -ForegroundColor White
    }
    Write-Host "    TOTAL:     ${totalFiles} archivos | $(Format-Size $totalSize)" -ForegroundColor Gray
    Write-Host ""
    Write-Host "    DESTINO:   ${rutaFinal}" -ForegroundColor White
    Write-Host "    DISCO:     $($driveInfo.Desc)" -ForegroundColor $driveInfo.Color
    Write-Host "    MODO:      ${modo}" -ForegroundColor $(if ($modo -eq "MOVER") { "Red" } elseif ($modo -eq "SINCRONIZAR") { "Yellow" } else { "Cyan" })
    Write-Host "    SPEED:     $($driveInfo.Speed) (auto)" -ForegroundColor Gray
    Write-Host "    EXCLUIR:   $($exclusions.Label)" -ForegroundColor DarkGray

    if ($comparison) {
        Write-Host ""
        Write-Host "    ANALISIS:  $($comparison.New) nuevos, $($comparison.Modified) modificados, $($comparison.Equal) iguales" -ForegroundColor Cyan
        Write-Host "    TRANSFERIR: $(Format-Size $comparison.SizeTotal)" -ForegroundColor Cyan
    }

    $avgSpeed = switch ($driveInfo.Type) { "USB" { 30 } "HDD" { 100 } "SSD" { 400 } default { 50 } }
    $estSize = if ($comparison) { $comparison.SizeTotal } else { $totalSize }
    if ($estSize -gt 0) {
        $etaSec = ($estSize / 1MB) / $avgSpeed
        $etaSpan = [TimeSpan]::FromSeconds($etaSec)
        Write-Host "    ETA:       ~$(Format-Duration $etaSpan)" -ForegroundColor DarkGray
    }

    if ($modo -eq "MOVER") { Write-Host ""; Write-Host "    [!!!] ARCHIVOS SE ELIMINARAN DEL ORIGEN" -ForegroundColor Red }
    if ($modo -eq "SINCRONIZAR") { Write-Host ""; Write-Host "    [!] Extras en destino seran ELIMINADOS" -ForegroundColor Yellow }

    Write-Host ""
    Write-Centered "=================================================" "White"
    Write-Host ""
    Write-Host "    [S] INICIAR  [B] Volver  [N] Cancelar" -ForegroundColor White
    Write-Host ""
    $confirmar = Read-Host "    >"
    if ($confirmar -ne "S" -and $confirmar -ne "s") { continue }

    # =============================================
    # EJECUTAR
    # =============================================
    Clear-Host
    Write-Host "`n"

    $result = Start-FastCopy -FastCopyExe $fastCopyExe -Origins $origenes -Destino $rutaFinal `
        -Mode $modo -SpeedMode $driveInfo.Speed -DiskType $driveInfo.Type `
        -ExcludeFiles $exclusions.Files -ExcludeDirs $exclusions.Dirs

    # NOTIFICACION
    $notifMsg = "$(Format-Size $result.BytesCopied) en $(Format-Duration $result.Elapsed) a $($result.SpeedMBps) MB/s"
    if ($result.OK) {
        Send-Notification -Title "Atlas - Copia Completada" -Message $notifMsg -Success $true
    } else {
        Send-Notification -Title "Atlas - Copy with Errors" -Message "Revisa el log" -Success $false
    }

    # =============================================
    # VERIFICACION MD5
    # =============================================
    $integrity = $null
    if ($result.OK -and $modo -ne "MOVER") {
        Write-Host ""
        Write-Host "    Verificar integridad MD5? [Y/N]" -ForegroundColor DarkGray
        $verSel = Read-Host "    >"
        if ($verSel -match '^[SsYy]$') {
            # Verificar el primer origen (el más importante)
            $integrity = Test-CopyIntegrity -Origen $origenes[0] -Destino $rutaFinal
        }
    }

    # =============================================
    # POST-COPIA
    # =============================================
    :postMenu while ($true) {
        Write-Host ""
        Write-Host "    --------------------------------------------------------" -ForegroundColor DarkGray
        Write-Host "    [A] Abrir carpeta destino" -ForegroundColor Cyan
        Write-Host "    [R] REPEAT with another target" -ForegroundColor Green
        Write-Host "    [X] Export summary for ticket" -ForegroundColor Yellow
        Write-Host "    [N] Nueva copia" -ForegroundColor White
        Write-Host "    [L] Ver log" -ForegroundColor DarkGray
        Write-Host "    [S] Salir" -ForegroundColor DarkGray
        Write-Host "    --------------------------------------------------------" -ForegroundColor DarkGray
        Write-Host ""
        $postOp = Read-Host "    >"

        switch ($postOp.ToUpper()) {
            "A" {
                if (Test-Path $rutaFinal) { Invoke-Item $rutaFinal }
                else { Write-Host "    No found." -ForegroundColor Red }
            }
            "R" {
                Write-Host ""
                $newPath = Get-PathFromUser -Prompt "DESTINO" -Mode "folder"
                if ($newPath -eq "BACK" -or $newPath -eq "EXIT" -or -not $newPath) { continue }
                if (-not (Test-Path $newPath)) { Write-Host "    No accesible." -ForegroundColor Red; continue }

                $newDriveInfo = Detect-DriveType ($newPath.Substring(0, 1))
                $newRutaFinal = Join-Path $newPath "${cliente}_${fechaHoy}"
                $newLabel = if ($newDriveInfo.Label) { " ($($newDriveInfo.Label))" } else { "" }
                Write-Host "    Disk: $($newDriveInfo.Desc)${newLabel}" -ForegroundColor $newDriveInfo.Color
                Write-Host "    Target: ${newRutaFinal}" -ForegroundColor White
                Write-Host "    [S] Copiar  [N] Cancelar" -ForegroundColor White
                $rc = Read-Host "    >"

                if ($rc -match '^[SsYy]$') {
                    Clear-Host; Write-Host "`n"
                    $r2 = Start-FastCopy -FastCopyExe $fastCopyExe -Origins $origenes -Destino $newRutaFinal `
                        -Mode $modo -SpeedMode $newDriveInfo.Speed -DiskType $newDriveInfo.Type `
                        -ExcludeFiles $exclusions.Files -ExcludeDirs $exclusions.Dirs
                    
                    $n2Msg = "$(Format-Size $r2.BytesCopied) en $(Format-Duration $r2.Elapsed)"
                    Send-Notification -Title "Atlas - Copia $(if ($r2.OK) {'OK'} else {'Error'})" -Message $n2Msg -Success $r2.OK

                    if ($r2.OK -and $modo -ne "MOVER") {
                        Write-Host "    Verificar MD5? [Y/N]" -ForegroundColor DarkGray
                        $v2 = Read-Host "    >"
                        if ($v2 -match '^[SsYy]$') { Test-CopyIntegrity -Origen $origenes[0] -Destino $newRutaFinal | Out-Null }
                    }
                }
            }
            "X" {
                $reportFile = Export-CopyReport -Origins $origenes -Destino $rutaFinal -Mode $modo `
                    -DiskType $driveInfo.Type -Result $result -Integrity $integrity `
                    -Comparison $comparison -ExclusionLabel $exclusions.Label -Cliente $cliente
                Write-Host "    [OK] Summary: $(Split-Path $reportFile -Leaf)" -ForegroundColor Green
                Write-Host "    Ready to attach to ticket." -ForegroundColor Cyan
                
                Write-Host "    Abrir? [Y/N]" -ForegroundColor DarkGray
                $openReport = Read-Host "    >"
                if ($openReport -match '^[SsYy]$') { Start-Process notepad $reportFile }
            }
            "N" { break }
            "L" {
                if ($result.LogFile -and (Test-Path $result.LogFile)) { Start-Process notepad $result.LogFile }
                else { Write-Host "    Log no found." -ForegroundColor Red }
            }
            "S" { exit }
        }
        if ($postOp -eq "N" -or $postOp -eq "n") { break }
    }

} while ($true)
}


# ---- tools\Invoke-GestorBitLocker.ps1 ----
# ============================================================
# Invoke-GestorBitLocker
# Migrado de: GestorBitLocker.ps1
# Atlas PC Support — v1.0
# ============================================================

function Invoke-GestorBitLocker {
    [CmdletBinding()]
    param(
        [ValidateSet("Extract","Status","")]
        [string]$Action = "",
        [string]$Output = "",
        [string]$MountPoint = ""
    )
# =======================================================
# Gestor de BitLocker v3 - Atlas PC Support
# TPM + Progreso + Backup USB + QR + Health Check + Log
# AD/Azure backup + CLI mode + Alerta disks sin proteger
# =======================================================

# (auto-elevación gestionada por Atlas Launcher)


[console]::BackgroundColor = "Black"
[console]::ForegroundColor = "Gray"
$Host.UI.RawUI.WindowTitle = "ATLAS PC SUPPORT - BitLocker Manager v3"
try { $Host.UI.RawUI.WindowSize = New-Object System.Management.Automation.Host.Size(105, 48) } catch {}

# Log file
$logFile = Join-Path $PSScriptRoot "ATLAS_bitlocker.log"

# ==================== FUNCIONES BASE ====================

function Write-Log {
    param([string]$Message, [string]$Level = "INFO")
    $timestamp = Get-Date -Format 'yyyy-MM-dd HH:mm:ss'
    $user = "$env:USERDOMAIN\$env:USERNAME"
    $pc = $env:COMPUTERNAME
    $entry = "${timestamp} | ${Level} | ${pc} | ${user} | ${Message}"
    try { $entry | Out-File -FilePath $script:logFile -Append -Encoding UTF8 } catch {}
}

function Escribir-Centrado {
    param([string]$Texto, [ConsoleColor]$Color = "Gray")
    $AnchoVentana = $Host.UI.RawUI.WindowSize.Width
    if ($Texto.Length -lt $AnchoVentana) {
        $Espacios = [Math]::Floor(($AnchoVentana - $Texto.Length) / 2)
        Write-Host (" " * $Espacios + $Texto) -ForegroundColor $Color
    } else {
        Write-Host $Texto -ForegroundColor $Color
    }
}

function Show-DiskTable {
    param([switch]$OnlyEncrypted, [switch]$Silent)
    
    $volumes = Get-BitLockerVolume -ErrorAction SilentlyContinue
    if (-not $volumes) {
        if (-not $Silent) { Write-Host "    Could not access BitLocker." -ForegroundColor Red }
        return $null
    }
    
    if ($OnlyEncrypted) {
        $volumes = $volumes | Where-Object { $_.VolumeStatus -ne 'FullyDecrypted' }
        if (-not $volumes) {
            if (-not $Silent) { Write-Host "    No disks with BitLocker active." -ForegroundColor Yellow }
            return $null
        }
    }
    
    if (-not $Silent) {
        Write-Host ""
        Write-Host "    DISK    STATUS                  ENCRYPTED    SIZE      METHOD" -ForegroundColor DarkGray
        Write-Host "    -----   ------                  ----------   ------    ------" -ForegroundColor DarkGray
        
        foreach ($v in $volumes) {
            $mount = $v.MountPoint
            $status = $v.VolumeStatus.ToString()
            $pct = "$($v.EncryptionPercentage)%"
            $capGB = if ($v.CapacityGB) { "{0:N1} GB" -f $v.CapacityGB } else { "N/A" }
            $method = if ($v.EncryptionMethod) { $v.EncryptionMethod.ToString() } else { "-" }
            
            $statusColor = switch ($status) {
                "FullyEncrypted" { "Green" }
                "FullyDecrypted" { "Gray" }
                "EncryptionInProgress" { "Yellow" }
                "DecryptionInProgress" { "Yellow" }
                default { "White" }
            }
            $statusLabel = switch ($status) {
                "FullyEncrypted" { "ENCRYPTED" }
                "FullyDecrypted" { "FREE" }
                "EncryptionInProgress" { "ENCRYPTING..." }
                "DecryptionInProgress" { "DECRYPTING..." }
                default { $status }
            }
            $icon = switch ($status) {
                "FullyEncrypted" { "[X]" }
                "FullyDecrypted" { "[ ]" }
                "EncryptionInProgress" { "[~]" }
                "DecryptionInProgress" { "[~]" }
                default { "[?]" }
            }
            
            Write-Host "    ${icon} ${mount}" -NoNewline -ForegroundColor $statusColor
            Write-Host ("   " + $statusLabel.PadRight(24)) -NoNewline -ForegroundColor $statusColor
            Write-Host ($pct.PadRight(13)) -NoNewline -ForegroundColor White
            Write-Host ($capGB.PadRight(10)) -NoNewline -ForegroundColor Gray
            Write-Host $method -ForegroundColor DarkGray
        }
        Write-Host ""
    }
    return $volumes
}

function Validate-DriveLetter {
    param([string]$Input, [array]$ValidVolumes)
    if ([string]::IsNullOrWhiteSpace($Input)) { return $null }
    $clean = $Input.Trim().ToUpper().Replace(":", "")
    if ($clean.Length -ne 1 -or $clean -notmatch "^[A-Z]$") {
        Write-Host "    Invalid letter. Use a single letter (e.g.: C, D, E)." -ForegroundColor Red
        return $null
    }
    $disk = "${clean}:"
    $found = $ValidVolumes | Where-Object { $_.MountPoint -eq $disk }
    if (-not $found) {
        Write-Host "    El disk ${disk} no existe." -ForegroundColor Red
        return $null
    }
    return @{ Letter = $disk; Volume = $found }
}

function Get-TPMStatus {
    $result = @{ HasTPM = $false; IsReady = $false; Version = "N/A"; Summary = "" }
    try {
        $tpm = Get-Tpm -ErrorAction Stop
        $result.HasTPM = $tpm.TpmPresent
        $result.IsReady = $tpm.TpmReady
        try {
            $tpmWMI = Get-CimInstance -Namespace "root\cimv2\Security\MicrosoftTpm" -ClassName Win32_Tpm -ErrorAction Stop
            if ($tpmWMI.SpecVersion) { $result.Version = ($tpmWMI.SpecVersion -split ',')[0].Trim() }
        } catch { }
        if ($result.HasTPM -and $result.IsReady) { $result.Summary = "TPM $($result.Version) presente y listo" }
        elseif ($result.HasTPM) { $result.Summary = "TPM present but NOT ready" }
        else { $result.Summary = "No TPM detected" }
    } catch { $result.Summary = "Could not query TPM" }
    return $result
}

function Show-EncryptionProgress {
    param([string]$MountPoint, [string]$Mode = "Encrypting")
    $label = if ($Mode -eq "Encrypting") { "ENCRYPTING" } else { "DECRYPTING" }
    $color = if ($Mode -eq "Encrypting") { "Cyan" } else { "Magenta" }
    Write-Host ""
    Escribir-Centrado "Monitoring (CTRL+C to leave running in background)..." "DarkGray"
    Write-Host ""
    $lastPct = -1
    try {
        while ($true) {
            $vol = Get-BitLockerVolume -MountPoint $MountPoint -ErrorAction SilentlyContinue
            if (-not $vol) { break }
            $pct = $vol.EncryptionPercentage; $status = $vol.VolumeStatus.ToString()
            if ($pct -ne $lastPct) {
                $barWidth = 40; $filled = [math]::Floor($pct / 100 * $barWidth); $empty = $barWidth - $filled
                $bar = ("#" * $filled) + ("-" * $empty)
                Write-Host "`r    ${label} ${MountPoint}: [${bar}] ${pct}%   " -NoNewline -ForegroundColor $color
                $lastPct = $pct
            }
            if ($status -eq "FullyEncrypted" -or $status -eq "FullyDecrypted") {
                Write-Host ""; Write-Host ""
                $doneMsg = if ($Mode -eq "Encrypting") { "Encryption complete." } else { "Decryption complete." }
                Escribir-Centrado $doneMsg "Green"
                Write-Log "${doneMsg} Disk: ${MountPoint}"
                break
            }
            Start-Sleep -Seconds 3
        }
    } catch { Write-Host ""; Write-Host ""; Escribir-Centrado "Monitoring stopped. Continues in background." "Yellow" }
}

# ==================== HEALTH CHECK PRE-ENCRIPTACION ====================

function Test-PreEncryptionHealth {
    param([string]$MountPoint)
    
    $issues = @(); $warnings = @(); $canProceed = $true
    $driveLetter = $MountPoint.TrimEnd(':')
    
    Write-Host ""
    Escribir-Centrado "PRE-ENCRYPTION HEALTH CHECK" "Yellow"
    Write-Host ""
    
    # 1. BATERIA (critico en laptops)
    Write-Host "    [1/5] Battery..." -NoNewline -ForegroundColor DarkGray
    $battery = Get-CimInstance Win32_Battery -ErrorAction SilentlyContinue
    if ($battery) {
        $charge = $battery.EstimatedChargeRemaining
        $plugged = $battery.BatteryStatus -eq 2
        if ($charge -lt 30 -and -not $plugged) {
            $issues += "BATERIA CRITICA: ${charge}% sin cargador. Conecta el cargador antes de encriptar."
            $canProceed = $false
            Write-Host " FALLO (${charge}%)" -ForegroundColor Red
        } elseif ($charge -lt 50 -and -not $plugged) {
            $warnings += "Battery al ${charge}%. Se recomienda conectar el cargador."
            Write-Host " WARNING (${charge}%)" -ForegroundColor Yellow
        } elseif ($plugged) {
            Write-Host " OK (${charge}%, cargador conectado)" -ForegroundColor Green
        } else {
            Write-Host " OK (${charge}%)" -ForegroundColor Green
        }
    } else {
        Write-Host " N/A (desktop)" -ForegroundColor Gray
    }
    
    # 2. ESPACIO EN DISCO
    Write-Host "    [2/5] Disk space..." -NoNewline -ForegroundColor DarkGray
    $logDisk = Get-CimInstance Win32_LogicalDisk -ErrorAction SilentlyContinue | Where-Object { $_.DeviceID -eq $MountPoint }
    if ($logDisk) {
        $freeGB = [math]::Round($logDisk.FreeSpace / 1GB, 1)
        $totalGB = [math]::Round($logDisk.Size / 1GB, 1)
        $usedPct = [math]::Round((($logDisk.Size - $logDisk.FreeSpace) / $logDisk.Size) * 100, 0)
        if ($freeGB -lt 1) {
            $issues += "DISCO CASI LLENO: Only ${freeGB}GB libre. BitLocker necesita espacio para metadatos."
            $canProceed = $false
            Write-Host " FALLO (${freeGB}GB libre)" -ForegroundColor Red
        } elseif ($usedPct -gt 95) {
            $warnings += "Disk al ${usedPct}% de capacidad. Recomendado liberar espacio."
            Write-Host " WARNING (${usedPct}%)" -ForegroundColor Yellow
        } else {
            Write-Host " OK (${freeGB}GB libre de ${totalGB}GB)" -ForegroundColor Green
        }
    } else {
        Write-Host " N/A" -ForegroundColor Gray
    }
    
    # 3. ESTADO SMART DEL DISCO
    Write-Host "    [3/5] Disk health (SMART)..." -NoNewline -ForegroundColor DarkGray
    try {
        $partition = Get-Partition -DriveLetter $driveLetter -ErrorAction Stop
        $physDisk = Get-PhysicalDisk -ErrorAction SilentlyContinue | Where-Object { $_.DeviceId -eq $partition.DiskNumber.ToString() }
        if (-not $physDisk) {
            $physDisk = Get-PhysicalDisk -ErrorAction SilentlyContinue | Select-Object -First 1
        }
        if ($physDisk) {
            $health = $physDisk.HealthStatus.ToString()
            if ($health -ne "Healthy") {
                $issues += "DISCO CON PROBLEMAS: Estado SMART = ${health}. Encriptar un disk danado puede causar perdida total."
                $canProceed = $false
                Write-Host " FALLO (${health})" -ForegroundColor Red
            } else {
                $opStatus = if ($physDisk.OperationalStatus) { $physDisk.OperationalStatus.ToString() } else { "OK" }
                Write-Host " OK (${health}, ${opStatus})" -ForegroundColor Green
            }
        } else {
            Write-Host " No verificable" -ForegroundColor Yellow
        }
    } catch {
        Write-Host " No verificable" -ForegroundColor Yellow
    }
    
    # 4. SISTEMA DE ARCHIVOS
    Write-Host "    [4/5] File system..." -NoNewline -ForegroundColor DarkGray
    try {
        $vol = Get-Volume -DriveLetter $driveLetter -ErrorAction Stop
        $fs = if ($vol.FileSystem) { $vol.FileSystem } else { "Desconocido" }
        if ($fs -ne "NTFS" -and $fs -ne "ReFS") {
            $issues += "SISTEMA DE ARCHIVOS INCOMPATIBLE: ${fs}. BitLocker requiere NTFS o ReFS."
            $canProceed = $false
            Write-Host " FALLO (${fs})" -ForegroundColor Red
        } else {
            Write-Host " OK (${fs})" -ForegroundColor Green
        }
    } catch {
        Write-Host " No verificable" -ForegroundColor Yellow
    }
    
    # 5. PROCESOS CRITICOS
    Write-Host "    [5/5] Critical processes..." -NoNewline -ForegroundColor DarkGray
    $chkdsk = Get-Process -Name "chkdsk" -ErrorAction SilentlyContinue
    $defrag = Get-Process -Name "defrag" -ErrorAction SilentlyContinue
    if ($chkdsk -or $defrag) {
        $procName = if ($chkdsk) { "chkdsk" } else { "defrag" }
        $warnings += "${procName} en execution. Espera a que termine antes de encriptar."
        Write-Host " WARNING (${procName} activo)" -ForegroundColor Yellow
    } else {
        Write-Host " OK" -ForegroundColor Green
    }
    
    # RESUMEN
    Write-Host ""
    if ($issues.Count -gt 0) {
        Escribir-Centrado "CRITICAL ISSUES (not recommended to continue):" "Red"
        foreach ($issue in $issues) { Write-Host "    [X] ${issue}" -ForegroundColor Red }
    }
    if ($warnings.Count -gt 0) {
        Write-Host ""
        Escribir-Centrado "WARNINGS:" "Yellow"
        foreach ($warn in $warnings) { Write-Host "    [!] ${warn}" -ForegroundColor Yellow }
    }
    if ($issues.Count -eq 0 -and $warnings.Count -eq 0) {
        Escribir-Centrado "ALL CHECKS PASSED" "Green"
    }
    
    Write-Log "HealthCheck ${MountPoint}: Issues=${issues.Count}, Warnings=${warnings.Count}, CanProceed=${canProceed}"
    
    return @{ CanProceed = $canProceed; Issues = $issues; Warnings = $warnings }
}

# ==================== ALERTA DISCOS SIN PROTEGER ====================

function Show-UnprotectedAlert {
    $allVols = Get-BitLockerVolume -ErrorAction SilentlyContinue
    if (-not $allVols) { return }
    
    $unprotected = @()
    foreach ($v in $allVols) {
        # Only alertar disks del sistema y datos (no removibles)
        $driveLetter = $v.MountPoint.TrimEnd(':')
        try {
            $volInfo = Get-Volume -DriveLetter $driveLetter -ErrorAction SilentlyContinue
            if ($volInfo -and $volInfo.DriveType -eq 'Fixed' -and $v.VolumeStatus -eq 'FullyDecrypted') {
                $capGB = if ($v.CapacityGB) { "{0:N0}" -f $v.CapacityGB } else { "?" }
                $unprotected += "${driveLetter}: (${capGB}GB)"
            }
        } catch { }
    }
    
    if ($unprotected.Count -gt 0) {
        Write-Host ""
        $alertLine = "ALERTA: $($unprotected.Count) disk(s) fijo(s) UNPROTECTED: $($unprotected -join ', ')"
        Escribir-Centrado $alertLine "Red"
    }
}

# ==================== GENERAR QR ====================

function Generate-QRCode {
    param([string]$Data, [string]$OutputPath, [string]$Label = "")
    
    # Generar QR como HTML con tabla (funciona sin dependencias externas)
    # Usa una representación simple que se puede imprimir
    
    $qrSize = 21  # QR Version 1
    
    # Método alternativo: generar imagen BMP usando .NET
    try {
        Add-Type -AssemblyName System.Drawing -ErrorAction Stop
        
        $cellSize = 10
        $margin = 40
        $textHeight = if ($Label) { 60 } else { 0 }
        
        # Generar patrón QR simplificado (encode como texto legible en imagen)
        $lines = @()
        $lines += "ATLAS PC SUPPORT"
        $lines += "BITLOCKER RECOVERY KEY"
        $lines += ""
        if ($Label) { $lines += $Label; $lines += "" }
        
        # Dividir la clave en grupos legibles
        $lines += "CLAVE:"
        if ($Data.Length -gt 20) {
            $chunks = [regex]::Matches($Data, '.{1,12}') | ForEach-Object { $_.Value }
            foreach ($chunk in $chunks) { $lines += "  $chunk" }
        } else {
            $lines += "  $Data"
        }
        $lines += ""
        $lines += "Date: $(Get-Date -Format 'dd/MM/yyyy')"
        $lines += "PC: $env:COMPUTERNAME"
        
        # Crear imagen
        $imgWidth = 500
        $lineHeight = 22
        $imgHeight = ($lines.Count * $lineHeight) + 80
        
        $bmp = New-Object System.Drawing.Bitmap($imgWidth, $imgHeight)
        $gfx = [System.Drawing.Graphics]::FromImage($bmp)
        $gfx.Clear([System.Drawing.Color]::White)
        
        # Borde
        $pen = New-Object System.Drawing.Pen([System.Drawing.Color]::Black, 2)
        $gfx.DrawRectangle($pen, 5, 5, $imgWidth - 10, $imgHeight - 10)
        
        # Texto
        $fontTitle = New-Object System.Drawing.Font("Consolas", 14, [System.Drawing.FontStyle]::Bold)
        $fontNormal = New-Object System.Drawing.Font("Consolas", 12)
        $fontKey = New-Object System.Drawing.Font("Consolas", 13, [System.Drawing.FontStyle]::Bold)
        $brush = [System.Drawing.Brushes]::Black
        $brushRed = [System.Drawing.Brushes]::DarkRed
        
        $y = 20
        foreach ($line in $lines) {
            $font = $fontNormal
            $b = $brush
            if ($line -match "^ATLAS|^BITLOCKER") { $font = $fontTitle }
            if ($line -match "^\s{2}\d" -or $line -match "^\s{2}[A-F0-9]") { $font = $fontKey; $b = $brushRed }
            $gfx.DrawString($line, $font, $b, 20, $y)
            $y += $lineHeight
        }
        
        $gfx.Dispose()
        $bmp.Save($OutputPath, [System.Drawing.Imaging.ImageFormat]::Png)
        $bmp.Dispose()
        
        return $true
    } catch {
        # Fallback: guardar como texto formateado para imprimir
        $txtPath = $OutputPath -replace '\.png$', '.txt'
        $border = "+" + ("-" * 48) + "+"
        $content = @()
        $content += $border
        $content += "|  ATLAS PC SUPPORT - BITLOCKER RECOVERY KEY    |"
        $content += $border
        if ($Label) { $content += "|  ${Label}".PadRight(49) + "|" }
        $content += "|  CLAVE:".PadRight(49) + "|"
        $content += "|  ${Data}".PadRight(49) + "|"
        $content += "|  PC: $env:COMPUTERNAME | $(Get-Date -Format 'dd/MM/yyyy')".PadRight(49) + "|"
        $content += $border
        $content += "  Cut out and stick on the computer case."
        
        $content -join "`r`n" | Out-File -FilePath $txtPath -Encoding UTF8
        return $txtPath
    }
}

# ==================== BACKUP A AD / AZURE ====================

function Backup-KeyToAD {
    param([string]$MountPoint)
    
    $vol = Get-BitLockerVolume -MountPoint $MountPoint -ErrorAction SilentlyContinue
    if (-not $vol) { return $false }
    
    $recoveryKeys = $vol.KeyProtector | Where-Object { $_.KeyProtectorType -eq 'RecoveryPassword' }
    if (-not $recoveryKeys) {
        Write-Host "    No recovery keys to back up." -ForegroundColor Yellow
        return $false
    }
    
    $success = $false
    
    foreach ($key in $recoveryKeys) {
        $keyId = $key.KeyProtectorId
        
        # Intentar AD On-Premise
        Write-Host "    Trying backup to Active Directory..." -ForegroundColor DarkGray
        try {
            Backup-BitLockerKeyProtector -MountPoint $MountPoint -KeyProtectorId $keyId -ErrorAction Stop
            Write-Host "    [OK] Key backed up to Active Directory." -ForegroundColor Green
            Write-Log "AD Backup OK: ${MountPoint} KeyID: ${keyId}"
            $success = $true
        } catch {
            $adError = $_.Exception.Message
            if ($adError -match "not joined|domain|directory") {
                Write-Host "    [--] Computer is not joined to AD domain." -ForegroundColor DarkGray
            } else {
                Write-Host "    [--] AD not available: $adError" -ForegroundColor DarkGray
            }
        }
        
        # Intentar Azure AD
        Write-Host "    Trying backup to Azure AD / Entra ID..." -ForegroundColor DarkGray
        try {
            $dsregStatus = dsregcmd /status 2>&1
            $isAzureJoined = ($dsregStatus | Select-String "AzureAdJoined\s*:\s*YES" -Quiet)
            
            if ($isAzureJoined) {
                BackupToAAD-BitLockerKeyProtector -MountPoint $MountPoint -KeyProtectorId $keyId -ErrorAction Stop
                Write-Host "    [OK] Key backed up to Azure AD / Entra ID." -ForegroundColor Green
                Write-Log "Azure AD Backup OK: ${MountPoint} KeyID: ${keyId}"
                $success = $true
            } else {
                Write-Host "    [--] Computer is not joined to Azure AD." -ForegroundColor DarkGray
            }
        } catch {
            Write-Host "    [--] Azure AD not available." -ForegroundColor DarkGray
        }
    }
    
    return $success
}

# ==================== MODO CLI ====================

if ($Action -ne "") {
    switch ($Action) {
        "Extract" {
            $VolumenesBL = Get-BitLockerVolume -ErrorAction SilentlyContinue | Where-Object { $_.VolumeStatus -ne 'FullyDecrypted' }
            if (-not $VolumenesBL) { Write-Host "No protected disks."; exit 1 }
            
            $outputPath = if ($Output) { $Output } else { Join-Path ([Environment]::GetFolderPath("Desktop")) "BL_$env:COMPUTERNAME_$(Get-Date -Format 'yyyyMMdd_HHmm').txt" }
            
            $content = "ATLAS PC SUPPORT - BITLOCKER KEYS`r`nPC: $env:COMPUTERNAME`r`nDate: $(Get-Date)`r`n---`r`n"
            foreach ($Vol in $VolumenesBL) {
                $keys = $Vol.KeyProtector | Where-Object { $_.KeyProtectorType -eq 'RecoveryPassword' }
                foreach ($k in $keys) {
                    $content += "$($Vol.MountPoint) -> $($k.RecoveryPassword)`r`n"
                    Write-Host "$($Vol.MountPoint) -> $($k.RecoveryPassword)"
                }
            }
            $content | Out-File -FilePath $outputPath -Encoding UTF8
            Write-Host "Saved to: ${outputPath}"
            Write-Log "CLI Extract: ${outputPath}"
            return
        }
        "Status" {
            $vols = Get-BitLockerVolume -ErrorAction SilentlyContinue
            foreach ($v in $vols) {
                $status = $v.VolumeStatus.ToString()
                $pct = $v.EncryptionPercentage
                Write-Host "$($v.MountPoint) | ${status} | ${pct}%"
            }
            return
        }
    }
}

# ==================== MENU PRINCIPAL ====================

Clear-Host

while ($true) {
    Clear-Host
    Write-Host "`n"
    Escribir-Centrado "===================================================" "DarkGray"
    Escribir-Centrado "|                                                 |" "DarkYellow"
    Escribir-Centrado "|               ATLAS PC SUPPORT                  |" "DarkYellow"
    Escribir-Centrado "|             GESTOR BITLOCKER v3                  |" "DarkYellow"
    Escribir-Centrado "|                                                 |" "DarkYellow"
    Escribir-Centrado "===================================================" "DarkGray"
    
    # TPM status
    Write-Host ""
    $tpmInfo = Get-TPMStatus
    $tpmColor = if ($tpmInfo.HasTPM -and $tpmInfo.IsReady) { "Green" } elseif ($tpmInfo.HasTPM) { "Yellow" } else { "Red" }
    Escribir-Centrado "TPM: $($tpmInfo.Summary)" $tpmColor
    
    # Disks protegidos
    $blVolumes = Get-BitLockerVolume -ErrorAction SilentlyContinue | Where-Object { $_.VolumeStatus -ne 'FullyDecrypted' }
    $blCount = if ($blVolumes) { @($blVolumes).Count } else { 0 }
    Escribir-Centrado "Disks protegidos: ${blCount}" $(if ($blCount -gt 0) { "Cyan" } else { "DarkGray" })
    
    # ALERTA DISCOS SIN PROTEGER
    Show-UnprotectedAlert
    
    Write-Host ""
    Escribir-Centrado "[ 1 ] Escanear y Guardar Claves" "White"
    Escribir-Centrado "[ 2 ] Activar BitLocker" "White"
    Escribir-Centrado "[ 3 ] Desactivar BitLocker" "White"
    Escribir-Centrado "[ 4 ] Ver Estado Completo" "White"
    Escribir-Centrado "[ 5 ] Ver Historial de Operaciones" "White"
    Escribir-Centrado "[ S ] Salir" "DarkGray"
    Write-Host ""
    Escribir-Centrado "===================================================" "DarkGray"
    Write-Host ""
    
    $Option = Read-Host "  Option"

    switch ($Option.ToUpper()) {
        # =============================================
        # 1. EXTRAER CLAVES (+ USB + QR + AD + Clipboard)
        # =============================================
        "1" {
            Clear-Host
            Write-Host "`n"
            Escribir-Centrado "=== EXTRACCION DE CLAVES BITLOCKER ===" "DarkYellow"
            Write-Host ""
            
            $NombreComputer = $env:COMPUTERNAME
            $UserActual = $env:USERNAME
            $FechaHora = Get-Date -Format 'dd-MM-yyyy_HHmm'
            $NombreArchivo = "BL_${NombreComputer}_${FechaHora}.txt"
            
            Write-Host "    Scanning disks protegidos..." -ForegroundColor DarkGray
            $VolumenesBL = Get-BitLockerVolume -ErrorAction SilentlyContinue | Where-Object { $_.VolumeStatus -ne 'FullyDecrypted' }
            
            if (-not $VolumenesBL) {
                Escribir-Centrado "No disks with BitLocker active found." "Red"
            } else {
                $Contenido = "===================================================`r`n"
                $Contenido += "      ATLAS PC SUPPORT - RESPALDO DE BITLOCKER`r`n"
                $Contenido += "===================================================`r`n"
                $Contenido += "Fecha               : $(Get-Date -Format 'dd/MM/yyyy HH:mm:ss')`r`n"
                $Contenido += "Nombre del Computer   : ${NombreComputer}`r`n"
                $Contenido += "User Activo      : ${UserActual}`r`n"
                $Contenido += "---------------------------------------------------`r`n`r`n"
                
                $ClavesEncontradas = 0
                $clavesParaClipboard = @()
                $clavesParaQR = @()
                
                foreach ($Vol in $VolumenesBL) {
                    $Claves = $Vol.KeyProtector | Where-Object { $_.KeyProtectorType -eq 'RecoveryPassword' }
                    if ($Claves) {
                        foreach ($Clave in $Claves) {
                            $mount = $Vol.MountPoint
                            $key = $Clave.RecoveryPassword
                            $keyId = $Clave.KeyProtectorId
                            
                            $Contenido += "UNIDAD: ${mount}`r`n"
                            $Contenido += "ID:     ${keyId}`r`n"
                            $Contenido += "CLAVE:  ${key}`r`n`r`n"
                            
                            $clavesParaClipboard += "${mount} -> ${key}"
                            $clavesParaQR += @{ Mount = $mount; Key = $key; KeyId = $keyId }
                            
                            Write-Host "    [OK] ${mount} -> ${key}" -ForegroundColor Green
                            $ClavesEncontradas++
                        }
                    }
                }
                
                if ($ClavesEncontradas -eq 0) {
                    Escribir-Centrado "No se encontraron recovery keys." "Red"
                } else {
                    $Contenido += "===================================================`r`n"
                    $Contenido += "TOTAL: ${ClavesEncontradas} clave(s)`r`n"
                    
                    Write-Host ""
                    Escribir-Centrado "${ClavesEncontradas} clave(s) found(s)" "Green"
                    Write-Log "Extraccion: ${ClavesEncontradas} claves de ${NombreComputer}"
                    
                    $rutasGuardadas = @()
                    
                    # Guardar en desktop
                    $RutaDesktop = [Environment]::GetFolderPath("Desktop")
                    $RutaCompleta = Join-Path $RutaDesktop $NombreArchivo
                    try {
                        $Contenido | Out-File -FilePath $RutaCompleta -Encoding UTF8
                        Write-Host "    [OK] Desktop: ${NombreArchivo}" -ForegroundColor Cyan
                        $rutasGuardadas += $RutaCompleta
                    } catch { Write-Host "    [ERROR] Could not save to desktop." -ForegroundColor Red }
                    
                    # USB
                    $usbs = Get-Volume -ErrorAction SilentlyContinue | Where-Object { $_.DriveType -eq 'Removable' -and $_.DriveLetter -and $_.Size -gt 0 }
                    if ($usbs) {
                        Write-Host ""
                        Write-Host "    USB detectado(s). Guardar copia? [Y/N]" -ForegroundColor Yellow
                        $usbSel = Read-Host "    >"
                        if ($usbSel -match '^[SsYy]$') {
                            foreach ($u in $usbs) {
                                try {
                                    $usbPath = Join-Path ($u.DriveLetter + ":\") $NombreArchivo
                                    $Contenido | Out-File -FilePath $usbPath -Encoding UTF8
                                    Write-Host "    [OK] USB $($u.DriveLetter): ${NombreArchivo}" -ForegroundColor Green
                                    $rutasGuardadas += $usbPath
                                } catch { Write-Host "    [ERROR] USB $($u.DriveLetter): $($_.Exception.Message)" -ForegroundColor Red }
                            }
                        }
                    }
                    
                    # QR / Imagen imprimible
                    Write-Host ""
                    Write-Host "    Generate printable image of keys? [Y/N]" -ForegroundColor Yellow
                    $qrSel = Read-Host "    >"
                    if ($qrSel -match '^[SsYy]$') {
                        foreach ($kInfo in $clavesParaQR) {
                            $qrFileName = "BL_KEY_${NombreComputer}_$($kInfo.Mount.TrimEnd(':'))_${FechaHora}.png"
                            $qrPath = Join-Path $RutaDesktop $qrFileName
                            $label = "Disk: $($kInfo.Mount) | PC: ${NombreComputer}"
                            $qrResult = Generate-QRCode -Data $kInfo.Key -OutputPath $qrPath -Label $label
                            if ($qrResult -eq $true) {
                                Write-Host "    [OK] Imagen: ${qrFileName}" -ForegroundColor Green
                                $rutasGuardadas += $qrPath
                            } elseif ($qrResult) {
                                Write-Host "    [OK] Texto imprimible: $(Split-Path $qrResult -Leaf)" -ForegroundColor Green
                                $rutasGuardadas += $qrResult
                            } else {
                                Write-Host "    [ERROR] No se genero imagen." -ForegroundColor Red
                            }
                        }
                        Write-Host ""
                        Escribir-Centrado "Print the image and stick it on the computer case." "Cyan"
                    }
                    
                    # AD / Azure AD backup
                    Write-Host ""
                    Write-Host "    Intentar backup a Active Directory / Azure AD? [Y/N]" -ForegroundColor Yellow
                    $adSel = Read-Host "    >"
                    if ($adSel -match '^[SsYy]$') {
                        foreach ($Vol in $VolumenesBL) {
                            $adOk = Backup-KeyToAD -MountPoint $Vol.MountPoint
                        }
                    }
                    
                    # Clipboard
                    Write-Host ""
                    Write-Host "    Copy keys to clipboard? [Y/N]" -ForegroundColor DarkGray
                    $clipSel = Read-Host "    >"
                    if ($clipSel -match '^[SsYy]$') {
                        try {
                            ($clavesParaClipboard -join "`r`n") | Set-Clipboard
                            Write-Host "    [OK] Copied to clipboard." -ForegroundColor Green
                        } catch { Write-Host "    [ERROR] Clipboard no disponible." -ForegroundColor Red }
                    }
                    
                    # Summary
                    Write-Host ""
                    Escribir-Centrado "RESUMEN DE BACKUPS:" "White"
                    foreach ($ruta in $rutasGuardadas) { Write-Host "    -> ${ruta}" -ForegroundColor Gray }
                }
            }
            Write-Host "`n"; Read-Host "    ENTER to go back..."
        }

        # =============================================
        # 2. ACTIVAR BITLOCKER (con Health Check)
        # =============================================
        "2" {
            Clear-Host
            Write-Host "`n"
            Escribir-Centrado "=== ACTIVAR BITLOCKER ===" "DarkYellow"
            Write-Host ""
            
            # TPM check
            $tpm = Get-TPMStatus
            $tpmColor = if ($tpm.HasTPM -and $tpm.IsReady) { "Green" } elseif ($tpm.HasTPM) { "Yellow" } else { "Red" }
            Write-Host "    TPM: $($tpm.Summary)" -ForegroundColor $tpmColor
            
            if (-not $tpm.HasTPM) {
                Write-Host "    No TPM = password required at every boot." -ForegroundColor Yellow
                Write-Host ""
                Write-Host "    [C] Continue with password  [B] Back" -ForegroundColor White
                $tpmChoice = Read-Host "    >"
                if ($tpmChoice -ne "C" -and $tpmChoice -ne "c") { continue }
            } elseif (-not $tpm.IsReady) {
                Write-Host "    May require activation in BIOS." -ForegroundColor Yellow
            }
            
            Write-Host ""
            $allVolumes = Show-DiskTable
            if (-not $allVolumes) { Read-Host "    ENTER to go back..."; continue }
            
            Write-Host "    Disk to encrypt (or [B] to go back):" -ForegroundColor White
            $input = Read-Host "    >"
            if ($input -eq "B" -or $input -eq "b") { continue }
            
            $validated = Validate-DriveLetter -Input $input -ValidVolumes $allVolumes
            if (-not $validated) { Read-Host "    ENTER to go back..."; continue }
            
            $disk = $validated.Letter; $vol = $validated.Volume
            
            if ($vol.VolumeStatus -eq 'FullyEncrypted') {
                Write-Host "    ${disk} YA esta encriptado." -ForegroundColor Yellow
                Read-Host "    ENTER to go back..."; continue
            }
            if ($vol.VolumeStatus -eq 'EncryptionInProgress') {
                Write-Host "    ${disk} ya se esta encriptando." -ForegroundColor Yellow
                Show-EncryptionProgress -MountPoint $disk -Mode "Encrypting"
                Read-Host "    ENTER to go back..."; continue
            }
            
            # HEALTH CHECK
            $health = Test-PreEncryptionHealth -MountPoint $disk
            
            if (-not $health.CanProceed) {
                Write-Host ""
                Escribir-Centrado "NO SE RECOMIENDA ENCRIPTAR EN ESTE ESTADO." "Red"
                Write-Host ""
                Write-Host "    [F] Force anyway  [B] Back (recommended)" -ForegroundColor Yellow
                $forceChoice = Read-Host "    >"
                if ($forceChoice -ne "F" -and $forceChoice -ne "f") {
                    Write-Log "Encryption cancelled por HealthCheck: ${disk}"
                    continue
                }
                Write-Log "HealthCheck FORZADO por user: ${disk}"
            }
            
            # Confirmación
            $capGB = if ($vol.CapacityGB) { "{0:N1}" -f $vol.CapacityGB } else { "?" }
            Write-Host ""
            Escribir-Centrado "CONFIRMAR: Activar BitLocker en ${disk} (${capGB} GB)?" "Yellow"
            Write-Host "    [S] Encriptar  [N] Cancelar" -ForegroundColor White
            $confirm = Read-Host "    >"
            if ($confirm -ne "S" -and $confirm -ne "s") { continue }
            
            Write-Host ""
            Write-Host "    Activating BitLocker on ${disk}..." -ForegroundColor Yellow
            
            try {
                if ($tpm.HasTPM -and $tpm.IsReady) {
                    Enable-BitLocker -MountPoint $disk -EncryptionMethod XtsAes256 -RecoveryPasswordProtector -ErrorAction Stop
                } else {
                    Write-Host "    Enter boot password:" -ForegroundColor Cyan
                    $secPwd = Read-Host "    Password" -AsSecureString
                    Enable-BitLocker -MountPoint $disk -EncryptionMethod XtsAes256 -PasswordProtector -Password $secPwd -ErrorAction Stop
                    Add-BitLockerKeyProtector -MountPoint $disk -RecoveryPasswordProtector -ErrorAction Stop
                }
                
                Write-Host ""
                Escribir-Centrado "BitLocker ACTIVADO en ${disk}" "Green"
                Escribir-Centrado "USA OPCION [1] PARA GUARDAR LA CLAVE!" "Cyan"
                Write-Log "BitLocker ACTIVADO: ${disk} (XtsAes256)"
                
                # AD backup automatico
                Write-Host ""
                Backup-KeyToAD -MountPoint $disk
                
                Write-Host ""
                Write-Host "    [M] Monitorear progreso  [ENTER] Volver" -ForegroundColor DarkGray
                $monSel = Read-Host "    >"
                if ($monSel -eq "M" -or $monSel -eq "m") {
                    Show-EncryptionProgress -MountPoint $disk -Mode "Encrypting"
                }
            } catch {
                Write-Host "    [ERROR] $($_.Exception.Message)" -ForegroundColor Red
                Write-Log "ERROR activando BitLocker ${disk}: $($_.Exception.Message)" "ERROR"
                
                $msg = $_.Exception.Message
                if ($msg -match "TPM") {
                    Write-Host "    SUGGESTION: Enable TPM in BIOS." -ForegroundColor Yellow
                }
                if ($msg -match "policy|Group Policy") {
                    Write-Host "    SUGERENCIA: gpedit.msc > Computer Config > Admin Templates > BitLocker" -ForegroundColor Yellow
                }
            }
            Write-Host ""; Read-Host "    ENTER to go back..."
        }

        # =============================================
        # 3. DESACTIVAR BITLOCKER
        # =============================================
        "3" {
            Clear-Host
            Write-Host "`n"
            Escribir-Centrado "=== DESACTIVAR BITLOCKER ===" "DarkYellow"
            Write-Host ""
            
            $encVolumes = Show-DiskTable -OnlyEncrypted
            if (-not $encVolumes) { Read-Host "    ENTER to go back..."; continue }
            
            Write-Host "    Disk a desencriptar (o [B]):" -ForegroundColor White
            $input = Read-Host "    >"
            if ($input -eq "B" -or $input -eq "b") { continue }
            
            $validated = Validate-DriveLetter -Input $input -ValidVolumes $encVolumes
            if (-not $validated) { Read-Host "    ENTER to go back..."; continue }
            
            $disk = $validated.Letter; $vol = $validated.Volume
            
            if ($vol.VolumeStatus -eq 'DecryptionInProgress') {
                Write-Host "    Already being decrypted." -ForegroundColor Yellow
                Show-EncryptionProgress -MountPoint $disk -Mode "Decrypting"
                Read-Host "    ENTER to go back..."; continue
            }
            
            $capGB = if ($vol.CapacityGB) { "{0:N1}" -f $vol.CapacityGB } else { "?" }
            Write-Host ""
            Escribir-Centrado "CONFIRMAR: Desactivar BitLocker en ${disk} (${capGB} GB)?" "Red"
            Write-Host "    WARNING: Data will be left unprotected." -ForegroundColor Yellow
            Write-Host "    [S] Desencriptar  [N] Cancelar" -ForegroundColor White
            $confirm = Read-Host "    >"
            if ($confirm -ne "S" -and $confirm -ne "s") { continue }
            
            try {
                Disable-BitLocker -MountPoint $disk -ErrorAction Stop
                Escribir-Centrado "Decryption iniciada en ${disk}." "Green"
                Write-Log "BitLocker DESACTIVADO: ${disk}"
                
                Write-Host "    [M] Monitorear  [ENTER] Volver" -ForegroundColor DarkGray
                $monSel = Read-Host "    >"
                if ($monSel -eq "M" -or $monSel -eq "m") {
                    Show-EncryptionProgress -MountPoint $disk -Mode "Decrypting"
                }
            } catch {
                Write-Host "    [ERROR] $($_.Exception.Message)" -ForegroundColor Red
                Write-Log "ERROR desactivando ${disk}: $($_.Exception.Message)" "ERROR"
            }
            Write-Host ""; Read-Host "    ENTER to go back..."
        }

        # =============================================
        # 4. ESTADO COMPLETO
        # =============================================
        "4" {
            Clear-Host
            Write-Host "`n"
            Escribir-Centrado "=== ESTADO COMPLETO ===" "DarkYellow"
            Write-Host ""
            
            $tpm = Get-TPMStatus
            $tpmColor = if ($tpm.HasTPM -and $tpm.IsReady) { "Green" } elseif ($tpm.HasTPM) { "Yellow" } else { "Red" }
            Write-Host "    TPM: $($tpm.Summary)" -ForegroundColor $tpmColor
            
            Show-DiskTable | Out-Null
            
            # Alerta
            Show-UnprotectedAlert
            
            # Protectores
            Write-Host ""
            Write-Host "    PROTECTORES ACTIVOS:" -ForegroundColor DarkGray
            Write-Host "    --------------------" -ForegroundColor DarkGray
            $allVols = Get-BitLockerVolume -ErrorAction SilentlyContinue
            $hasProtectors = $false
            foreach ($v in $allVols) {
                if ($v.VolumeStatus -ne 'FullyDecrypted' -and $v.KeyProtector) {
                    foreach ($kp in $v.KeyProtector) {
                        $kpType = $kp.KeyProtectorType.ToString()
                        $kpId = if ($kp.KeyProtectorId) { $kp.KeyProtectorId.Substring(0, [math]::Min(20, $kp.KeyProtectorId.Length)) + "..." } else { "" }
                        $typeLabel = switch ($kpType) {
                            "RecoveryPassword" { "Clave Recovery" }
                            "Tpm" { "TPM" }
                            "TpmPin" { "TPM + PIN" }
                            "Password" { "Password" }
                            "ExternalKey" { "Llave Externa" }
                            default { $kpType }
                        }
                        Write-Host "    $($v.MountPoint) -> ${typeLabel} ${kpId}" -ForegroundColor Gray
                        $hasProtectors = $true
                    }
                }
            }
            if (-not $hasProtectors) { Write-Host "    (none)" -ForegroundColor DarkGray }
            
            Write-Host "`n"; Read-Host "    ENTER to go back..."
        }

        # =============================================
        # 5. HISTORIAL
        # =============================================
        "5" {
            Clear-Host
            Write-Host "`n"
            Escribir-Centrado "=== HISTORIAL DE OPERACIONES ===" "DarkYellow"
            Write-Host ""
            
            if (Test-Path $logFile) {
                $logContent = Get-Content $logFile -Tail 50 -ErrorAction SilentlyContinue
                if ($logContent) {
                    Write-Host "    Last operations (max 50):" -ForegroundColor DarkGray
                    Write-Host "    " + ("-" * 80) -ForegroundColor DarkGray
                    Write-Host ""
                    foreach ($line in $logContent) {
                        $lineColor = "Gray"
                        if ($line -match "ERROR") { $lineColor = "Red" }
                        elseif ($line -match "ACTIVADO") { $lineColor = "Green" }
                        elseif ($line -match "DESACTIVADO") { $lineColor = "Yellow" }
                        elseif ($line -match "Extraccion|Extract") { $lineColor = "Cyan" }
                        elseif ($line -match "FORZADO") { $lineColor = "Red" }
                        Write-Host "    ${line}" -ForegroundColor $lineColor
                    }
                } else {
                    Write-Host "    Log vacio." -ForegroundColor DarkGray
                }
            } else {
                Write-Host "    No hay historial aun." -ForegroundColor DarkGray
                Write-Host "    Created automatically with each operation." -ForegroundColor DarkGray
            }
            
            Write-Host ""
            Write-Host "    File: ${logFile}" -ForegroundColor DarkGray
            Write-Host ""
            Write-Host "    [L] Limpiar historial  [ENTER] Volver" -ForegroundColor DarkGray
            $logAction = Read-Host "    >"
            if ($logAction -eq "L" -or $logAction -eq "l") {
                Write-Host "    Seguro? [Y/N]" -ForegroundColor Yellow
                $logConfirm = Read-Host "    >"
                if ($logConfirm -match '^[SsYy]$') {
                    Remove-Item $logFile -Force -ErrorAction SilentlyContinue
                    Write-Host "    Historial limpiado." -ForegroundColor Green
                    Start-Sleep 1
                }
            }
        }

        "S" {
            Write-Host ""
            Escribir-Centrado "Cerrando..." "DarkYellow"
            Write-Log "Sesion cerrada"
            Start-Sleep -Seconds 1
            [console]::ResetColor()
            Clear-Host
            return
        }

        default {
            Escribir-Centrado "Option no valida." "Red"
            Start-Sleep -Seconds 1
        }
    }
}
}


# ---- tools\Invoke-HostsManager.ps1 ----
# ============================================================
# Invoke-HostsManager  ->  Hosts File Editor
#
# i18n: Option A (en default + full es secondary). Function name
# kept as Invoke-HostsManager for tools.json compatibility.
#
# Atlas PC Support
# ============================================================

function Invoke-HostsManager {
    [CmdletBinding()]
    param()

    # --- Language detection ---
    function _Atlas-DetectLang {
        if ($env:ATLAS_LANG) { return [string]$env:ATLAS_LANG }
        try {
            $cfg = Join-Path $env:LOCALAPPDATA 'AtlasPC\config.json'
            if (Test-Path -LiteralPath $cfg) {
                $obj = Get-Content -Raw -LiteralPath $cfg -Encoding UTF8 | ConvertFrom-Json
                if ($obj.language) { return [string]$obj.language }
            }
        } catch {}
        $sys = (Get-Culture).TwoLetterISOLanguageName
        if ($sys -eq 'es') { return 'es' }
        return 'en'
    }

    $T = @{
        en = @{
            WinTitle      = 'ATLAS PC SUPPORT - HOSTS FILE EDITOR'
            Header        = 'ATLAS PC SUPPORT - HOSTS FILE EDITOR'
            PathLabel     = 'Path:  {0}'
            AdminLabel    = 'Admin: {0}'
            AdminYes      = 'YES'
            AdminNo       = 'NO (writes will fail)'
            Options       = 'Options:'
            Opt1          = '[1] View current contents'
            Opt2          = '[2] Backup with timestamp'
            Opt3          = '[3] Add entry (IP + name)'
            Opt4          = '[4] Remove lines containing a name'
            Opt5          = '[5] Open in Notepad (admin)'
            Opt6          = '[6] Restore default (auto-backup first)'
            OptAdv        = '--- ADVANCED ---'
            Opt7          = '[7] Export hosts to Desktop'
            Opt8          = '[8] Import hosts from file (with backup)'
            Opt9          = '[9] Apply StevenBlack ads/tracking (separate, with backup)'
            OptR          = '[R] Revert StevenBlack (restore pre-application)'
            OptQ          = '[Q] Quit'
            SelectPrompt  = 'Selection'
            NotExist      = '(does not exist)'
            EnterCont     = 'Enter to continue'
            BackupCreated = 'Backup created: {0}'
            ErrPrefix     = 'Error: {0}'
            IPLabel       = 'IP'
            NameLabel     = 'Host name'
            Added         = 'Added: {0}  {1}'
            ErrAdmin      = 'Error (need admin?): {0}'
            CancelEmpty   = 'Cancelled (empty IP or name).'
            DelPrompt     = 'Name to remove (lines containing it)'
            Removed       = 'Removed {0} line(s) containing "{1}".'
            NotepadOpen   = 'Notepad opened (in elevated window).'
            ConfirmReset  = 'This OVERWRITES hosts. Confirm? [y/N]'
            Restored      = 'hosts restored. Previous backup at: {0}'
            ErrAdmin2     = 'Error (need admin): {0}'
            Exported      = 'Exported: {0}'
            ImportPrompt  = 'Full path of hosts file to import (drag into CMD and Enter)'
            FileNotFound  = 'File not found.'
            ConfirmImport = 'This will OVERWRITE current hosts (a backup will be made). Confirm? [y/N]'
            Imported      = 'Imported. Previous backup: {0}'
            SBHeader      = '=== STEVENBLACK HOSTS - ads/tracking blocking ==='
            SBSource      = 'Official source: https://github.com/StevenBlack/hosts'
            SBChoose      = 'List to apply:'
            SBOpt1        = '[1] unified (ads + malware)'
            SBOpt2        = '[2] ads + malware + fakenews'
            SBOpt3        = '[3] ads + malware + fakenews + gambling + social'
            SBOpt0        = '[0] Cancel'
            SBCancelled   = 'Cancelled. Enter'
            SBNote1       = '[!] An automatic backup of your current hosts will be made'
            SBNote2       = '    in the SAME folder (hosts.atlas-pre-stevenblack.<timestamp>)'
            SBNote3       = '    so you can revert with option [R].'
            SBContinue    = 'Continue and download the list? [y/N]'
            SBBackupOK    = 'Backup ready: {0}'
            SBDownloading = 'Downloading list...'
            SBEmpty       = 'Download empty or too small.'
            SBApplied     = '[OK] StevenBlack applied. DNS cache flushed.'
            SBSuggest     = 'Hint: check connection, admin perms, or try again.'
            SBNoBackup    = 'No StevenBlack backup recorded.'
            SBBackupGone  = 'Recorded backup does not exist: {0}'
            SBWillRestore = 'Will restore: {0}'
            SBConfirm     = 'Confirm? [y/N]'
            SBRestored    = '[OK] Restored. DNS cache flushed.'
            SBPostBackup  = '(Backup of post-StevenBlack state: {0})'
            HostsDefault  = "# Copyright (c) 1993-2009 Microsoft Corp.`n#`n# This is a sample HOSTS file used by Microsoft TCP/IP for Windows.`n#`n# Localhost name resolution is handled within DNS itself.`n#`t127.0.0.1`tlocalhost`n#`t::1`tlocalhost"
            CommentTag    = 'Atlas-added'
        }
        es = @{
            WinTitle      = 'ATLAS PC SUPPORT - GESTOR HOSTS'
            Header        = 'ATLAS PC SUPPORT - GESTOR DEL ARCHIVO HOSTS'
            PathLabel     = 'Ruta:  {0}'
            AdminLabel    = 'Admin: {0}'
            AdminYes      = 'SI'
            AdminNo       = 'NO (las escrituras fallaran)'
            Options       = 'Opciones:'
            Opt1          = '[1] Ver contenido actual'
            Opt2          = '[2] Hacer backup con timestamp'
            Opt3          = '[3] Agregar entrada (IP + nombre)'
            Opt4          = '[4] Eliminar lineas que contengan un nombre'
            Opt5          = '[5] Abrir en Notepad (admin)'
            Opt6          = '[6] Restaurar default (backup automatico previo)'
            OptAdv        = '--- AVANZADO ---'
            Opt7          = '[7] Exportar hosts a Escritorio'
            Opt8          = '[8] Importar hosts desde archivo (con backup)'
            Opt9          = '[9] Aplicar StevenBlack ads/tracking (separado, con backup)'
            OptR          = '[R] Revertir StevenBlack (restaurar pre-aplicacion)'
            OptQ          = '[Q] Salir'
            SelectPrompt  = 'Seleccion'
            NotExist      = '(no existe)'
            EnterCont     = 'Enter para continuar'
            BackupCreated = 'Backup creado: {0}'
            ErrPrefix     = 'Error: {0}'
            IPLabel       = 'IP'
            NameLabel     = 'Nombre host'
            Added         = 'Agregada: {0}  {1}'
            ErrAdmin      = 'Error (necesita admin?): {0}'
            CancelEmpty   = 'Cancelado (IP o nombre vacios).'
            DelPrompt     = 'Nombre a eliminar (lineas que lo contengan)'
            Removed       = 'Eliminadas {0} linea(s) que contenian "{1}".'
            NotepadOpen   = 'Notepad abierto (en nueva ventana elevada).'
            ConfirmReset  = 'Esto SOBREESCRIBE hosts. Confirmar? [s/N]'
            Restored      = 'hosts restaurado. Backup previo en: {0}'
            ErrAdmin2     = 'Error (necesita admin): {0}'
            Exported      = 'Exportado: {0}'
            ImportPrompt  = 'Ruta completa del archivo hosts a importar (arrastra al CMD y Enter)'
            FileNotFound  = 'Archivo no encontrado.'
            ConfirmImport = 'Esto SOBREESCRIBIRA hosts actual (se hara backup). Confirmar? [s/N]'
            Imported      = 'Importado. Backup previo: {0}'
            SBHeader      = '=== STEVENBLACK HOSTS - Bloqueo ads/tracking ==='
            SBSource      = 'Fuente oficial: https://github.com/StevenBlack/hosts'
            SBChoose      = 'Lista a aplicar:'
            SBOpt1        = '[1] unified (ads + malware)'
            SBOpt2        = '[2] ads + malware + fakenews'
            SBOpt3        = '[3] ads + malware + fakenews + gambling + social'
            SBOpt0        = '[0] Cancelar'
            SBCancelled   = 'Cancelado. Enter'
            SBNote1       = '[!] Se hara backup automatico de tu hosts actual'
            SBNote2       = '    en la MISMA carpeta (hosts.atlas-pre-stevenblack.<timestamp>)'
            SBNote3       = '    para que puedas revertir con la opcion [R].'
            SBContinue    = 'Continuar y descargar la lista? [s/N]'
            SBBackupOK    = 'Backup listo: {0}'
            SBDownloading = 'Descargando lista...'
            SBEmpty       = 'Descarga vacia o demasiado pequena.'
            SBApplied     = '[OK] StevenBlack aplicado. DNS cache purgada.'
            SBSuggest     = 'Sugerencia: verifica conexion, permisos admin, o intenta de nuevo.'
            SBNoBackup    = 'No hay backup de StevenBlack registrado.'
            SBBackupGone  = 'Backup registrado no existe: {0}'
            SBWillRestore = 'Se restaurara: {0}'
            SBConfirm     = 'Confirmar? [s/N]'
            SBRestored    = '[OK] Restaurado. DNS cache purgada.'
            SBPostBackup  = '(Backup del estado con StevenBlack: {0})'
            HostsDefault  = "# Copyright (c) 1993-2009 Microsoft Corp.`n#`n# This is a sample HOSTS file used by Microsoft TCP/IP for Windows.`n#`n# Localhost name resolution is handled within DNS itself.`n#`t127.0.0.1`tlocalhost`n#`t::1`tlocalhost"
            CommentTag    = 'Atlas-added'
        }
    }
    $lang = _Atlas-DetectLang
    if (-not $T.ContainsKey($lang)) { $lang = 'en' }
    $L = $T[$lang]

    $hostsPath = Join-Path $env:SystemRoot 'System32\drivers\etc\hosts'

    try { $Host.UI.RawUI.WindowTitle = $L.WinTitle } catch {}

    $principal = [Security.Principal.WindowsPrincipal]::new([Security.Principal.WindowsIdentity]::GetCurrent())
    $isAdmin   = $principal.IsInRole([Security.Principal.WindowsBuiltInRole]::Administrator)

    do {
        Clear-Host
        Write-Host ""
        Write-Host "  =================================================" -ForegroundColor DarkGray
        Write-Host ('   ' + $L.Header) -ForegroundColor Yellow
        Write-Host "  =================================================" -ForegroundColor DarkGray
        Write-Host ('  ' + ($L.PathLabel -f $hostsPath)) -ForegroundColor Gray
        $adminText = if ($isAdmin) { $L.AdminYes } else { $L.AdminNo }
        Write-Host ('  ' + ($L.AdminLabel -f $adminText)) -ForegroundColor $(if ($isAdmin) { 'Green' } else { 'Yellow' })
        Write-Host ""
        Write-Host ('  ' + $L.Options) -ForegroundColor Cyan
        Write-Host ('    ' + $L.Opt1)
        Write-Host ('    ' + $L.Opt2)
        Write-Host ('    ' + $L.Opt3)
        Write-Host ('    ' + $L.Opt4)
        Write-Host ('    ' + $L.Opt5)
        Write-Host ('    ' + $L.Opt6)
        Write-Host ('    ' + $L.OptAdv) -ForegroundColor Cyan
        Write-Host ('    ' + $L.Opt7)
        Write-Host ('    ' + $L.Opt8)
        Write-Host ('    ' + $L.Opt9) -ForegroundColor Yellow
        Write-Host ('    ' + $L.OptR) -ForegroundColor Yellow
        Write-Host ('    ' + $L.OptQ)
        Write-Host ""
        $sel = Read-Host ('  ' + $L.SelectPrompt)

        switch ($sel) {
            '1' {
                Write-Host ""
                if (Test-Path $hostsPath) {
                    Get-Content $hostsPath | ForEach-Object { Write-Host "    $_" -ForegroundColor Gray }
                } else {
                    Write-Host ('  ' + $L.NotExist) -ForegroundColor Red
                }
                Write-Host ""
                Read-Host ('  ' + $L.EnterCont) | Out-Null
            }
            '2' {
                try {
                    $stamp  = Get-Date -Format 'yyyyMMdd-HHmmss'
                    $backup = Join-Path (Split-Path $hostsPath) "hosts.backup.$stamp"
                    Copy-Item $hostsPath $backup -Force
                    Write-Host ""
                    Write-Host ('  ' + ($L.BackupCreated -f $backup)) -ForegroundColor Green
                } catch {
                    Write-Host ('  ' + ($L.ErrPrefix -f $_.Exception.Message)) -ForegroundColor Red
                }
                Read-Host ('  ' + $L.EnterCont) | Out-Null
            }
            '3' {
                $ip   = Read-Host ('  ' + $L.IPLabel)
                $name = Read-Host ('  ' + $L.NameLabel)
                if ($ip -and $name) {
                    try {
                        $line = "{0}`t{1}`t# {2} {3}" -f $ip, $name, $L.CommentTag, (Get-Date -Format 'yyyy-MM-dd')
                        Add-Content -Path $hostsPath -Value "`r`n$line" -Encoding UTF8
                        Write-Host ('  ' + ($L.Added -f $ip, $name)) -ForegroundColor Green
                    } catch {
                        Write-Host ('  ' + ($L.ErrAdmin -f $_.Exception.Message)) -ForegroundColor Red
                    }
                } else {
                    Write-Host ('  ' + $L.CancelEmpty) -ForegroundColor Yellow
                }
                Read-Host ('  ' + $L.EnterCont) | Out-Null
            }
            '4' {
                $name = Read-Host ('  ' + $L.DelPrompt)
                if ($name) {
                    try {
                        $pattern = [regex]::Escape($name)
                        $content = Get-Content $hostsPath
                        $kept    = $content | Where-Object { $_ -notmatch $pattern }
                        $deleted = $content.Count - $kept.Count
                        Set-Content -Path $hostsPath -Value $kept -Encoding UTF8
                        Write-Host ('  ' + ($L.Removed -f $deleted, $name)) -ForegroundColor Green
                    } catch {
                        Write-Host ('  ' + ($L.ErrAdmin -f $_.Exception.Message)) -ForegroundColor Red
                    }
                }
                Read-Host ('  ' + $L.EnterCont) | Out-Null
            }
            '5' {
                try {
                    Start-Process notepad.exe -ArgumentList $hostsPath -Verb RunAs
                    Write-Host ('  ' + $L.NotepadOpen) -ForegroundColor Green
                } catch {
                    Write-Host ('  ' + ($L.ErrPrefix -f $_.Exception.Message)) -ForegroundColor Red
                }
                Read-Host ('  ' + $L.EnterCont) | Out-Null
            }
            '6' {
                $ok = Read-Host ('  ' + $L.ConfirmReset)
                if ($ok -match '^[sSyY]$') {
                    try {
                        $stamp = Get-Date -Format 'yyyyMMdd-HHmmss'
                        $before = Join-Path (Split-Path $hostsPath) "hosts.before-reset.$stamp"
                        Copy-Item $hostsPath $before -Force
                        Set-Content -Path $hostsPath -Value $L.HostsDefault -Encoding UTF8
                        Write-Host ('  ' + ($L.Restored -f $before)) -ForegroundColor Green
                    } catch {
                        Write-Host ('  ' + ($L.ErrAdmin2 -f $_.Exception.Message)) -ForegroundColor Red
                    }
                }
                Read-Host ('  ' + $L.EnterCont) | Out-Null
            }
            '7' {
                try {
                    $stamp = Get-Date -Format 'yyyyMMdd-HHmmss'
                    $out = Join-Path ([Environment]::GetFolderPath('Desktop')) "hosts.atlas.$stamp.txt"
                    Copy-Item $hostsPath $out -Force
                    Write-Host ""
                    Write-Host ('  ' + ($L.Exported -f $out)) -ForegroundColor Green
                } catch {
                    Write-Host ('  ' + ($L.ErrPrefix -f $_.Exception.Message)) -ForegroundColor Red
                }
                Read-Host ('  ' + $L.EnterCont) | Out-Null
            }
            '8' {
                $src = Read-Host ('  ' + $L.ImportPrompt)
                $src = $src.Trim('"').Trim("'")
                if (-not (Test-Path $src)) {
                    Write-Host ('  ' + $L.FileNotFound) -ForegroundColor Red
                    Read-Host ('  ' + $L.EnterCont) | Out-Null
                    continue
                }
                $ok = Read-Host ('  ' + $L.ConfirmImport)
                if ($ok -match '^[sSyY]$') {
                    try {
                        $stamp = Get-Date -Format 'yyyyMMdd-HHmmss'
                        $before = Join-Path (Split-Path $hostsPath) "hosts.before-import.$stamp"
                        Copy-Item $hostsPath $before -Force
                        Copy-Item $src $hostsPath -Force
                        Write-Host ('  ' + ($L.Imported -f $before)) -ForegroundColor Green
                    } catch {
                        Write-Host ('  ' + ($L.ErrAdmin2 -f $_.Exception.Message)) -ForegroundColor Red
                    }
                }
                Read-Host ('  ' + $L.EnterCont) | Out-Null
            }
            '9' {
                Write-Host ""
                Write-Host ('  ' + $L.SBHeader) -ForegroundColor Yellow
                Write-Host ('  ' + $L.SBSource) -ForegroundColor DarkGray
                Write-Host ""
                Write-Host ('  ' + $L.SBChoose) -ForegroundColor Cyan
                Write-Host ('    ' + $L.SBOpt1) -ForegroundColor White
                Write-Host ('    ' + $L.SBOpt2) -ForegroundColor White
                Write-Host ('    ' + $L.SBOpt3) -ForegroundColor White
                Write-Host ('    ' + $L.SBOpt0) -ForegroundColor DarkGray
                $lsel = Read-Host ('  ' + $L.SelectPrompt)
                $url = switch ($lsel) {
                    '1' { 'https://raw.githubusercontent.com/StevenBlack/hosts/master/hosts' }
                    '2' { 'https://raw.githubusercontent.com/StevenBlack/hosts/master/alternates/fakenews/hosts' }
                    '3' { 'https://raw.githubusercontent.com/StevenBlack/hosts/master/alternates/fakenews-gambling-porn-social/hosts' }
                    default { $null }
                }
                if (-not $url) {
                    Read-Host ('  ' + $L.SBCancelled) | Out-Null
                    continue
                }
                Write-Host ""
                Write-Host ('  ' + $L.SBNote1) -ForegroundColor Yellow
                Write-Host ('  ' + $L.SBNote2) -ForegroundColor Yellow
                Write-Host ('  ' + $L.SBNote3) -ForegroundColor Yellow
                Write-Host ""
                $ok = Read-Host ('  ' + $L.SBContinue)
                if ($ok -notmatch '^[sSyY]$') { Read-Host ('  ' + $L.SBCancelled) | Out-Null; continue }
                try {
                    $stamp = Get-Date -Format 'yyyyMMdd-HHmmss'
                    $before = Join-Path (Split-Path $hostsPath) "hosts.atlas-pre-stevenblack.$stamp"
                    Copy-Item $hostsPath $before -Force
                    $ptrFile = Join-Path $env:LOCALAPPDATA 'AtlasPC\hosts-last-stevenblack-backup.txt'
                    if (-not (Test-Path (Split-Path $ptrFile))) { New-Item -ItemType Directory -Path (Split-Path $ptrFile) -Force | Out-Null }
                    Set-Content -Path $ptrFile -Value $before -Encoding UTF8
                    Write-Host ('  ' + ($L.SBBackupOK -f $before)) -ForegroundColor Green
                    Write-Host ('  ' + $L.SBDownloading) -ForegroundColor Cyan
                    $tmp = Join-Path $env:TEMP "atlas-stevenblack-$stamp.txt"
                    Invoke-WebRequest -Uri $url -OutFile $tmp -UseBasicParsing -TimeoutSec 60
                    if (-not (Test-Path $tmp) -or (Get-Item $tmp).Length -lt 1000) {
                        throw $L.SBEmpty
                    }
                    $userLines = Get-Content $hostsPath
                    $marker = "# === ATLAS StevenBlack applied $stamp ==="
                    $new = @()
                    $new += $userLines
                    $new += ""
                    $new += $marker
                    $new += (Get-Content $tmp)
                    Set-Content -Path $hostsPath -Value $new -Encoding UTF8
                    Remove-Item $tmp -Force -ErrorAction SilentlyContinue
                    try { ipconfig /flushdns | Out-Null } catch {}
                    Write-Host ('  ' + $L.SBApplied) -ForegroundColor Green
                } catch {
                    Write-Host ('  ' + ($L.ErrPrefix -f $_.Exception.Message)) -ForegroundColor Red
                    Write-Host ('  ' + $L.SBSuggest) -ForegroundColor Yellow
                }
                Read-Host ('  ' + $L.EnterCont) | Out-Null
            }
            { $_ -match '^[rR]$' } {
                $ptrFile = Join-Path $env:LOCALAPPDATA 'AtlasPC\hosts-last-stevenblack-backup.txt'
                if (-not (Test-Path $ptrFile)) {
                    Write-Host ('  ' + $L.SBNoBackup) -ForegroundColor Yellow
                    Read-Host ('  ' + $L.EnterCont) | Out-Null
                    continue
                }
                $backupPath = (Get-Content $ptrFile -Raw).Trim()
                if (-not (Test-Path $backupPath)) {
                    Write-Host ('  ' + ($L.SBBackupGone -f $backupPath)) -ForegroundColor Red
                    Read-Host ('  ' + $L.EnterCont) | Out-Null
                    continue
                }
                Write-Host ""
                Write-Host ('  ' + ($L.SBWillRestore -f $backupPath)) -ForegroundColor Cyan
                $ok = Read-Host ('  ' + $L.SBConfirm)
                if ($ok -match '^[sSyY]$') {
                    try {
                        $stamp = Get-Date -Format 'yyyyMMdd-HHmmss'
                        $bumpBefore = Join-Path (Split-Path $hostsPath) "hosts.before-revert-stevenblack.$stamp"
                        Copy-Item $hostsPath $bumpBefore -Force
                        Copy-Item $backupPath $hostsPath -Force
                        try { ipconfig /flushdns | Out-Null } catch {}
                        Write-Host ('  ' + $L.SBRestored) -ForegroundColor Green
                        Write-Host ('  ' + ($L.SBPostBackup -f $bumpBefore)) -ForegroundColor DarkGray
                    } catch {
                        Write-Host ('  ' + ($L.ErrAdmin2 -f $_.Exception.Message)) -ForegroundColor Red
                    }
                }
                Read-Host ('  ' + $L.EnterCont) | Out-Null
            }
            { $_ -match '^[qQ]$' } { return }
        }
    } while ($true)
}


# ---- tools\Invoke-InstalarPaquetes.ps1 ----
# ============================================================
# Invoke-InstalarPaquetes  ->  Bulk App Installer (winget)
#
# Pilot tool for the EN/ES i18n migration ("Option A" — strings
# centralized per tool). Default language is English; Spanish
# kept as full secondary translation (read from
# %LOCALAPPDATA%\AtlasPC\config.json -> language).
#
# Atlas PC Support
# ============================================================

function Invoke-InstalarPaquetes {
    [CmdletBinding()]
    param()

    $ErrorActionPreference = 'Continue'
    $Host.UI.RawUI.WindowTitle = 'ATLAS PC SUPPORT - Bulk App Installer'
    try { $Host.UI.RawUI.WindowSize = New-Object System.Management.Automation.Host.Size(115, 44) } catch {}

    # --- Language detection (env var -> config.json -> system culture -> en) ---
    function _Atlas-DetectLang {
        if ($env:ATLAS_LANG) { return [string]$env:ATLAS_LANG }
        try {
            $cfg = Join-Path $env:LOCALAPPDATA 'AtlasPC\config.json'
            if (Test-Path -LiteralPath $cfg) {
                $obj = Get-Content -Raw -LiteralPath $cfg -Encoding UTF8 | ConvertFrom-Json
                if ($obj.language) { return [string]$obj.language }
            }
        } catch {}
        $sys = (Get-Culture).TwoLetterISOLanguageName
        if ($sys -eq 'es') { return 'es' }
        return 'en'
    }

    # --- Localized strings ---
    $T = @{
